INSERT INTO `article_comments` (`id`, `name`, `surname`, `email`, `text`, `published`, `article_id`, `deleted_reason`, `deleted_at`, `created_at`, `updated_at`) VALUES
(2, 'igor', 'fedorishchev', 'fiss04@gmail.com', 'please correct grade of Old road routes:\nI propose this:\n3.Hera : 7a. See allclimb\n5. Argo. 6b\n6. Hera . 6a. 6. is much easier than 5.\nyou can check it in AllClimb app, it reflects difficulties more correctly.\nBut as 3. Hera listed as 5c is absolute joke, its 7a/7a+', 1, 13, NULL, NULL, '2023-12-09 23:19:42', '2023-12-09 23:19:42'),
(4, 'climbing', 'ge', 'info@climbing.ge', 'Routes are graded by climbing.ge athletes. This is the official guidebook of Georgian routes. Of course the routes may change but the routes grads will be changed when our athletes climb and evaluate it.\n\nWe should also mention that we do not use uncertain and unofficial apps for our routes grading!', 1, 13, NULL, NULL, '2024-02-22 01:14:51', '2024-02-22 01:14:51'),
(5, 'niloufar', 'banitalebi', 'ndehkordi@newvision.ge', 'I am looking for a climbing group to start from scratch', NULL, 34, NULL, NULL, NULL, NULL),
(6, 'SOPIO', 'TCHELIDZE', 'sofachelidze@gmail.com', '❤️❤️❤️', 1, 97, NULL, NULL, NULL, '2025-08-02 16:23:17'),
(7, 'Rob', 'Van de Loo', 'vandeloo.rob@gmail.com', 'Hi! Me and my friend are planning to visit Georgia this june and were thinking of climbing Tetnuldi. Can you give us more info on the trip and the price? Kind Regards, Rob', NULL, 63, NULL, NULL, NULL, NULL);
