INSERT INTO `general_infos` (`id`, `title`, `text_ka`, `text_us`, `created_at`, `updated_at`) VALUES
(1, 'Bolting info', '<h2><strong><ins>გთხოვთ გაითვალისწინოთ</ins></strong></h2>\n\n<h2><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong></h2>\n\n<p>რეგიონში მარშრუტების დამატება (დაბოლტვა, დაშლამბურება) ადგილობრივი მცოცავების გარეშე სასტიკად აკრძლულია. გთხოვთ დაუკავშირდეთ მარშრუტების ორგანიზატორებს და გააცოთ თქვენი გეგმები, წინააღმდეგ შემთხვევაში თქვენი მარშრუტები დემონტაჟს დაექვემდებარება!</p>\n\n<p>თქვენ შეგიძლიათ დაგვეხმაროთ რეგიონის განვითარებაში, <a href=\"https://You can help us develop the region by visiting the page to learn more.\">ეწვიეთ გვერდს მეტი ინფორმაციის გასაგებათ</a>.</p>\n\n<p><strong>აგრეთვე აკრძალულია Drytooling-ის ცოცვაც!</strong></p>\n\n<p><strong>გამოიყენეთ ჩაფხუტი თქვენი უსაფრთხოებისათვის !</strong></p>', '<h2><ins><strong>Please note</strong></ins></h2>\n\n<h2><strong>Area is not free for bolting !!!</strong></h2>\n\n<p>Please note that the area is not open for bolting without permission. If you plan to come for bolting in Georgia, kindly inform the local community about your plans. Any route that does not adhere to our standards will be removed.</p>\n\n<p>You can help us develop the region, <a href=\"https://climbing.ge/special_article/suport_outdoor_climbing_routes_bolting_in_georgia\">visiting the page to learn more</a>.</p>\n\n<p><strong>Dry tolling is not allowed&nbsp; in climbing area!</strong></p>\n\n<p><strong>Camping under climbing lines is strictly prohibited for safety reasons!</strong></p>\n\n<p><strong>Remember to always wear a helmet for your own safety!</strong></p>', '2023-01-24 12:09:45', '2024-07-03 10:10:28'),
(2, 'Contact info', '<hr />\n<p><strong>გუგა</strong></p>\n\n<p><em>Mail</em>: gugadabrunda@gmail.com</p>\n\n<p><em>Tel</em>: (+995) 557 300 700</p>\n\n<hr />\n<p><strong>თემო</strong></p>\n\n<p><em>Mail</em>: samsonadze.temo9@gmail.com&nbsp;</p>\n\n<p><em>Tel</em><strong>:</strong>&nbsp;(+995) 598 45 70 48</p>\n\n<hr />\n<p><a href=\"https://shop.climbing.ge/tours\" target=\"_blank\">გვაქვს გიდის სერვისი, ტურების მენეჯმენტი, აღჭურვილობის ქირაობა და მანქანის მომსახურება. ჩვენს გიდებს აქვთ საქართველოს სამთო გიდების ასოციაციის სერთიფიკატები (GMGA) და მრავალწლიანი გამოცდილება. გაეცანით ჩვენი ტურის კატალოგი.</a></p>\n\n<p><a href=\"https://shop.climbing.ge/service/rent_climbing_gear\" target=\"_blank\">ასევე შესაძლებელია აღჭურვილობის ქირაობა. ეწვიეთ გვერდს მეტი ინფორმაციის მისაღებად.</a></p>', '<hr />\n<p><strong>Guga</strong></p>\n\n<p><em>Mail</em>:<a href=\"mailto:gugadabrunda@gmail.com?subject=Message%20From%20Climbing.ge\"> gugadabrunda@gmail.com</a></p>\n\n<p><em>Tel</em>: <a href=\"tel:(+995) 557 300 700\">(+995) 557 300 700</a></p>\n\n<hr />\n<p><strong>Temo</strong></p>\n\n<p><em>Mail</em>: <a href=\"mailto:samsonadze.temo9@gmail.com ?subject=Message%20From%20Climbing.ge\">samsonadze.temo9@gmail.com&nbsp;</a></p>\n\n<p><em>Tel</em><strong>:</strong>&nbsp;<a href=\"tel:(+995) 598 45 70 48\">(+995) 598 45 70 48</a></p>\n\n<hr />\n<p><a href=\"https://shop.climbing.ge/tours\" target=\"_blank\"><em>We have guide service, tour management, climbing gear rental and car service Our guides have Georgian mountain&nbsp;guide&nbsp;association&nbsp;certificates (GMGA) and years of experience. </em>Check out our tour catalog.</a></p>\n\n<p><a href=\"https://shop.climbing.ge/service/rent_climbing_gear\" target=\"_blank\">Also you can rent climbing gear. Check price list.</a></p>', '2023-01-24 12:10:25', '2024-12-19 19:54:59'),
(3, 'Climbing federatione contacts', '<p>საქართველოს მეკლდეურობის ეროვნული ფედერაციის <strong><a href=\"http://geoclimbing.ge/?fbclid=IwAR1AjhfxZb0rvvsvG9Afa8XPP-QaiCeQbjuStkb7PZgSfujLjkAaptLbmr8\">ოფიციალური ვებგვერდი</a></strong></p>\n\n<p>საქართველოს მეკლდეურობის ეროვნული ფედერაციის <strong>ელექტრონული ფოსტა -&nbsp;info@geoclimbing.ge</strong></p>\n\n<p>საქართველოს მეკლდეურობის ეროვნული ფედერაციის <a href=\"https://www.facebook.com/gcnf.georgianclimbing\"><strong>ფეისბუქ გვერდი</strong></a></p>\n\n<p>საქართველოს მეკლდეურობის ეროვნული ფედერაციის <strong>ვიცეპრეზიდენტი ლაზარე კომახიძე - 598 212310</strong></p>', '<p><a href=\"http://geoclimbing.ge/?fbclid=IwAR1AjhfxZb0rvvsvG9Afa8XPP-QaiCeQbjuStkb7PZgSfujLjkAaptLbmr8\"><strong>The official website</strong></a> of the Georgian Climbing National Federation</p>\n\n<p>Email of the Georgian Climbing National Federation- <strong>info@geoclimbing.ge</strong></p>\n\n<p><a href=\"https://www.facebook.com/gcnf.georgianclimbing\"><strong>Facebook page</strong></a> of the Georgian Climbing National Federation</p>\n\n<p>Vice-President of the Georgian Climbing National Federation,&nbsp;<strong>Lazare Komakhidze&nbsp;- 598 212310</strong></p>', '2023-04-15 10:41:17', '2023-05-27 00:52:54'),
(4, 'Chaukhi standard gear list', '<p>მარშრუტზე დაგჭირდებათ:</p>\n\n<ol>\n	<li>თოკი 50მ</li>\n	<li>ზაკლადკები 4-5ც საშუალო ზომები</li>\n	<li>ფრენდები 3-4ც საშუალო ზომები</li>\n	<li>ექსპრესი 4-5ც</li>\n	<li>კარაბინი 3-4ც და თვითდაცვა</li>\n	<li>დაცვის-დასაშვები სისტემა</li>\n	<li>დაცვის ქამარი და ჩაფხუტი</li>\n	<li>წრიაპი წერაყინი (დამოკიდებულია თოვლის სიმრავლეზე კულუარში)</li>\n</ol>\n\n<p>ზამთრის პერიოდში დამატებით დაგჭირდებათ&nbsp;</p>\n\n<ol>\n	<li>თოვლის ფეხსაცმელი (სნეგასტუპები)</li>\n	<li>ყინულის ბური 2-3ც</li>\n</ol>', '<p>On the route you will need:</p>\n\n<ol>\n	<li>Rope 50 m</li>\n	<li>Stopers&nbsp;4-5&nbsp;(medium size)</li>\n	<li>Cams&nbsp;3-4 (medium-sized)</li>\n	<li>&nbsp;Quickdraw&nbsp;4-5</li>\n	<li>3-4s carbine and self-defense</li>\n	<li>Belay device</li>\n	<li>Harness and helmet</li>\n	<li>Crampons and iceax (depending on the amount of snow on the couloir)</li>\n</ol>\n\n<p>In winter, you will need additional equipment</p>\n\n<ol>\n	<li>Snowsues</li>\n	<li>Ice screws 2-3</li>\n</ol>', '2023-04-24 23:29:12', '2024-05-05 23:29:13'),
(5, 'Bolting info for dry tooling sector', '<h2><strong><ins>გთხოვთ გაითვალისწინოთ</ins></strong></h2>\n\n<h3><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong></h3>\n\n<p>რეგიონში მარშრუტების დამატება (დაბოლტვა, დაშლამბურება) ადგილობრივი მცოცავების გარეშე სასტიკად აკრძლულია. გთხოვთ დაუკავშირდეთ მარშრუტების ორგანიზატორებს და გააცოთ თქვენი გეგმები, წინააღმდეგ შემთხვევაში თქვენი მარშრუტები დემონტაჟს დაექვემდებარება!</p>\n\n<p>თქვენ შეგიძლიათ დაგვეხმაროთ რეგიონის განვითარებაში, <a href=\"https://climbing.ge/special_article/suport_outdoor_climbing_routes_bolting_in_georgia\">ეწვიეთ გვერდს მეტი ინფორმაციის გასაგებათ</a>.</p>\n\n<p><strong>უსაფრთხოების მიზნით კატეგორიულად აკრძალულია საცოცი მარშრუტების ქვეშ დაბანაკება!!!</strong></p>\n\n<p><strong>გთხოვთ გამოიყენოთ მხოლოდ ის მშრალი დრაითულინგისთვის, რომლებიც მითითებულია !!!</strong></p>\n\n<p><strong>გამოიყენეთ ჩაფხუტი თქვენი უსაფრთხოებისათვის !!!</strong></p>', '<h2><ins><strong>Please note</strong></ins></h2>\n\n<h2><strong>Area is not free for bolting !!!</strong></h2>\n\n<p>Please note that the area is not open for bolting without permission. If you plan to come for bolting in Georgia, kindly inform the local community about your plans. Any route that does not adhere to our standards will be removed.</p>\n\n<p>You can help us develop the region, <a href=\"https://climbing.ge/special_article/suport_outdoor_climbing_routes_bolting_in_georgia\">visiting the page to learn more</a>.</p>\n\n<p><strong>please use only those drytooling routes that are indicated!!!</strong></p>\n\n<p><strong>Camping under climbing lines is strictly prohibited for safety reasons!!!</strong></p>\n\n<p><strong>Remember to always wear a helmet for your own safety!!!</strong></p>', '2023-11-02 02:11:16', '2024-07-03 10:11:31'),
(6, 'Ushba Gear List (Rock)', '<p>/</p>', '<p>.</p>', '2024-12-19 19:55:44', '2024-12-19 19:55:44'),
(7, 'Ushba Gear List (Ice)', '<p>.</p>', '<p>.</p>', '2024-12-19 19:56:03', '2024-12-19 19:56:03'),
(8, 'Snow Mountain Route Gear List (easy)', '<p>ზაფხულის პირობებში, სტანდარტული მყინვარული აღჭურვილობა საკმარისია ასასვლელად.</p>\n\n<ol>\n	<li>დაცვის წამარი</li>\n	<li>ჩაფხუტი</li>\n	<li>წერაყინი</li>\n	<li>წრიაპი</li>\n	<li>თოკი (40-50 მ) (3 კაცზე მეტის ერთ თოკში ჩაბმა რეკომენდირებული არ არის)</li>\n	<li>ყინულის ბური (2-3 ც)</li>\n	<li>კარაბინი (3-4 ც)</li>\n	<li>ნაპრალიდან ამოყვანის სამაშველო კომპლექტი</li>\n	<li>თბილი და ქარისგან დამცავი ტანსაცმელი აუცილებელია</li>\n</ol>\n\n<p><strong>თბილი და ქარსაწინააღმდეგო ტანსაცმელი აუცილებელია</strong></p>', '<p>Under usual summer conditions, the standard glacier gear is enough to handle the climb.</p>\n\n<ol>\n	<li>Safety harness</li>\n	<li>Helmet</li>\n	<li>Ice axe</li>\n	<li>Crampons</li>\n	<li>Rope (40-50 M) (it is not recommended to tie more than 3 people to one rope)</li>\n	<li>Ice scrows (2-3 Pic)</li>\n	<li>Carabiners (3-4 Pic)</li>\n	<li>Crevice rescue kit</li>\n</ol>\n\n<p><strong>A warm and windproof clothes is a must</strong></p>', '2024-12-19 19:56:26', '2025-01-23 01:46:53'),
(9, 'Ice Climbing Mount Route (Hard)', '<ol>\n	<li>წრიაპი + სამთო ბათინკი</li>\n	<li>ყინულის ინსტრუმნტი (საცოცი წერაყინები)</li>\n	<li>თოკი 2ც 50-60მ. (Double rope)</li>\n	<li>ყინულის ბურეი 10-12ც</li>\n	<li>ექსპრესები 8-10ც</li>\n	<li>ჩაფხუტი</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა + 5-6&nbsp;კარაბინი</li>\n	<li>2-3 ბალდა</li>\n	<li>პირადი თვითდაცვა</li>\n</ol>', '<ol>\n	<li>Crampons + Mountaineering boots</li>\n	<li>Ice tools&nbsp;</li>\n	<li>Rope 2 pcs 50-60 m. (Double rope)</li>\n	<li>Ice Scrows 10-12 pcs</li>\n	<li>Expresses 8-10 pcs</li>\n	<li>Helmet</li>\n	<li>Protective belt</li>\n	<li>Hurnes + 5-6&nbsp;carabiners</li>\n	<li>2-3 dinema sling</li>\n	<li>Personal direct sling</li>\n</ol>', '2024-12-19 21:27:46', '2024-12-23 00:25:08'),
(10, 'Ice Climbing Gear', '<p><strong>სტანდარტული აღჭურვილობა</strong></p>\n\n<ol>\n	<li>ჩაფხუტი&nbsp;</li>\n	<li>დაცვის ქამარი</li>\n	<li>დასაზღვევი მოყყობილობა</li>\n	<li>სამთო ბათინკი</li>\n	<li>წრიაპი</li>\n	<li>თოკი (2ც 50მ)</li>\n	<li>ყინულის ინსტრუმენტი (2ც)</li>\n	<li>კარაბინი 3-4ც</li>\n	<li>თბილი ტანსაცმელი (წყალგაუმტარი ქურთუკი, ხელთათმანები, თბილი შარვალი, თბილი ზედა, ქუდი.)</li>\n	<li>დიდი თოვლისას სასურველია თოვლის ფეხსაცმლის (სნეგასტუპების) გამოყენება</li>\n</ol>\n\n<p><strong>ქვედა დაცვით საცოცად</strong></p>\n\n<ol>\n	<li>ყინულის ბურები (10-12ც)</li>\n	<li>ექსპრესევი (10-12ც)</li>\n</ol>', '<p><strong>Standard Equipment</strong></p>\n\n<ol>\n	<li>Helmet</li>\n	<li>Harness</li>\n	<li>Belay device</li>\n	<li>Mountaineering boots</li>\n	<li>Crampons</li>\n	<li>Rope (2 pcs, 50m)</li>\n	<li>Ice tools (2 pcs)</li>\n	<li>Carabiners (3-4 pcs)</li>\n	<li>Warm clothing (waterproof jacket, gloves, warm pants, warm top, hat)</li>\n	<li>In heavy snow, it is recommended to use snow boots (snegastup)</li>\n</ol>\n\n<p><strong>For Lead Climbing</strong></p>\n\n<ol>\n	<li>Ice screws (10-12 pcs)</li>\n	<li>Quickdraws (10-12 pcs)</li>\n</ol>', '2025-01-21 00:34:39', '2025-01-21 00:34:39'),
(12, 'Contact info (Temo)', '<p>.</p>', '<p>.</p>', '2026-03-29 23:28:07', '2026-03-29 23:28:07');
