INSERT INTO `locale_articles` (`id`, `locale`, `title`, `short_description`, `text`, `route`, `how_get`, `best_time`, `what_need`, `info`, `price_text`, `address`, `created_at`, `updated_at`) VALUES
(1, 'ka', 'ცოცვა სვერში (ჭიათურა)', '<p>სვერის საცოცი რეგიონი მდებარეობს დასავლეთ საქართველოში,&nbsp;იმერეთში.</p>\n', '<p>სვერი საცოცი რეგიონი&nbsp;შედარებით ახალია მაგრამ მიუხედავად ამისა აქ საკმაოდ ბევრი სპორტული მარშრუტია. მარშრუტების კეთება დაიწყო 2018 წელს. რეგიონი პერსპეკტიულია როგორც საცოცი სექტორების ათვისებისთვის ასევე სხვა სპორტული აქტიობებებისთვის. რეგიონში თქვენ შეგიძლიათ დაკავდეთ არამხოლოდ ცოცვით არამედ ბევრი სხვა აქტიობით</p>\n\n<p><strong>სხვა აქტიობები</strong></p>\n\n<p>სვერშო არის რამდენიმე ძველი ციხესიმაგრე, მონასტერი და მრავალი ლამაზი.&nbsp;ასევე მიმდებარე ტერიტორიაზე არის რამდენიმე ტბა და ჩანჩქერი სადაც შესაძლებელია ნავით გასეირნება და&nbsp;ბანაობა ზაფხულის ცხელ დღეებში.</p>\n\n<p>&nbsp;</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=zeExJv0-4Cs\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/4gAulQS\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n', '<p>საცოცი სეკტორებთან მისასვლელი გზა საკმაოდ მარტივი მისაგნებია.</p>\n\n<p>მარშრუტების უმეტესობა 10-25 მეტრია, სირთულე&nbsp;5A- დან 7C- მდე.</p>\n', '<p>სოფელი სვერი მდებარეობს&nbsp;ქალაქ ჭიათურასთან თბილისიდან 170 კმ-ში.</p>\n\n<p><br />\nსვერამდე მისვლა შეგიძლიათ მიკროავტობუსით&nbsp;თბილისიდან, დიდუბის სადგურიდან, ქალაქ ჭიათურაში. ჭიათურიდან შეგიძლიათ მიკროავტობუსით ან ტაქსით გაემართოთ სოფელ სვერში, რომელიც 11 კმ-თია დაშორებული. სოფელ სვერის ავტობუსის გაჩერებიდან დაახლოებით 400 მეტრია გასავლელი საცოც სექტორამდე.<br />\nტერიტორია არ არის მარკირებული ბოლომდე, მაგრამ არის რამდენიმე მიმართიულების მიმცემი ნიშანი სოფლის დასაწყისში შეგხვდებათ რეგიონის ნიშანი მიმართულებით და&nbsp;სოფლის ბოლოს არის ნიშანი &quot;Climbing Zone&quot; და იქიდან დაახლოებით 50 მეტრია კლდეებამდე.</p>\n\n<p>თუ თქვენ გამოიყენებთ პირად ავტომობილს რეკომენდირებულია იყოლიოთ 4X4ზე მანქანა. წინააღმდეგ შემთხვევაში სოფლის შიგნიტ გადაადგილება შეიძლება გაგიჭირდეთ.</p>\n\n<p>დარჩენა რეკომენდირებულია სექტორების ძირში მდებარე კემპინგში &quot;<a href=\"https://www.campingeorgia.ge/camp/\">Sveri adventure camp</a>&quot;. კემპინგი სექტორებისკენ მიმავალ გზაზა მდებარეოდს და მისი მოძებნა არ გაგიჭირდებათ. აქ თქვენ დაგხვდებათ მოწყობილი საკარვე ადგილი და რამდენიმე კოტეჯი. აგრეთვე შხაპი, სამზარეულო და სველი წერტილები.</p>\n\n<p><br />\nსაკვები და მარაგი</p>\n\n<p>სურსათის შეძენას გირჩევთ&nbsp;ქალაქ ჭიათურაში. აქ არის ადგილობრივი აგრარული&nbsp;ბაზარი, მრავალფეროვანი მაღაზიები და უამრავი საცხობი, რომლებიც გთავაზობთ ყოველდღიურად გამომცხვარ ახალ პურს, ხაჭაპურს და ლობიანს.<br />\nსამწუხაროდ, სვერში საკვები პროდუქტების ბაზარი აღარ არის, ასე რომ თქვენ უნდა თან წაიყვანეთ მთელი თქვენი მარაგი.წყლის აღება შეგიძლიაღ სოფლის წყაროებზე.წყაროები სუფთაა და სასმელად გამოსადექი.</p>\n', '<p>ზამთრის გარდა, სვერში ცოცვა იდეალურია გაზაფხულიდან შემოდგომამდე.</p>\n\n<p>კლდეებიის დიდი ნაწილი ჩრდილოეთისკენ არის მიმართული, რაც იმას ნიშნავს რომ დღის უმეტესი ნაწილი ისინი ჩრდილშია (1-2 საათის შემდეგ) და ზაპხულის დღეებში აქ ცოცვა ძალიან კომპორტულია. წელიწადის ცივ დროს აქ საცოცვა საკმაოდ არაკომფორტულია ამინდის გამო და ჩვენ გირჩევთ ეწვიოთ <a href=\"http://climbing.ge/outdoor/Climbing_In_Chiatura\">ჭიათურის</a> და <a href=\"http://climbing.ge/outdoor/Climbing_In_Katskhi_%28Chiatura%29\">კაცხის</a> საცოც სექტორებს.</p>\n', '<ol>\n	<li>12 ექსპრესი</li>\n	<li>50m თოკი</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხოტი</li>\n	<li>საცოცი ფეხსაცმელი (სკალნები) და მაგნეზიის ტომარა</li>\n</ol>\n', '', NULL, NULL, '2021-03-02 11:04:04', '2023-11-20 02:27:20'),
(6, 'ka', 'ცოცვა კაცხში (ჭიათურა)', '<p>კაცხი ერთ-ერთი ყველაზე საუკეთესო ადგილია საცოცად საქართველოში. კლდის ხარისხი შესანიშნავია ცოცვის&nbsp;სხვადასხვა ტიპისთვის.</p>\n', '<p>კაცხი ერთ-ერთი ყველაზე პოპულარული ადგილია საცოცად საქართველოში.&nbsp;კლდის ხარისხი შესანიშნავია ცოცვის სხვადასხვა ტიპისთვის. აქ გვაქვს ბევრი სხვადასხვა ტიპის რელიეფი, როგორც უარყოფითი მარშრუტები ასევე სწორუ ფილები, რაც მეტ საშვალებას აძლებს სპორცმენს მაქსიმალურად განვითარდეს.</p>\n', '<p>მარშრუტები კლასიფიცირებულია ფრანგულ სისტემით.&nbsp;5a&nbsp;&ndash; დან 8b&nbsp;&ndash; მდე.</p>\n\n<p><strong>გამოიყენეთ ჩაფხუტი თქვენი უსაფრთხოებისათვის !</strong></p>\n\n<p><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong><br />\nიმ შემთხვევაში, თუ აპირებთ მარშრუტების გაკეთებას ამ რეგიონში, გთხოვთ, აცნობოთ ადგილობრივ მეკლდეურებს თქვენი გეგმების შესახებ, წინააღმდებ შემთხვევაში თქვენი მაშრუტები შესაძლებელია დემონტაჟს დაექვემდებაროს.</p>\n\n<p><strong>აგრეთვე აკრძალულია Drytooling-ის ცოცვაც!</strong></p>\n', '<p>კაცხი მდებარეობს დედაქალაქ თბილისიდან დაახლოებით 180 კმ-ში. მანქანით დაგჭირდებათ დაახლოებით 2 - 2.5 საათი. სასურველია მაღალი გამავლობის 4X4 მანქანით გადადგილება.&nbsp;</p>\n\n<p>ქუთაისის აეროპორტიდან 1 საათი.</p>\n\n<p>სამოქალაქო ტრანსპორტით თქვენ დაგჭირდებათ ცასვლა ქალაქ ჭიათურაში. სამარშრუტო ტაქსები ახორციაელებენ მარშრუტზე მოძრაობას დილის 9დან საღამოს 5ამდე. ჭიათურიდან თქვენ მოგიწევთ ჭიათურა-კაცხი მარშრუტკახე გადაჯდომა და ის ჩამოგიყვანთ სოფელ&nbsp;კაცხის მთავარ მოედანზე.&nbsp;</p>\n\n<p>დასარჩენად საუკეთესო ადგილია &quot;კაცხის სახლი&quot; (იხილეთ რუკა). აქ შესაძლებელია გაჩერება როგორც სახლში ისევე კარავში.</p>\n', '<p>,სკაცხი მდებარეობს ზღვის დონიდან 700 მ. ცოცვისთვის&nbsp;საუკეთესო პერიოდია ზამთარი, გაზაპხული&nbsp;და შემოდგომა. ზამთარში და ადრე გზაფხულზე ხშირია წვიმა მაგრამ კარ გამინდში თქვენ შეძლებთ ცოცვას გრილ და სასიმოვნო ამინდში. ზაფხოლში უმეტესად ცხელი ამინდებია საცოცად და ცოცვას მოახერხებთ ადრე დილას ან მხოლოდ ინ სეკტორებში რომლების ჩრდილშია.</p>\n', '<ol>\n	<li>12 ექსპრესი</li>\n	<li>60m თოკი</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხოტი</li>\n	<li>საცოცი ფეხსაცმელი (სკალნები) და მაგნეზიის ტომარა</li>\n</ol>\n', '<p>მოგვწერეთ შეტყობინება და ჩვენ მალე გიპასუხებთ.</p>\n\n<p><strong>Guga</strong> - <em>Mail</em>: gugadabrunda@gmail.com &nbsp; &nbsp;<em>Tel</em>: (+995) 557 300 700</p>\n\n<p><strong>Temo</strong> - <em>Mail</em>: samsonadze.temo9@gmail.com&nbsp; &nbsp; <em>Tel</em>; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 17:31:38', '2023-06-29 21:34:55'),
(7, 'ka', 'ცოცვა ლოტკინის მონუმენტზე', '<p>კეთილი იყოს თქვენი მობრძანება ლოტკინის მონუმენტზე. ეს არის 40 მეტრიანი ბეტონის კონსტრუქცია. რომელზეც შესაძლებელია ცოცვა.</p>\n', '<p>კეთილი იყოს თქვენი მობრძანება ლოტკინის მონუმენტზე.</p>\n\n<p>ეს არის 40 მეტრიანი ბეტონის კონსტრუქცია. მონუმენტი მდებარეობს ქალაქის გარეუბანში და მაგრამ მასთან მისვლა არანაირ სირთულეს არ წარმოადგენს. მონუმენტი არის კარგი ადგილი საცოცად თბილისში. აქ გვაქვს 7 მარშრუტი 5B-7B. (იხილეთ მარშრუტების არჭერა)</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=TTX8b63u4_k\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/C3fjJHW\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n', '<p>დღეისათვის არსებობს 7&nbsp;სპორტული მარშრუტი. 1&nbsp;მაღშრუტი&nbsp;ყველაზე მაღალია 40 მ, 1 მარშრუტი 30 მ და 4&nbsp;მარშრუტი 20 მ.</p>\n\n<p><strong>გაითვალისინეთ რომ ზოგი საჭიდი შესაძლოა ტრიალებდეს!!! სურვილის შემთხვევაში შეგიძლიათ დაუჭიროთ საჭიდებს ეხვსკუთხა ქანჩით (შესტიგრანკით).</strong></p>\n\n<p><a href=\"https://climbing.ge/ice/dry_tooling_on_lotkin_monument\">დრაითულინგის მარშრუტების სანახავად ეწვიეთ გვერდს</a></p>\n', '<p>მონუმენტი მდებარეობს ქალაქის გარეუბანში და მაგრამ მასთან მისვლა არანაირ სირთულეს არ წარმოადგენს. მეტრო <a href=\"https://goo.gl/maps/Rjou6mefmr52\">&#39;სადგურის მოედნიდან</a>&#39; ზედა გასასვლელიდან მიდიან es110, №111, №48 (<a href=\"http://goo.gl/maps/EG9Emms68YN5yGvC7\">გაჩერება 1</a>) და №36 (<a href=\"https://goo.gl/maps/2XZPEGVgAEP7QezZ8\">გაჩერება 2</a>) ავტობუსებით (<a href=\"https://www.google.com/maps/d/u/0/viewer?mid=1Nzu-J7c65ivpXrma5iAdWye1a7nhYslt&amp;ll=41.72681806910237%2C44.81414870000003&amp;z=15\">იხილეთ რუკა</a>). თუ თქვენ პირადი მანქანით მიდიხართ მოგიწავთ მანქანის გაჩერება ქალაქის პარკინგზე. მონუმენტთან მისასვლე გზა გადაკეტილია!</p>\n', '<p>აქ მთელი წლის განმავლობაში შეგიძლიათ ცოცვა&nbsp;ამინდის მიხედვით. მონუენტი მდებარეობს ქარიან ადგილას ამიტომაც ხშირია ძლიერი ქარი. ზაფხოლში მეტად სასიამოვნოა ცოცვა საღამოს საათებში როცა მზე ჩასვლას იწყებს. ზამთარში ხშირია ცივი ქარი ამიტომაც აუცილებელოია ამინდის შერჩევა, მაგრამ კარგ ამინდში ზამთარშიც კი აქ ცოცვა ძალიან სასიამოვნოა.</p>\n', '<p>&nbsp;</p>\n\n<ol>\n	<li>20 ექსპრესი</li>\n	<li>(Min) 40m - (Max) 80m თოკი</li>\n	<li>დეაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხუტი</li>\n	<li>საცოცი ფეხსაცმელი(სკალნები) &amp; მაგნეზიის ტომარა</li>\n</ol>\n', '', NULL, NULL, '2021-03-02 17:36:24', '2023-11-18 00:52:35'),
(8, 'ka', 'ცოცვა ჭიათურაში', '<p>ჭიათურა ერთ-ერთი ყველაზე პერსპექტიული საცოცი რეგიონია საქართველოში.</p>\n', '<p>ჭიათურა ერთ-ერთი ყველაზე პერსპექტიული საცოცი რეგიონია საქართველოში. აქ გვაქვს მაღალი კედლები 50-150მ რომელიც ჯერჯერობით უმეტესად არაა ათვისებული, მაგრამ გვაქვს 2 რეგიონი 30 მარშრუტით სადაც შეგიძლიათ სასიამოვნოდ ცოცვა.</p>\n', '<p>ამ რეგიონში მუდმივად ვამატებთ ახალ მარშრუტებს. მარშრუტები 5A- დან 8A- მდეა. აგრეთვე გვაქვს 3, 2 თოკიანი მარშრუტი (მულტიპიჩი).</p>\n\n<p><strong>უსაფრთხოების მიზნით, გამოიყენეთ ჩაფხეტი!</strong></p>\n\n<p><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong><br />\nიმ შემთხვევაში, თუ თქვენ აპირებთ მატშტუტების გაკეთებას ჭიათურაში აუცილებლად შეატყობინეთ ადგილობრივ მეკლდეურებს. წინააღმდეგ შემთხვევაში თქვენი მარშრუტი შესაძლებელია დემონტაჟს დაექვემდებაროს.</p>\n\n<p><strong>&quot;Drytooling&quot;-ის ცოცვა რეგიონში სასტიკად აკრძალულია!</strong></p>\n\n<p>&nbsp;</p>\n', '<p>ჭიათურა მდებარეობს დედაქალაქ თბილისიდან 180 კმ-ში. მანქანით დაგჭირდებათ დაახლოებით 2.0-2.5 საათი. საქალაქთაშიორისო ტრანსპორთით დაგჭირდებათ თბილისი-ჭიათურა სამარშრუტო ტაქსით ჩახვიდეთ ჭიათურაში, აქედან ფეხით ან ტაქსით შეძლებთ ახვიდეთ საცოც სეკტორამდე. (იხილეთ რუკა)</p>\n\n<p>თქვენ შეგიძლიათ დარჩენა ქალაქში ჰოსტელში ან კაცხის სახლში. კაცხის სახელი&nbsp;მდებარეობს ქალაქიდან 9 კილომეტრში, სოფელ კაცხში. (იხილეთ მეტი)</p>\n', '<p>ჭიათურაში ცოცვისთვის საუკეთესო სეზონია ზამთარი, გაზაფხული და შემოდგომა. ზაპხულში ამ რეგიონში საცოცად ძალიან ცხელა. ცოცვა შესაძლებელია დარე დილას, 10.00-11.00 საათამდე. წლის სხვა პერიოდში სასურველია ამინდის შემოწმება რათა წვიმამ არ შეგიშალოთ ცოცვაში ხელი</p>\n', '<ol>\n	<li>20 ექსპრესი</li>\n	<li>თოკი 60მ</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხუტი</li>\n	<li>საცოცი ფეხსაცმელი (სკალნი) &amp; მაგნეზიის ტომატა</li>\n</ol>\n', '<p>მოგვწერეთ შეტყობინენა და ჩვენ სულ მალე გიპასუხებთ.</p>\n\n<p><strong>Guga</strong> - <em>Mail</em>: gugadabrunda@gmail.com &nbsp; &nbsp;<em>Tel</em>: (+995) 557 300 700</p>\n\n<p><strong>Temo</strong> - <em>Mail</em>: samsonadze.temo9@gmail.com&nbsp; &nbsp; <em>Tel</em>; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 17:38:50', '2023-06-29 21:31:56'),
(9, 'ka', 'ცოცვა მესტიაში (ჭალაადი)', '<p>.</p>\n', '<p>სვანეთი ერთ-ერთი ულამაზესი ადგილია საქართველოში.</p>\n\n<p>შეიძლება იყოს აქტიური სპორტული და ისტორიული და სასიამოვნო ადგილები.</p>\n\n<p>მესტია არის სვანეთის ცენტრი, რომელიც მდებარეობს ზღვის დონიდან 1500 მეტრში და თბილისიდან 460 კმ 8 საათის სავალზე.</p>\n', '<h2><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong></h2>\n\n<p><br />\nიმ შემთხვევაში, თუ აპირებთ მარშრუტების გაკეთებას ამ რეგიონში, გთხოვთ, აცნობოთ ადგილობრივ მეკლდეურებს თქვენი გეგმების შესახებ, წინააღმდებ შემთხვევაში თქვენი მაშრუტები შესაძლებელია დემონტაჟს დაექვემდებაროს.</p>\n\n<p><strong>აგრეთვე აკრძალულია Drytooling-ის ცოცვაც!</strong></p>\n\n<p><strong>გამოიყენეთ ჩაფხუტი თქვენი უსაფრთხოებისათვის !</strong></p>\n', '', '<p>ასვლისთვის საუკეთესო დროა ზაფხულის ბოლოს, შემოდგომის დასაწყისი. სალაშქრო ადგილი მარტივია ავტოსტოპით, ის მდებარეობს ქალაქის ცენტრიდან 10 კმ-ის დაშორებით.</p>\n', '<ol>\n	<li>14 ექსპრესი</li>\n	<li>თოკი 70მ</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხუტი</li>\n	<li>საცოცი ფეხსაცმელი (სკალნი) &amp; მაგნეზიის ტომატა</li>\n</ol>\n', '<p>Guga - <strong>Mail</strong>: gugadabrunda@gmail.com &nbsp; &nbsp;<strong>Tel</strong>: (+995) 557 300 700</p>\n\n<p>Temo - <strong>Mail</strong>: samsonadze.temo9@gmail.com&nbsp;</p>\n', NULL, NULL, '2021-03-02 17:41:37', '2023-06-29 21:31:00'),
(10, 'ka', 'ცოცვა ძევრში', '<p>.</p>\n', '<p>საფეხმავლო ხაზები მართლაც ახლოს არის გზასთან და მათ უმეტესობას აქვს კომფორტული სასტარტო პლატფორმა.</p>\n\n<p>შესაძლებელია ცოცვის ზონაში დაბანაკება.</p>\n\n<p>კლდეებთან ახლოს არის რესტორანი და ბაზარი.</p>\n\n<p>ადგილობრივი მოსახლეობა ნამდვილად მეგობრულია მთამსვლელთა საზოგადოების მიმართ.</p>\n\n<p>კლდის სახეს განსხვავებული ექსპოზიცია აქვს და მაშინაც კი, როცა მზეზე ცხელა, შეგიძლიათ იპოვოთ დაჩრდილული ადგილი ასასვლელად.</p>\n', '<h2><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong></h2>\n\n<p><br />\nიმ შემთხვევაში, თუ აპირებთ მარშრუტების გაკეთებას ამ რეგიონში, გთხოვთ, აცნობოთ ადგილობრივ მეკლდეურებს თქვენი გეგმების შესახებ, წინააღმდებ შემთხვევაში თქვენი მაშრუტები შესაძლებელია დემონტაჟს დაექვემდებაროს.</p>\n\n<p><strong>აგრეთვე აკრძალულია Drytooling-ის ცოცვაც!</strong></p>\n\n<p><strong>გამოიყენეთ ჩაფხუტი თქვენი უსაფრთხოებისათვის !</strong></p>\n', '<p>მანძილი თბილისიდან 200 კმ 3 საათი მანქანით.</p>\n\n<p>მანძილი ქუთაისის კოპიტნარის აეროპორტიდან 60 კმ 1 საათი მანქანით. (რუკის ჩვენება)</p>\n', '<p>ასვლისთვის საუკეთესო სეზონია ზაფხულის დასაწყისი და შემოდგომა, მაგრამ კარგი ამინდის შემთხვევაში ასვლა შესაძლებელია მთელი წლის განმავლობაში.</p>\n', '<ol>\n	<li>14 ექსპრესი</li>\n	<li>თოკი 60მ</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხუტი</li>\n	<li>საცოცი ფეხსაცმელი (სკალნი) &amp; მაგნეზიის ტომატა</li>\n</ol>\n', '<p>Guga - <strong>Mail</strong>: gugadabrunda@gmail.com &nbsp; &nbsp;<strong>Tel</strong>: (+995) 557 300 700</p>\n\n<p>Temo - <strong>Mail</strong>: samsonadze.temo9@gmail.com&nbsp;</p>\n', NULL, NULL, '2021-03-02 17:44:09', '2023-06-29 21:29:17'),
(11, 'ka', 'ცოცვა ქუთაისში(ჭომა)', '<p>ქალაქში არ არის ბევრი საცოცი მარშრუტი, მაგრამ დღის სასიამოვნოდ გასატარებლად, ეს სავსებით საკმარისია.</p>\n', '<p>ქუთაისი საქართველოში სისდიდით მეორე ქალაქია. მოსახლეობა 147&nbsp;635 ადამიანი. იგი 235 კმ - ითაა დაშრებული თბილისიდან. ზ.დ. 125-300მ. ქალაქში არ არის ბევრი საცოცი მარშრუტი, მაგრამ დღის სასიამოვნოდ გასატარებლად, ეს სავსებით საკმარისია. მარშრუტების სირთულე 5A დან 7A- მდე მერყეობს, ამიტომ აქ ცოცვა დამწყებ მეკლდეურთათვის იდეალურია.</p>\n', '', '<p>ქუთაისში ცასვლა საქარტელოს ნებისმიერი ქალაქიდან ძალიან მარტივია. მუნიციპალური ტრანსპორტი აქ ყველა ქალაქიდან მოზრაობს. საკუთარი მანქანით მგზავრობის შემთხვევაში გამოიყენეთ GPS ნავიგატორი. ასევე ქალაქიდან 5 კმ - ში არის აეროპორტი. ფერენები როგორც თბილისიდან, ასევე მსოფლიოს ბევრი სხვა ქვეყნიდანაა.</p>\n\n<p>საცოცო სექტორებთან მისასვლელად იხილეთ რუკა.</p>\n\n<p>ღამის გასათენებლად შეგიძლიათ დარჩეთ ქუთაისში მდებარე ერთ - ერთ სასტუმროშ, ან კარვით დარჩეთ კლდეების მიმდებარე ტერიტორიაზე.</p>\n', '<p>საუკეთესო დრო აქ საცოცად გაზაფხული და შემოდგომაა. ზაფხულის პერიოდში აქ ზალიან ცხელა. ზამტარში საკმაოდ ცივა, მაგრამ თბილ დღეებში შესაძლებელია კომფორტულად ცოცვა.</p>\n', '<p>12 ექსპრესი<br />\n60m თოკი<br />\nდაცვის ქამარი<br />\nდაცვის სისტემა<br />\nჩაფხოტი<br />\nსაცოცი ფეხსაცმელი (სკალნები) და მაგნეზიის ტომარა</p>\n', '<p>Guga - <strong>Mail</strong>: gugadabrunda@gmail.com &nbsp; &nbsp;<strong>Tel</strong>: (+995) 557 300 700</p>\n\n<p>Temo - <strong>Mail</strong>: samsonadze.temo9@gmail.com&nbsp;</p>\n', NULL, NULL, '2021-03-02 17:46:18', '2023-05-24 07:42:59'),
(12, 'ka', 'ცოცვა არშაში', '<p>ყაზბიგი (სტეპანციმინდა) ზდ 1750მ, ერთერთი ყველაზე პოპულარულია ადგილია საქართველოში. ყოველწლიურად მას უამრავი აქტიური დასვენების მოყვარული სტუმრობს.</p>\n\n<p>&nbsp;</p>\n', '<p>არშა მდებარეობს ჩრდილოეთ საქართველოში, დაბა სტეფანწმინდიდან 5კმ - ში,&nbsp; ზ.დ. 1500მ. მოსახლეობა 700 ადამიანი. სტეფანწმინდის რეგიონი ძალიან პოპულარულია სათავგადასავლო ტურიზმის მოყვარულთა შორის. აქ შეგიძლია დაკავდეთ, როგორც კლდეზე ცოცვით, ასევე სხვადასხვა აქტივობებით: ტრეკინგი, ველო ტური, ჯომარდობა, ალპინიზმი, პარაპლანი და უამრავი სხვა. ალპინიზმის მოყვარულებს ვურჩევთ წაუხის და მყინვარწვერის მასივებს. აგრეთვე 6 კმ - ში არის სხვა საცოცი რეგიონი ცდო, რომელსაც აგრეთვე შეგიძლიათ ეწვიოთ.</p>\n\n<p>მარშრუტების სირთულე 5A-დან 7A-მდე მერყეობს. აგრეთვე შეგიძლიათ მულტიპიჩის ცოცვაც. არის ბევრი კარგი ნაპრალი სადაც შეიძლება Tred climbing-ის ცოცვა.</p>\n\n<p>&nbsp;</p>\n', '<h2><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong></h2>\n\n<p><br />\nიმ შემთხვევაში, თუ აპირებთ მარშრუტების გაკეთებას ამ რეგიონში, გთხოვთ, აცნობოთ ადგილობრივ მეკლდეურებს თქვენი გეგმების შესახებ, წინააღმდებ შემთხვევაში თქვენი მაშრუტები შესაძლებელია დემონტაჟს დაექვემდებაროს.</p>\n\n<p><strong>აგრეთვე აკრძალულია Drytooling-ის ცოცვაც!</strong></p>\n\n<p><strong>გამოიყენეთ ჩაფხუტი თქვენი უსაფრთხოებისათვის !</strong></p>\n', '<p>არშაში მოსახვედრათ დაგჭირდებათ ყაზბეგისკენ მომავალი მუნიციპალური ტრანსპორტი და ჩამოხვიდეთ სტეფანწმინდამდე 5 კმ - ში. აქედან ფეხით მოგიწევთ 1,5 კმ - ის გავლა. შესაძლებელია ყაზბეგში ტაქსის ქირაობაც.</p>\n\n<p>საკუტარი მანქანით მგზავრობის შემთხვევაში, მანქანა სასურველია იყოს 4X4 -ზე ( იხილეთ რუკა).</p>\n\n<p>არსასი და სტეფანწმინდაში უამრავი სასტუმროა, რომელშიც თქვენ შეგიძლიათ გაჩერდეთ ( ფასები 30 ლარიდან). აგრეთვე შეგიძლიათ გაჩერდეთ არსას კლდეებთან არსებულ საკემპინგე ადგილას, კლდეებიდან 10 &ndash; 15 წუთის სავალზე.</p>\n', '<p>იმის გამო რომ საცოცი სექტორი მაღალმთიან რეგიონში მდებარეოს, აქ ცოცვა გვიან გაზაფხულზე , ზაფხულში და ადრე შემოდგომაზეა შესაძლებელი. ზამთარში აქ ცოცვა დაბალი ტემპერატურისა და უხვი ნალექის გამო შეუძლებელია. ზამტარში გირჩევთ გველეთის გაყინულ ჩანცქერზე ცოცვას.</p>\n', '<p>თქვენ გჭირდებათ</p>\n\n<ol>\n	<li>\n	<p>20 ექსპრესი</p>\n	</li>\n	<li>\n	<p>თოკი 60მ</p>\n	</li>\n	<li>\n	<p>დაცვის ქამარი</p>\n	</li>\n	<li>\n	<p>დაცვის სისტემა</p>\n	</li>\n	<li>\n	<p>ჩაფხუტი</p>\n	</li>\n	<li>\n	<p>საცოცი ფეხსაცმელი (სკალნი) &amp; მაგნეზიის ტომატა</p>\n	</li>\n</ol>\n', '<p>გუგა - Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p>თემო - Mail: samsonadze.temo9@gmail.com</p>\n', NULL, NULL, '2021-03-02 17:51:02', '2023-06-29 21:26:09'),
(13, 'ka', 'ცოცვა შავი ზღვის სანაპიროზე', '<p>შავი ზღვის სანაპირო გთავაზობთ რამდენიმე სეკტორს ცოცვისთვის.</p>\n', '<p>თუ გსურთ შავი ზღვის სანაპიროზე კლდეზე ცოცვა, შავი ზღვის სანაპირო გთავაზობთ რამდენიმე შესაძლებლობას.</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=5nnz6wFzn4s\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/DHzVnUA\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n', '<p>მარშრუტების უმრავლესობა დაშლამბურებულია საკმაოდ დიდი ხნის წინ, მაგრამ არის მარშრუტები რომლებიც გაკეთებულია დიდი ხნის წინ. მარშრუტების სირთულე მერყეობს&nbsp;&nbsp;5A-დან 7A-მდე.</p>\n', '<p>მანძილი დედაქალაქ თბილისიდან ბათუმამდე არის 380 კმ.&nbsp;თქვენ შეგიძლიათ ფრენა ბათუმის აეროპორტში. საცოცი სექტორიები მდებარეობს&nbsp;10 კმ-ში ბათუმიდან. აგრეთვე მიკროავტობუსით მისვლა მარტივად შეგიძლიათ.</p>\n\n<p><strong>Დასარჩენი ადგილი</strong><br />\nშეგიძლიათ დარჩეთ კერძო სახლებში ან სასტუმროებში ბათუმში, სარფში, გონიოში ან კვარიათში. ფასები იწყება 25-30 ლარიდან (დაახლოებით 10-15 ევრო) და იზრდება, სეზონის მიხედვით.</p>\n', '<p>თქვენ გაქვთ შესაძლებლობა ასვლა როგორც მზეზე, ისე ჩრდილში, თუმცა სიცხე ზაფხულის სეზონზე უნდა გაითვალისწინოთ. Საუკეთესო დრო<br />\nასვლა მაისი, ივნისი, სექტემბერი და ოქტომბერი.</p>\n', '<ol>\n	<li>10 ექსპრესი</li>\n	<li>თოკი 40მ</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხუტი</li>\n	<li>საცოცი ფეხსაცმელი (სკალნი) &amp; მაგნეზიის ტომატა</li>\n</ol>\n', '<p><strong>გუგა&nbsp;</strong>- Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p><strong>თემო&nbsp;</strong>- Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 17:53:23', '2023-10-01 00:35:30'),
(14, 'ka', 'ცოცვა ბირთვისის კანიონში', '<p>ბირთვისის კანიონი მდებარეობს 40 კმ - ში თბილისიდან.&nbsp;საცოცო რეგიონში მარშრუტების უმეტესი ნაწილი ბოლდერინგია, მაგრამ არის სპორტული მარშრუტებიც.</p>\n', '<p>ბირთვისის კანიონი მდებარეობს 40 კმ - ში თბილისიდან. ზ.დ 1077 მ. აქ თქვენ შეძლებთ ცოცვით, კანიონინგით და ტრეკინგით დაკავებას. საცოცო რეგიონში მარშრუტების უმეტესი ნაწილი ბოლდერინგია, მაგრამ არის სპორტული მარშრუტებიც.</p>\n\n<p>საფეხმავლო გზა&nbsp;სოფელი ტბისი-დან, საიდანაც უნდა აუყვე&nbsp;ბილიკს. როცა დაინახავ ნიშნულას წარწერით&nbsp;&bdquo;ბირთვისის ბუნებრივი ძეგლი&ldquo;&nbsp;&ndash; ეს ნიშნავს რომ სწორ გზაზე დგახარ. სამწუხაროდ, ბილიკი არ არის მონიშნული და სჯობს&nbsp;Wikiloc-დან ჩამოტვირთო ტრეკი ან&nbsp;დაიხმარო &ndash; Maps.me.</p>\n', '<p>სპორტული მარშრუტების სირთულე 5A - დან 7C - მდე მერყეობს.&nbsp;ბოლდერინგიდ სირთულე V1-დან V7-მდე მერყეობს. არის პროეკტებიც. ამიტომაც აქ ცოცვა დამწყები და მოყვარული მცოცავებისთვის იდეალურია.</p>\n\n<h2><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong></h2>\n\n<p><br />\nიმ შემთხვევაში, თუ აპირებთ მარშრუტების გაკეთებას ამ რეგიონში, გთხოვთ, აცნობოთ ადგილობრივ მეკლდეურებს თქვენი გეგმების შესახებ, წინააღმდებ შემთხვევაში თქვენი მაშრუტები შესაძლებელია დემონტაჟს დაექვემდებაროს.</p>\n\n<p><strong>აგრეთვე აკრძალულია Drytooling-ის ცოცვაც!</strong></p>\n\n<p><strong>გამოიყენეთ ჩაფხუტი თქვენი უსაფრთხოებისათვის !</strong></p>\n', '<p>გზა საცოცი სექტორებისა და კანიონისკენ იწყება სოფელ ტბისიდან, სადაც თქვენ მოგიწევთ მანქანის დატოვება და 45 &ndash; 60 წთ. ფეხით სიარული ტყის ზონაში ( იხილეთ რუკა). მანქანა სასურველია 4X4 - ზე.</p>\n\n<p>რეგიონში გაჩერება მხოლოდ კარვითაა შესაძლებელი. საკარვე ადგილი საცოცი რეგიონების შუაში მდებარეობს და მარშრუტებამდე მისასვლელად მაქსიმუმ 5წთ - ია საჭირო. წყლის ავსება კემპინგიდან ზევით მიმავალ გზასთან არსებულ მდინარეზეა შესაძლებელი.</p>\n', '<p>საუკეთსეო დრო ბირთვისში საცოცად: გაზაფხული და შემოდგომაა. ზაფხულის პერიოდში კანიონში ძალიან ცხელა. ზამთრის პერიოდში უმეტესად საკმაოდ ცივა, მაგრამ ხშირია თბილი ამინდი, როდესაც შესაძლებელია ცოცვა. ბირთვისის კანიონში ცოცვა&nbsp;წლის ნებისმიერ დროს არის შესაძლებელი. თუმცა, ზაფხულში აქ საკმაოდ ცხელა და მიმდებარედ სასმელი წყალიც შრება. ძლიერი წვიმების შემდეგ სჯობს არ ეწვიო ამ ადგილს, რადგან ზოგიერთ ადგილას ძალიან ტალახიანია და წყლის დონეც მაღლა იწევს.</p>\n', '<p>სპორტული ცოცვისთვის დაგჭირდებათ:&nbsp;</p>\n\n<ol>\n	<li>50მ თოკი</li>\n	<li>10 ექსპრესი</li>\n	<li>დაცვის სისტემა და დაცვის ქამარი</li>\n	<li>ჩაფხუტი</li>\n</ol>\n\n<p>ბოლდერინგის საცოცად დაგჭირდებათ &#39;ქრეშპადები&#39; (<a href=\"https://images.app.goo.gl/X598rhKxzugftkZA8\">crash bad</a>)</p>\n', '<p>გუგა: <strong>Tel</strong>. (+995)&nbsp;557 300 700 <strong>Mail</strong>.&nbsp;gugadabrunda@gmail.com</p>\n\n<p>თემო: <strong>Mail</strong>. samsonadze.temo9@gmail.com</p>\n', NULL, NULL, '2021-03-02 17:55:39', '2023-06-29 21:24:04'),
(15, 'ka', 'ცოცვა \"თბილისის ბოტანიკურ ბაღში\"', '<p>თბილისის ბოტანიკური ბაღი მშვენიერი ადგილია დასვენებისთვის და დროის სასიამოვნოდ გასატარებლად. ასევე აქ შეგიძლიათ ცოცვითაც დაკავება</p>\n', '<p>თბილისის ბოტანიკური ბაღი მშვენიერი ადგილია დასვენებისთვის და დროის სასიამოვნოდ გასატარებლად. ასევე აქ შეგიძლიათ ცოცვითაც დაკავება. ამ საცოცო რეგიონს საკმაოდ დიდი ისტორია აქვს. ქართველი სპორცმენები აქ , წინა საუკუნის 70 - იანი წლებიდან დღემდე ვარჯიშობენ. ეს ადგილი მშვენიერია იმ ადამიანებისთვისაც, ვისაც არასდროს უცოცია ბუნებრივ კლდეზე.</p>\n', '<p>საბაგირო ზედა მარშრუტების გარდა, მარშრუტი No. 9, 10, 13, 14, 15 და 22 არის bolted. No1 და 2 პროექტებია, რომლებიც ჯერ კიდევ არ არის გასწორებული. ლოდის მარშრუტები არ არის მონიშნული კლდეებზე, მაგრამ ისინი ადვილად ამოიცნობენ და შეგიძლიათ იხილოთ აქ განთავსებულ ფოტოებზე.</p>\n\n<p>თქვენ ასევე გაქვთ შესაძლებლობა, რომ ასვლა 80 მ-ზე გაიაროთ ბოტანიკური ბაღის მთის კლდის მთის გავლით.</p>\n', '<p>აქ მოსახვედრად არსებობს ორი გზა.</p>\n\n<p>პირველი: ბოტანიკური ბაღის მთავარი შესასვლელიდან შემოსვლა შეუძლია ნებისმიერ მსურველს. გაითვალისწინეთ, რომ ცენყტრალური შემოსასვლელიდან შესვლა ფასიანია.</p>\n\n<p>მეორე: ნარიყალას ციხის მხრიდან არსებული შესასვლელიდან. ეს შესასვლელი გამოიყენება მხოლოდ ბაღის ადმინისტრაციისთვის და ქართველი სპორცმენებისთვის, ან მათთვის, ვინც მუდმივად ცოცავს ბოტანიკური ბაღში და ამ ადამიანზე ბაღის დაცვა ფლობს იმფორმაციას.</p>\n', '<p>ბოტანიკურ ბაღში ცოცვა წლის ნებისმერ დროსაა შესაძლებელი.ზაფხულის პერიოდში ცოცვა ყველაზე სასიამოვნოა საღამოს, როდესაც მზე აღარ ადგას კლდეებს ( 17:00 საათის შემდეგ).</p>\n\n<p>ზამთრის პერიოდში კი პირიქით, დილის საათებშ, 15:00 საატამდე, როდესაც მზე კლდეებს ათბობს და მასზე ცოცვა თბილი და სასიამოვნოა.</p>\n', '<p>საცოცად დაგჭირდებათ</p>\n\n<ol>\n	<li>60მ თოკი&nbsp;</li>\n	<li>8 ექსპრესი</li>\n	<li>ჩაფხუტი</li>\n	<li>დაცვის სისტემა და დაცვის ქამარი</li>\n</ol>\n', '<p>Guga - Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p>Temo - Mail: samsonadze.temo9@gmail.com</p>\n', NULL, NULL, '2021-03-02 18:29:06', '2023-06-29 21:22:40'),
(16, 'ka', 'ცოცვა ნავარძეთში (ჭიათურა)', '<p>პატარა სოფელი &quot;ნავარძეთი&quot; მდებარეობს ჭიათურიდან 4,5 კმ-ში დაშორებით დიდი საფეხმავლო რეგიონის &quot;კაჩის&quot; მიმართულებით.</p>\n', '<p>პატარა სოფელი &rdquo;ნავარძეთი&rdquo; მდებარეობს ჭიათურიდან 4,5 კმ-ში დაშორებით დიდი საფეხმავლო რეგიონის &rdquo;კაჩის&rdquo; მიმართულებით.</p>\n\n<p>საფეხმავლო ხაზები ახალია და რეგიონი მიმდინარეობს, ამიტომ დღეისათვის მხოლოდ 7 ხაზი გვაქვს, მაგრამ მალე ჩვენი კლუბი &rdquo;ქართველი ალპინისტების კლუბი&rdquo; აპირებს ყველა შესაძლო ხაზის გადაკეტვას ამ რეგიონში.</p>\n\n<p>კლდის მაღალი 30/40 მ, მაგრამ ხაზების მაქსიმალური სიმაღლე 30 მ.</p>\n\n<p>შეაფასეთ მთავარი გზიდან დაახლოებით 200 მ.</p>\n\n<p>ასვლასთან ახლოს მდებარე მთავარ გზაზე შეგიძლიათ მიიღოთ წყაროს წყალი.</p>\n\n<p>მოგზაურობის დროს დარჩენისთვის შეგიძლიათ გამოიყენოთ ალპინისტები, რომლებიც ბანაკობენ კაჩში</p>\n', '<p>ამ რეგიონში მუდმივად ვამატებთ ახალ მარშრუტებს. მარშრუტები 5A- დან 8A- მდეა. აგრეთვე გვაქვს 3, 2 თოკიანი მარშრუტი (მულტიპიჩი).</p>\n\n<p><strong>უსაფრთხოების მიზნით, გამოიყენეთ ჩაფხეტი!</strong></p>\n\n<p><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong><br />\nიმ შემთხვევაში, თუ თქვენ აპირებთ მატშტუტების გაკეთებას ჭიათურაში აუცილებლად შეატყობინეთ ადგილობრივ მეკლდეურებს. წინააღმდეგ შემთხვევაში თქვენი მარშრუტი შესაძლებელია დემონტაჟს დაექვემდებაროს.</p>\n\n<p><strong>&quot;Drytooling&quot;-ის ცოცვა რეგიონში სასტიკად აკრძალულია!</strong></p>\n', '<p>ჭიათურიდან სამარშრუტო ტაქსია ნავარძეთში. ასევე შეგიძლიათ გამოიყენოთ სამარშრუტო ტაქსი კაცხამდე და გადმოხვიდეთ სოფელ ნავარძეთის მახლობლად</p>\n', '<p>ფართობის დიდი პლუსია ის, რომ კლდე ჩრდილშია 15:00 საათის შემდეგ, ასე რომ ზაფხულში შეგიძლიათ ჩრდილში ასვლა.</p>\n', '<ol>\n	<li>20 ექსპრესი</li>\n	<li>თოკი 60მ</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხუტი</li>\n	<li>საცოცი ფეხსაცმელი (სკალნი) &amp; მაგნეზიის ტომატა</li>\n</ol>\n', '<p>Guga - Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p>Temo - Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 18:31:44', '2023-06-29 21:20:22'),
(17, 'ka', 'ცოცვა ცდოში', '<p>ცდო - პატარა სოფელია ყაზბეგთან&nbsp;ეს არის ულამაზესი ადგილი. მშვენიერი ადგილია სპორტული და მრავალსაფეხურიანი ასვლისთვის.</p>\n', '<p>ყაზბეგში მთავარი ყურადღება მთის ტურიზმს წარმოადგენს (მწვერვალი 5047 მ), თუმცა ასვლაში შესაბამისი ინფრასტრუქტურის შექმნა მიმდინარეობს. სოფელი ცდო კაზბეკიდან 7 კმ-ზე მდებარეობს.</p>\n', '<p>ამ რეგიონში მუდმივად ვამატებთ ახალ მარშრუტებს. მარშრუტები 5A- დან 8A- მდეა. აგრეთვე გვაქვს 3, 2 თოკიანი მარშრუტი (მულტიპიჩი).</p>\n\n<p><strong>უსაფრთხოების მიზნით, გამოიყენეთ ჩაფხეტი!</strong></p>\n\n<p><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong><br />\nიმ შემთხვევაში, თუ თქვენ აპირებთ მატშტუტების გაკეთებას ჭიათურაში აუცილებლად შეატყობინეთ ადგილობრივ მეკლდეურებს. წინააღმდეგ შემთხვევაში თქვენი მარშრუტი შესაძლებელია დემონტაჟს დაექვემდებაროს.</p>\n\n<p><strong>&quot;Drytooling&quot;-ის ცოცვა რეგიონში სასტიკად აკრძალულია!</strong></p>\n', '', '<p>ივნისი-ოქტომბერი, მაგრამ თუ კარგი ამინდია შესაძლებელია ზამთარშიც ასვლა.</p>\n', '<ol>\n	<li>20 ექსპრესი</li>\n	<li>თოკი 60მ</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხუტი</li>\n	<li>საცოცი ფეხსაცმელი (სკალნი) &amp; მაგნეზიის ტომატა</li>\n</ol>\n', '<p>Guga - Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p>Temo - Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 18:36:35', '2023-06-29 20:22:28'),
(18, 'ka', 'ცოცვა ჭაუხის ბანაკში', '<p>ალპინისტური მარშრუტების გარდა თქვენ შეგიძლიათ იცოცოთ სპორტული მარშრუტები ჭაუხის ბანაკში</p>\n', '<p>ჭაუხის მთები - ხევსურეთის ერთერთი მთის მასივია. უახლოესი სოფელი ჯუთაა. კლდოვანი მთები აგებულია მწვანე ალპური ბორცვებისგან. საბაზო ბანაკიდან ალპინისტური მარშრუტების ძირამდე&nbsp;1-2.5 საათში ადიხართ. აქვთ ყველანაირი მარშრუტი, რომელიც საინტერესოა როგორც დამწყებთათვის, ასევე პროფესიონალებისთვის. (ალპინიზმის შესახებ ინფორმაციისთვის <a href=\"http://climbing.ge/mountaineering\">იხილეთ აქ</a>).</p>\n\n<p>ალპური მარშრუტების გარდა, საბაზო ბანაკში&nbsp;შეგიძლიათ იცოცოთ სპორტული მარშრუტებიც.</p>\n', '<p>აქ არის მოკლე მარშრუტი (მაქსიმუმ 15 მ), არის რამდენიმე მარშრუტი ქვედა დაცვით და რამდენიმე ზედა დაცვითაც. ეს მარშრუტი ძირითადად დამწყებ ალპინისტებისთვისაა განკუთვნილი რათა მათ ისწავლონ ცოცვის&nbsp;ტექნიკური საფუძვლები, მაგრამ ასვლა კარგია 3-4 საათიანი სარელაქსაციო&nbsp;ცოცვისთვის.&nbsp;</p>\n', '<p>საპეხმავლო ბილიკი, რომელიც მიემართება ჭაუხის მწვერვალის მასივში,&nbsp;იწყება სოფელ ჯჟუტაში (2100 მ). სოფლის გავლის შემდეგ და მოხვდით ზეტას საბანაკეზე. (ბანაკში შეგიძლიათ მიიღოთ შხაპი, იკვებოთ და ღამე გაატაროთ, მაგრამ ალპინისტური ასცლისთვის საჭიროა უფრო მაღლა ასვლა) ბანაკის შემდენ კვლავ მივუყვებით ბილიკს გზად რამდენჯერმე გვიწევს ბილიკის გადაკვეთა.&nbsp;საპეხმავლო ბილიკი&nbsp;კარგად არის მონიშნული. ბალახოვანი პლატოებისა და ფერდობების გავლის შემდეგ თქვენ მოხვდებით მაღალ პლატოზე (cemp-1 2250 მ), მორენას ძირში აქ არის ჭაუხის მთავარი საბანაკე</p>\n', '<p>საუკეთესო პერიობი აქ საცოცად ხაპხულია. მაგრამ შესაძლებელია ცოცვა გაზაფხულის ბოლოს და შემოდგომის დასაწყისში.</p>\n', '<p>საცოცად დადჭირდებათ:</p>\n\n<ol>\n	<li>6 ექსპრესი</li>\n	<li>40m თოკი</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაოფხუტი&nbsp;(გირჩევთ ჩაფხუტის გამოყენებას თქვენივე უსაფრთხოებისთვის)</li>\n	<li>საცოცი ფეხსაცმელი (სკალნები) &amp; მაგნეზიის ტომარა</li>\n</ol>\n', '<p>მეტუ ინფპრმაციისთვის დაგვოკავშირდით.</p>\n\n<p>თემო - Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 18:39:31', '2023-06-29 20:21:05'),
(19, 'ka', 'Bouldering Club Tbilisi', '<p>ალპინიზმის ფედერაციის დაქვემდებარებაში არსებული ვერის, ბოლდერინგის დარბაზი.</p>\n', '<p>ვერის საცოცი დარბაზი, არის ალპინიზმის ფედერაციის დაქვემდებარებში არსებული &nbsp;ბოლდერინგის დარბაზი. სიმაღლე 4,5მ. სხვადასხვა სირთულის მარშრუტებით, როგორც დამწყებთათვის, ასევე პროფესიონალი მცოცავებისთვის.</p>\n\n<p>ერთ თვიანი აბონიმენტის ღირებულება - 60 ლარი</p>\n\n<p>ერთჯერადი შემოსვლა - 10 ლარი.</p>\n\n<p>შესაძლებელია ერთჯერადად (1,5 საათი - 20 ლარი), ასევე ინდივიდუალური ვარჯიშებისთვის მწვრთნელის აყვანა.</p>\n\n<p>ასევე არის&nbsp;მწვრთნელი, რომელიც ამეცადინებს&nbsp;შეზღუდული შესაძლებლობის მქონე ბავშვებს და მოზარდებს ცოცვასა და იოგაში</p>\n\n<p>დარბაზი მუაშაობს 11:00 - 23:00 საათამდე, ყოველ დღე.</p>\n\n<p>ქირავდება:&nbsp;<br />\nსაცოცი კეტები -5 ლ<br />\nმაგნეზია - 5 ლ<br />\nტომარა - 5 ლ</p>\n\n<p>გაყიდვაშია:<br />\nმაგნეზია 100გრ &nbsp;- 20 ₾<br />\nმაგნეზია 200გრ - 37 ₾<br />\nმაგნეზიის ტომარა - 40 ₾</p>\n', NULL, '<p>დარბაზი მდებარეობს ჭადრაკის სასახლის შენობაში, პირველ სართულზე. შესასვლელი უკანა ( პარკინგის) მხრიდან.</p>\n\n<p>მისამართი:&nbsp;თბილისი, მერაბ კოსტავას 37ა.</p>\n\n<p>&nbsp;</p>\n', NULL, '', '<p>ოთო -&nbsp;(+995)&nbsp;514 51 11 77</p>\n\n<p>თემო - (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 18:49:57', '2023-06-29 20:08:51'),
(20, 'ka', 'S.K.Lucky', '<p>საცოცი დარბაზი s.k.lucky საქართველოში ერთ - ერთი საუკეთესო დარბაზია. აქ თქვენ შეგიძლიათ, როგორც ბოლდერინგის, ასევე სპორტული მარშრუტების ცოცვა</p>\n', '<p>საცოცი დარბაზი s.k.lucky საქართველოში ერთ - ერთი საუკეთესო დარბაზია. აქ თქვენ შეგიძლიათ, როგორც ბოლდერინგის, ასევე სპორტული მარშრუტების ცოცვა. სპორტული ცოცვის კედლის სიმაღლე 12მ არის, ბოლდერინგის კედლის - 4მ.</p>\n\n<p>აქ თქვენ დაგხვდებიან ინსტრუქტორები, რომლებიც დაგეხმარებიან აგირჩიონ გამოცდილებიდან გამომდინარე სხვადასხვა სირთულის მარშრუტები და დაგაზღვევენ, თუ თქვენ საცოცად მარტო ხართ მისული და მეწყვილე არ გყავთ.</p>\n', NULL, '<p>დარბაზი მდებარეობს უნივერსიტეტის ქ. N 6, სპორტკომპლექტ არენა ორის მე -2 - რე სართულზე.</p>\n\n<p>დარბაზში მისვლა შესაძლებელია, როგორც საქალაქო ტრანსპორტით, ასევე ტაქსით და ტქვენი საკუთარი მანქანით ( იხილეთ რუკა).</p>\n', NULL, '<p>სპორტული დარბაზი აღჭურვილია ყველა საჭირო ინვენტარითა და აღჭურვილობით, რათა უზრუნველყოს თქვენი კომფორტი და სიამოვნება ვარჯიშის დროს. გთხოვთ გაითვალისწინოთ, რომ აღჭურვილობის ქირაობა ფასიანია.</p>\n', '<p>Tel: (+995) 574 80 95 02</p>\n', NULL, NULL, '2021-03-02 18:52:39', '2023-11-20 01:38:14'),
(21, 'ka', 'ვაკის საცოცი დარბაზი', '<p>სპორტული და სწრაფი ცოცვის დარბაზი თბილისში</p>\n', '<p>&quot;ვაკის საცოცი დარბაზი&quot; თბილისში მდებარე &quot;საქაღტველოს მეკლდეურობის ეროვნული ფედერაციის&quot; დაქვებდებარებაში არსებული ერთადერთი დარბაზია. დარბაზში შეძლებa როგორც სწრაფი ცოცვა ასევე რტული და ბოლდერინგის ცოცვაც. დარბაზში მუდამ დაგხვდებათ ინსტრუქტორი რომელიც ყოველთვის შეძლებს დახმარებას.</p>\n\n<p>&nbsp;</p>\n\n<p>სამუშაო საათები</p>\n\n<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:100%\">\n	<tbody>\n		<tr>\n			<td>Manday</td>\n			<td>13.00 - 22.00</td>\n		</tr>\n		<tr>\n			<td>Tuesday&nbsp;</td>\n			<td>13.00 - 22.00</td>\n		</tr>\n		<tr>\n			<td>Wednesday&nbsp;</td>\n			<td>13.00 - 22.00</td>\n		</tr>\n		<tr>\n			<td>Thursday&nbsp;</td>\n			<td>13.00 - 22.00</td>\n		</tr>\n		<tr>\n			<td>Friday&nbsp;</td>\n			<td>13.00 - 22.00</td>\n		</tr>\n		<tr>\n			<td>Saturday&nbsp;</td>\n			<td>13.00 - 22.00</td>\n		</tr>\n		<tr>\n			<td>Sunday&nbsp;</td>\n			<td>13.00 - 22.00&nbsp;</td>\n		</tr>\n	</tbody>\n</table>\n', NULL, '<p>ჭავჭავაძის გამზ. 49. ადვილად მისადგომი ავტობუსით. (ვაკის საცურაო აუზის წინ)</p>\n', NULL, '<p>სპორტული დარბაზი აღჭურვილია ყველა საჭირო ინვენტარითა და აღჭურვილობით, რათა უზრუნველყოს თქვენი კომფორტი და სიამოვნება ვარჯიშის დროს. გთხოვთ გაითვალისწინოთ, რომ აღჭურვილობის ქირაობა ფასიანია.</p>\n', '', NULL, NULL, '2021-03-02 18:54:34', '2025-05-19 23:09:34'),
(22, 'ka', 'ყინულზე ცოცვა გველეთში', '<p>გველეთში ყინულზე ცოცვა ერთ-ერთი საუკეთესო ადგილია ამ საქმიანობისთვის.</p>\n', '<p>გველეთში ჩანჩქერი ერთერთი საუკეთესო ადგილია ყინულზე საცოცად საქართველოში</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=_wUtCO6z1Xo\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/V9XYJze\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n', '', '<p>გველსთში მოსახვედრად სტეფანწმინდიდან უნდა იმოძრაოთ დარიალის ხეობიაში რუZეთის საზღვრის მიმართულებით. 12კილომეტრში შეგხვდებათ სოფლის სანიშნე და მარცხენამხარეს სოფლის გადასახვევი.</p>\n', '<p>ასვლისთვის საუკეთესო დროა იანვარი, თებერვალი და მარტის დასაწყისი. სასურველია ნახოთ ამინდის პროგნოზი სექტორში ჩასვლამდე.</p>\n', '<ol>\n	<li>თოკი 60 м (2 ც) ან&nbsp;120 м (1 ც)</li>\n	<li>წერაყინი (ყინულის ინსტრუმენტი)</li>\n	<li>წრიაპი</li>\n	<li>დაცვის სისტემა</li>\n	<li>კარაბინი (4-5 ცალი.)</li>\n	<li>დაცვის ქამარი</li>\n	<li>ჩაფხუტი</li>\n</ol>\n\n<p>ქვედათი ცოცვისთვის</p>\n\n<ol>\n	<li>7-8 ყინულის ბური და&nbsp;ექსპრესი</li>\n</ol>\n', '<p><strong>Guga -</strong>&nbsp;Mail: gugadabrunda@gmail.com&nbsp; &nbsp; Tel: (+995) 557 300 700.</p>\n\n<p><strong>Temo</strong>&nbsp;- Mail; samsonadze.temo9@gmail.com&nbsp; &nbsp; &nbsp;Tel: (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-19 20:23:10', '2023-08-08 22:47:57'),
(23, 'ka', 'ყინულზე ცოცვა ატენის ხეობაში', '<p>ყინულზე ცოცვა საქართველოში საკმაოდ დამკვიდრებული სპორტული დისციპლინაა. ვარჯიშის ერთ-ერთი საუკეთესო ადგილი ატენის ხეობაშია, სოფელ ბიისთან ახლოს.</p>\n', '<p>ყინულზე ცოცვა საქართველოში საკმაოდ დამკვიდრებული სპორტული დისციპლინაა. ვარჯიშის ერთ-ერთი საუკეთესო ადგილი ატენის ხეობაშია, სოფელ ბიისთან ახლოს.</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=DYw7XP9Iwv4\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/dxgq6p1\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n', '', '<p>დაგჭირდებათ თბილისიდან ბიისამდე დაახლოებით 1,5 საათი, მანძილი 130 კმ. მანქანის მთავარი მარშრუტის შემდეგ მარცხნივ შეუხვიეთ და შედიხართ სოფელში. გირჩევთ იმოგზაუროთ 4 &times; 4 მანქანით, რადგან ამ შემთხვევაში თქვენ შეძლებთ დამატებით 300 მეტრში ჩასვლას სოფელში, ქუჩის ცუდი პირობების გამო მთავარ გზაზე გაჩერებული მანქანის დატოვების გარეშე.</p>\n\n<p>თქვენი მანქანის გაჩერებასთან ერთად, 20 წუთის განმავლობაში უნდა იაროთ მდინარის გასწვრივ, სანამ არ მიაღწევთ გაყინული ჩანჩქერი, რომლის სიმაღლეა 60 მ, ხოლო სიგანე 5-15 მ.</p>\n\n<p>ახლომდებარე ქალაქები: 41 &deg; 51&#39;4 &quot;N 43 &deg; 59&#39;6&quot; E</p>\n\n<p>Დასარჩენი ადგილი<br />\nყინულის დაცემის ბოლოში ადგილი ღირსეულად დასაბანაკებლად - მაგრამ გაითვალისწინეთ, რომ ღამით ნამდვილად ცივდება!</p>\n', '<p>ეს დამოკიდებულია წლის ტემპერატურაზე, თებერვალი საუკეთესო თვეა ყინულზე ასვლისთვის.</p>\n', '<ol>\n	<li>თოკი 60 м (2 ც) ან&nbsp;120 м (1 ც)</li>\n	<li>წერაყინი (ყინულის ინსტრუმენტი)</li>\n	<li>წრიაპი</li>\n	<li>დაცვის სისტემა</li>\n	<li>კარაბინი (4-5 шт.)</li>\n	<li>დაცვის ქამარი</li>\n	<li>ჩაფხუტი</li>\n</ol>\n\n<p>ქვედათი ცოცვისთვის</p>\n\n<ol>\n	<li>7-8 ყინულის ბური და&nbsp;ექსპრესი</li>\n</ol>\n', '<p><strong>Guga -</strong>&nbsp;Mail: gugadabrunda@gmail.com&nbsp; &nbsp; Tel: (+995) 557 300 700.</p>\n\n<p><strong>Temo</strong>&nbsp;- Mail; samsonadze.temo9@gmail.com&nbsp; &nbsp; &nbsp;Tel: (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-19 20:47:03', '2023-08-08 22:49:54'),
(24, 'ka', 'სლექლაინი საქართველოში', '<p>საქართველოში slackline არ არის განვითარებული დისციპლინა, მაგრამ ის ვითარდება.</p>\n', '<p>Slacklining - ეხება სიარულის ან დაბალანსების აქტს ბრტყელი ქსელის შეჩერებული სიგრძის გასწვრივ, რომელიც დაძაბულია ორ წამყვანს შორის. Slacklining მსგავსია თოკზე სიარული და მჭიდრო სიარული. Slacklines განსხვავდება მჭიდრო მავთულხლართებისა და გამკაცრებისგან გამოყენებული მასალის ტიპით და გამოყენების დროს გამოყენებული დაძაბულობით. სლაკლაინები მნიშვნელოვნად ნაკლებია ვიდრე მჭიდები და მავთულები, რათა შეიქმნას დინამიური ხაზი, რომელიც გრძელი და ვიწრო ბატუტივით გაიჭიმება და გადახტება. დაძაბულობის რეგულირება შესაძლებელია მომხმარებლის შესაბამისად, და სხვადასხვა გარემოში შეიძლება გამოყენებულ იქნას სხვადასხვა ქსელის გამოყენება. Slacklining პოპულარულია მისი სიმარტივისა და მრავალფეროვნების გამო; ის შეიძლება გამოყენებულ იქნას სხვადასხვა გარემოში, რამდენიმე კომპონენტით.</p>\n\n<p>სლაკლინი საქართველოში - საქართველოში slackline არ არის განვითარებული დისციპლინა, მაგრამ ის ვითარდება. უკვე მთელ საქართველოში არის რამდენიმე მაღალი ხაზის რეგიონი (მათგან ყველაზე პოპულარული რაჭაში არის &quot;9 ჯვარი&quot;). ვებგვერდზე slacklinegeorgia.wordpress.com შეგიძლიათ იხილოთ დეტალური ინფორმაცია საქართველოს ყველა რეგიონის შესახებ.</p>\n\n<p>როგორ ვიპოვოთ?<br />\nთბილისში, ყველაზე ხშირად ვიკრიბებით &#39;ვაკის პარკში&#39;, &#39;თბილისის ბოტანიკურ ბაღში&#39; (კლდეზე ასვლის ადგილას) და &#39;ლისის ტბაში&#39;. შეხვედრის ადგილის შესახებ ერთმანეთს ვაცნობთ facebook- ის გვერდზე &#39;Sleckline Georgia&#39;.</p>\n\n<p>ბათუმში, ყველაზე ხშირად ვიკრიბებით &#39;6 მაისის პარკში&#39; და &#39;თემ კაფე ბართან&#39;. შეხვედრის ადგილის შესახებ ერთმანეთს ვაცნობთ facebook- ის გვერდზე &#39;Sleckline ბათუმი&#39;.</p>\n\n<p>ქუთაისში ყველაზე ხშირად ვიკრიბებით &#39;ჩომაში&#39; (კლდეზე ასვლის ადგილას). ადგილობრივ ბიჭებს თემო ქუთდიანს შეგიძლიათ დაუკავშირდეთ facebook- ზე.</p>\n\n<p>ინფორმაცია:<br />\nფეისბუქის გვერდი: slackline Georgia</p>\n\n<p>თბილისი -&gt; ფოსტა: Iraklisixarulidze@gmail.com; Facebook: მტვრიანი ჩექმები.</p>\n\n<p>ბათუმი -&gt; ფეისბუქი: ერეკლე ჩიკვაიძე.</p>\n\n<p>ქუთაისი -&gt; ფეისბუქი: თემო ქუთდიანი</p>\n', NULL, NULL, NULL, NULL, '<p><strong>Guga -</strong>&nbsp;Mail: gugadabrunda@gmail.com&nbsp; &nbsp; Tel: (+995) 557 300 700.</p>\n\n<p><strong>Temo</strong>&nbsp;- Mail; samsonadze.temo9@gmail.com&nbsp; &nbsp; &nbsp;Tel: (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-19 21:01:44', '2024-04-15 20:34:50'),
(25, 'ka', 'ჯავახიშვილის კლასიკური მარშრუტი (3A)', '<p>AD, M1, 300M, 5A (3A - RUS)</p>\n', '<p>P0 მარშრუტი იწყება ლეონიძე - ჯავახიშვილის კულვარიდან. კულვარიდან ავდივართ უნაგირამდე, სადაც გვხვდება დიდი ქვა. ქვის მარცხნივ ვპოულობთ ქიმზე აწყობილ სადგურს.</p>\n', '<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"height:106px; width:100%\">\n	<tbody>\n		<tr>\n			<td>Pitch</td>\n			<td>Grade</td>\n			<td>Height</td>\n		</tr>\n		<tr>\n			<td>P0</td>\n			<td>M1</td>\n			<td>100m</td>\n		</tr>\n		<tr>\n			<td>P1</td>\n			<td>5A</td>\n			<td>25m</td>\n		</tr>\n		<tr>\n			<td>P2</td>\n			<td>5A</td>\n			<td>50m</td>\n		</tr>\n		<tr>\n			<td>P3</td>\n			<td>4</td>\n			<td>50m</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>P1 - სადგურიდან არის ასვლის 2 ვარიანტი. პირველი - სადგურის მარცხნივ არსებული ბუხარით გავდივართ ტაროზე, სადაც გვხვდება პალოებით აწყობილი სადგური.</p>\n\n<p>მეორე - სადგურის ტავზე არსებული ნაპრალი ავდივართ თაროზე.</p>\n\n<p>P2 - სადგურიდან გავდივართ მარჯვნივ. დახრილი ნაპრალით გავდივართ ბრტყელ გადაწვენილ კლდეზე. კედელზე შესაძლებელია ვიპოვოთ პალოები. ვაგრძლებეთ ცოცვას და ვპოულობთ სამ პალოზე აწყობილ სადგურს.</p>\n\n<p>P3 - სადგურიდან ვაგრძელებთ ცოცვას და გავდივართ თაროზე. ტაროზე ვპოულობთ ქიმზე აწყობილ სადგურს.</p>\n\n<p>Top - სადგურიდან მარცხნივ მივდივართ ბილიკით, რომელსაც გავყავართ მწვერვალ ჯავახიშვილზე.</p>\n\n<p><br />\n&nbsp;</p>\n\n<p>ჯავახიშვილის კლასიკური მარშრუტი, ყველაზე მარტივი გზაა მა მთის მწვერვალზე მოსახვედრად. მარშრუტი საკმაოდ მარტივია, ამიტომ მისი ცოცვა დამწყები ალპინისტისთვის იქნება ყველაზე კარგი. მათთვის ვინც ახლა იწყებს მთაში სიარულს. მარშრუტი სულ სამი თოკისგან შედგება, რომელთა სირთულე 5A -ს (F) არ აღემატება.</p>\n\n<p>პირველი საბანაკედან კულვარის ძირამდე მისასვლელად 2:00 &ndash; 2,5 საათი დაგჭირდებათ.</p>\n\n<p>მეორე საბანაკედან 00: 45 &ndash; 1,5 საათი.</p>\n\n<p>საშუალო დრო კულვარიდან წვერამდე 4- 5 საათი.</p>\n', '<p>.</p>', '<p>საუკეთესო დრო მარშრუტის გასავლელად ზაფხულის პერიოდია. ამ დროს ნალექების რაოდენობა ყველაზე მცირეა და ტემპერატურა ყველაზე მაღალი (12-დან - 0-გრადუსამდე), მაგრამ შესაძლებელია ზამთრის პერიოდში მარშრუტზე გასვლა. გასითვალისწინეთ: ზამთარში კულუარში ბევრად მეტი თოვლია და ხშირია ზვავები. ტემპერატურა -15-დან -25-თ გრადუსამდე მერყეობს.</p>', '', '<p>თემო - samsonadze.temo9@gmail.com</p>\n', NULL, NULL, '2021-10-03 07:01:13', '2024-05-06 01:48:07'),
(26, 'ka', 'ცოცვა ბორჯომის მუნიციპალიტეტში', '<p>ბორჯომი მდებარეობს აღმოსავლეთ საქართველოში&nbsp;აქ შეგიძლია დაკავდეთ, როგორც კლდეზე ცოცვით, ასევე სხვადასხვა აქტივობებით.</p>\n', '<p>ბორჯომი მდებარეობს აღმოსავლეთ საქართველოში,&nbsp; ზ.დ. 900მ. მოსახლეობა ~10000&nbsp;ადამიანი. ბორჯომის მუნიციპალიტეტი&nbsp;ძალიან პოპულარულია სათავგადასავლო ტურიზმის მოყვარულთა შორის. აქ შეგიძლია დაკავდეთ, როგორც კლდეზე ცოცვით, ასევე სხვადასხვა აქტივობებით: ტრეკინგი, ველო ტური, ჯომარდობა, და სხვა.</p>\n\n<p>დაბა ბორჯომიდან 10&nbsp;კმ - ში სოფელ ტიმოთესუბანში&nbsp;არის საცოცი რეგიონი. რეგიონის ისტორია წინა საუკუნის 80-იან წლებში იწყებ მაგრამ ბოლო 20-25 წელი&nbsp;რეგიონში არანაირი აქტიობა არ ჩატარებულა.&nbsp;2021წლის ზამთარში დაიწყო რეგიონის რეაბილიტაცია. დასაწყისისთვის გაკეთდა მხოლოდ 1 სექტორი და 8 მარშრუტი მაგრამ უკვე 2022 წლის ზაფხულისთვის იგეგმება მეტი მარშრუტის გაკეთება.</p>\n\n<p>&nbsp;</p>\n\n<p><a href=\"https://www.amazon.com/PETZL-Mambo-10-1mm-Climbing-Turquoise/dp/B08PW16GBQ?crid=2PB785LFNRL1W&amp;keywords=petzl%2Bclimbing%2Brope&amp;qid=1698877575&amp;sprefix=petzlclimbing%2Brope%2Caps%2C206&amp;sr=8-1-spons&amp;sp_csd=d2lkZ2V0TmFtZT1zcF9hdGY&amp;th=1&amp;psc=1&amp;linkCode=li2&amp;tag=climbingge09-20&amp;linkId=1b4a794b071ac8049b3c306a03f54623&amp;language=en_US&amp;ref_=as_li_ss_il\" target=\"_blank\"><img src=\"//ws-na.amazon-adsystem.com/widgets/q?_encoding=UTF8&amp;ASIN=B08PW16GBQ&amp;Format=_SL160_&amp;ID=AsinImage&amp;MarketPlace=US&amp;ServiceVersion=20070822&amp;WS=1&amp;tag=climbingge09-20&amp;language=en_US\" /></a><img alt=\"\" src=\"https://ir-na.amazon-adsystem.com/e/ir?t=climbingge09-20&amp;language=en_US&amp;l=li2&amp;o=1&amp;a=B08PW16GBQ\" style=\"height:1px; margin:0px !important; width:1px\" /></p>\n', '<p>2021წლის ზამთარში დაიწყო რეგიონის რეაბილიტაცია. დასაწყისისთვის გაკეთდა მხოლოდ 1 სექტორი და 8 მარშრუტი მაგრამ უკვე 2022 წლის ზაფხულისთვის იგეგმება მეტი მარშრუტის გაკეთება.</p>\n\n<p><strong>ქანი</strong> - ბაზალტი</p>\n\n<h3><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong></h3>\n\n<h3><br />\nიმ შემთხვევაში, თუ აპირებთ მარშრუტების გაკეთებას ამ რეგიონში, გთხოვთ, აცნობოთ ადგილობრივ მეკლდეურებს თქვენი გეგმების შესახებ, წინააღმდებ შემთხვევაში თქვენი მაშრუტები შესაძლებელია დემონტაჟს დაექვემდებაროს.</h3>\n\n<p><strong>აგრეთვე აკრძალულია Drytooling-ის ცოცვაც!</strong></p>\n\n<p><strong>გამოიყენეთ ჩაფხუტი თქვენი უსაფრთხოებისათვის !</strong></p>\n\n<h3><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong><br />\nიმ შემთხვევაში, თუ აპირებთ მარშრუტების გაკეთებას ამ რეგიონში, გთხოვთ, აცნობოთ ადგილობრივ მეკლდეურებს თქვენი გეგმების შესახებ, წინააღმდებ შემთხვევაში თქვენი მაშრუტები შესაძლებელია დემონტაჟს დაექვემდებაროს.</h3>\n\n<p><strong>აგრეთვე აკრძალულია Drytooling-ის ცოცვაც!</strong></p>\n\n<p><strong>გამოიყენეთ ჩაფხუტი თქვენი უსაფრთხოებისათვის !</strong></p>\n', '<p>დაბა ბორჯომიდან მივდივართ ბაკურიანის მიმართულებით 9კმ-ში შეგვხვდება სოფელი წაღვერი. წაღვერის ცენტრალური მოედნიდან ვუხვევთ მარცხნივ და მივდივართ 700-1000მ-ს&nbsp;სოფელ ტიმოთეს უბნისკენ. მარჯვენა მხარეს შეგვხდება წყარო ( და წყაროს ნიშანი). წყაროსთან ვპოულიბთ მდინარეზე გადასასვლელ ხიდს გადავდივართ ხიდზე და ვხვდებით კლდესთან. აქვე შესაძლებელია მანქანის გაჩერება. დეტალური ინფორმაციისთვის იხილეთ რუკა.</p>\n', '<p>საუკეთესო დრო რეგიონში საცოცად: გვიანი გაზაფხოლი,&nbsp;ზაფხული შემოდგომის შუამდე. კლდე დღის განმავლობაში უმეტესად ჩრდილშია აიტომაც დღის განმავლობაში უმეტესად ცივა. რეგიონში მისვლამდე გირჩევთ გადაამოწმოთ ამინდი.</p>\n', '<ol>\n	<li>14 ექსპრესი</li>\n	<li>თოკი 60მ</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხუტი</li>\n	<li>საცოცი ფეხსაცმელი (სკალნი) &amp; მაგნეზიის ტომატა</li>\n</ol>\n', '<p>თემო - Tel - (+995) 598457048.&nbsp;Email - samsonadze.temo9@gmail.com</p>\n', NULL, NULL, '2021-11-21 18:30:47', '2023-11-02 02:30:06'),
(27, 'ka', 'ახალი საცოცი სექტორები ბორჯომში', '<p>ბორჯომის მუნიციპალიტეტი ერთერთი ყველაზე პოპულარულია ტურისტებისთვის და აქტიური დასვენების მოყვარულთათვის. ცოტახნის წინ აქ დაემატა ახალი საცცი სექტორი.</p>\n', '<p>დაბა ბორჯომი თბილისიდან 150კმ-ში მდებარეობს. ბორჯომის მუნიციპალიტეტი ერთერთი ყველაზე პოპულარულია ტურისტებისთვის და აქტიური დასვენების მოყვარულთათვის. აქ თქვენ შეგიძლებთ ეწვიოთ ბორჯომ-ხარაგაულის ეროვნულ პარკს, სადაც შეჯიძლიათ რტეკინგით დაკავება შესაძლებელია ასევე ეწვიოთ გოგირდის აბანოებს და დაკავდეთ ჯომარდობით.</p>\n\n<p>ბორჯომიდან 20კმ-ში მდებარეობს სოფელი ცემი სადაც საქაღთველოში ერთერთი ყველაზე ძველი საცოცი სექტორი მდებარეობს. სექტორში შეჯიბრები ჯერ კიდე მე-20 საუკუნის 80 წლებში ტარდებოდა. მიუხედავად ამისა ბოლო 20 წელია რეგიონი სრულიად მივიწყებულია და აქ სპორტული აქტიობები საერთოდ არ ტარდებოდა.&nbsp;საცოც სექტორში არ იყო არანაირი ინფროსტრუქტურა საცოცად რის გამოს აქ ცოცვა შეუძლებელი იყო.</p>\n\n<p>2021 წლის ნოემბრიდან დაიწყო სამუშაოები საცოცი სექტორის გასანახლებლად. პირველ ეტაპზე გაკეთდა მხოლოდ 3 საცოცი მარშრუტი, მაგრამ, უახლოეს მომავალში სამუშაოები გაგრძელდება და აქ გაკეთდება კიდევ უფრო მეტი საცოცი მარშრუტი.</p>\n\n<p><a href=\"https://climbing.ge/outdoor/climbing_near_borjomi\">რეგიონის დეტალური აღწერის სანახავად გადადით ბმულზე.</a></p>\n', NULL, '<p>საცოც სექტორში მისასვლელად <a href=\"https://www.google.com/maps/d/u/0/edit?mid=1zLk1GegB8K4QLJKiheI4D1odWy6rPffn&amp;ll=41.798991224962606%2C43.490982900000006&amp;z=18\">იხილეთ რუკა</a>.</p>', NULL, NULL, '<p><strong>თემო</strong> &nbsp;<strong>Tel:</strong> (+995) 598 45 70 48. <strong>Mail:</strong> samsonadze.temo9@gmail.com</p>', NULL, NULL, '2021-11-23 17:24:11', '2024-08-12 14:23:58'),
(28, 'ka', 'საცოცი დარბაზი სტეფანწმინდა (ყაზბეგი)', '<p>.</p>', '<p>.</p>', NULL, NULL, NULL, NULL, '<p>.</p>', NULL, NULL, '2022-05-05 18:52:52', '2022-05-05 18:59:15');
INSERT INTO `locale_articles` (`id`, `locale`, `title`, `short_description`, `text`, `route`, `how_get`, `best_time`, `what_need`, `info`, `price_text`, `address`, `created_at`, `updated_at`) VALUES
(29, 'ka', 'მწვერვალი ჯავახიშვილის სამხრეთ კედელი \"ილიაუნი\"', '<p>TD+/ED (5A RUS)</p>\n', '<p>დილის საათებში მარშრუტი მზეშია, ამიტომ მისი ცოცვა სასიამოვნოა, როგორც ზაფხულში, ასევე ზამტარში.</p>\n\n<p>პირველი ბანაკიდან მარშუტის ძირამდე მისასვლელად 2,5 &ndash; 3,0 საათი დაგჭირდებათ.</p>\n\n<p>მეორე ბანაკიდან 1,0 -1,5 საათი.</p>\n\n<p>საშუალო დრო მარშრუტის ძირიტად მწვერვალამდე 4-6 საათი.</p>\n', '<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"height:106px; width:100%\">\n	<tbody>\n		<tr>\n			<td>Pitch</td>\n			<td>Grade</td>\n			<td>Height</td>\n		</tr>\n		<tr>\n			<td>P0</td>\n			<td>&nbsp;</td>\n			<td>30m</td>\n		</tr>\n		<tr>\n			<td>P1</td>\n			<td>5B</td>\n			<td>50m</td>\n		</tr>\n		<tr>\n			<td>P1.5</td>\n			<td>4</td>\n			<td>15m</td>\n		</tr>\n		<tr>\n			<td>P2</td>\n			<td>6A</td>\n			<td>40m</td>\n		</tr>\n		<tr>\n			<td>P3</td>\n			<td>5C+</td>\n			<td>40m</td>\n		</tr>\n		<tr>\n			<td>P4</td>\n			<td>5A</td>\n			<td>30m</td>\n		</tr>\n		<tr>\n			<td>P5</td>\n			<td>5b</td>\n			<td>30m</td>\n		</tr>\n		<tr>\n			<td>Top</td>\n			<td>&nbsp;</td>\n			<td>40m</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>&nbsp;</p>\n\n<p>მარშრუტი იწყება ლეონიძე - ჯავახიშვილის კულუარის მარცხნივ. ნაყარ ფერდზე შევდივართ კედლის ძირამდე, მარცხენა მხარეს ვპოულობთ ნაპრალს. აქედან იწყება მარშრუტი.</p>\n\n<p>P0 - ვიწყებთ ცოცვას ფართე ნაპრალში(დაცვისთვის გამოიყენეთ დიდი ზომის ჩასადები ელემენტები), გავდივართ ვიწრო ტაროზე და ქიმზე ვაკეთებთ დაცვას. სადგურიდან ვაგრძელებთ ცოცვას მარჯვნივ. 4-5 მეტრიანი კედლით გავდივართ დიდ ტაროზე, გავდივართ მარჯვნივ და ქიმზე ვაკეთებთ სადგურს, დიდი ბუხრის ძირში.</p>\n\n<p>P1 - ვიწყებთ ცოცვას ბუხარში, ბუხრის მარჯვნივ და მარცხენა კედელზე ბევრი ნაპრალია დაცვის გასაკეთებლად. ბუხრის თავზე გვხვდება დიდი ქვების ვარდნის შედეგად წარმოქმნილი ჭერი. მარცხენა მხარეს ვპოულობთ ვიწრო გასაძრომს და გავდივართ თაროზე. გასაძრომის თავთან გვხვდება ქიმზე აწყობილი სადგური.</p>\n\n<p>P1.5 - სადგურის მარცხნივ ერთდროული სიარულით მივუყვებით თაროს, ავდივართ 5მ სიმაღლის მარტივ კედელზე და ვხვდებით დიდი კედლის ძირას არსებულ ტაროზე.</p>\n\n<p>P2- დიდ კედელზე შუაში მივუყვებით ღარს (ყველაზე დიდი ღარი), მივყვებით ღარს, მარჯვენა მხარეს გვხვდება თარო და თაროს 4მ მაღლა ვპოულობთ 2 პალოს, რომელზეც ვაწყობთ სადგურს.</p>\n\n<p>P3 - ვაგრძელებთ ცოცვას ღარში, სანამ არ გადავალთ გადაწვენილ კედელზე, ნატეხი, ნაშალი ქანით.</p>\n\n<p>კედელზე ბევრია ვიწრო ღარი. ვაგრძელებთ ცოცვას კედლის შუაში და ვხვდებით ვიწრო თაროზე, სადაც ვაკეთებთ სადგურს (სადგურის გაკეთება ამაზე მაღლა რეკომენდირებული არ არის).</p>\n\n<p>P4 - ვაგრძელებთ ცოცვას პირდაპირ, სანამ არ მოვხვდებით დიდი ბუხრის ქვემოთ, დიდ თაროზე. ბუხრის ძირში ვაკეთებთ სადგურს.</p>\n\n<p>P5- ვაგრძელებთ ცოცვას დიდ ბუხარში, სანამ არ გავალთ მორიგ დიდ ტაროზე. აქედან ვიწყებთ ერთდროულად სიარულს.</p>\n\n<p>TOP - თაროდან ვაგრძელებთ ერთდროულად ცოცვას, მარტივ რელიეფზე. გავდივართ მწვერვალის ძირში. პატარა თაროზე ვუვლით მწვერვალს დასავლეთის მხრიდან ( მივდივართ მარცხნივ) ვხვდებით ბუხარში. ბუხრიდან გასვლისთანავე ვხვდებით მწვერვალზე.</p>\n\n<p>საშუალო დრო მარშრუტის ძირიტად მწვერვალამდე 4-6 საათი.</p>\n', '<p>პირველი ბანაკიდან მარშუტის ძირამდე მისასვლელად 2,0&nbsp;&ndash; 3,0 საათი დაგჭირდებათ.</p>\n\n<p>მეორე ბანაკიდან 0.5&nbsp;-1,0&nbsp;საათი.</p>\n\n<p>&nbsp;</p>', '<p>დილის საათებში მარშრუტი მზეშია, ამიტომ მისი ცოცვა სასიამოვნოა, როგორც ზაფხულში, ასევე ზამტარში.</p>\n\n<p>საუკეთესო დრო მარშრუტის გასავლელად ზაფხულის პერიოდია. ამ დროს ნალექების რაოდენობა ყველაზე მცირეა და ტემპერატურა ყველაზე მაღალი (12-დან - 0-გრადუსამდე), მაგრამ შესაძლებელია ზამთრის პერიოდში მარშრუტზე გასვლა. გასითვალისწინეთ: ზამთარში კულუარში ბევრად მეტი თოვლია და ხშირია ზვავები. ტემპერატურა -15-დან -25-თ გრადუსამდე მერყეობს.</p>', '<p>&nbsp;</p>\n\n<ol>\n</ol>\n', '<p>თემო - samsonadze.temo9@gmail.com</p>\n', NULL, NULL, '2022-08-23 19:24:25', '2025-06-13 16:55:12'),
(30, 'ka', 'მწვერვალი ლეონიძე სამხრეთიდან', '<p>EA - M1, 6A, 350M (4A RUSS)</p>\n', '<p>ჯავახიშვილის აღმოსავლითი კედელი ამ მწვერვალის ყველაზე პოპულარული მარშრუტი. მარშრუტი კარგია მოყვარულ ალპინისტათვის.</p>\n', '<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"height:106px; width:100%\">\n	<tbody>\n		<tr>\n			<td>Pitch</td>\n			<td>Grade</td>\n			<td>Height</td>\n		</tr>\n		<tr>\n			<td>P0</td>\n			<td>M1</td>\n			<td>200m</td>\n		</tr>\n		<tr>\n			<td>P1</td>\n			<td>6A+</td>\n			<td>50m</td>\n		</tr>\n		<tr>\n			<td>P2</td>\n			<td>6A</td>\n			<td>40m</td>\n		</tr>\n		<tr>\n			<td>P3</td>\n			<td>5B</td>\n			<td>40m</td>\n		</tr>\n		<tr>\n			<td>P4</td>\n			<td>4</td>\n			<td>100m</td>\n		</tr>\n		<tr>\n			<td>P5</td>\n			<td>5A</td>\n			<td>70m</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>&nbsp;</p>\n\n<p>P0 - მარშრუტი იწყება ჭაუხის ცირკიდან. ჯავახიშვილი &ndash; ლეონიძის კულუარით, შავდივართ უნაგირამდე. კულუარში გვხვდება უმეტესად თოვლი თუმცა წლის ცივ დროს შესაძლოა ყინულიც. აგვისტოში და სექტემბრის ბოლომდე თოვლი და ყინული თითქმის სოლ დამდნარია და გვიწევს ნაყარი ქვებით ასვლა. სასურველია თოკში ჩაბმით სიარული თუმცა ხშირად ცალცალკე ასვლაც(ჩაუბმელად) არ წარმოადგენს საშიშროებას.</p>\n\n<p>P1 - კ&nbsp;უნაგირიდან მარჯვენა მხარეს ვიწყებთ ცოცვას. დასაწყისში 10მ მცირე უარყოფითი ცოცვით გავდივართ პატარა თაროზე, აქედან მივუყვებით ღარს რომელიც ნელ-ნელა შედის მარჯვნივ.( 50 მ).</p>\n\n<p>P2 - სადგურიდან მარჯვნივ მიუყვება მცირე ზომის ნაპრალი, ამ ნაპრალის გავლის შემდეგ ვხვდებით მარცხნივ ვიწრო ბუხარში და გავდივართ დიდ პლატფორმაზე, სადაც არის რამდენიმე სადგური.</p>\n\n<p>P3 -&nbsp; თაროდან მარჯვენა მხარეს მივყვებით მარტივი ბუხარი (50 მ).</p>\n\n<p>P4 - ბუხრის დამთავრებისთანავე ვაგრძელებთ ტრავერს მარჯვენა მხარეს 100 მ, ფართო პლატფორმამდე. აქედან მივუყვებით გაშლილ ბუხარს რომლითაც გავდივართ ქედზე.</p>\n\n<p>P5 - მივუყვებით ქედს და 70მ-ში გავდივართ მწვერვალზე.</p>\n\n<p>დაშვება იგივე მარშრუტით</p>\n\n<p>მარშრუტის ხანგრძლივობა: 7-8 საათი.</p>\n', NULL, NULL, '', '<p>.</p>\n', NULL, NULL, '2022-08-23 19:35:54', '2025-06-19 23:43:00'),
(31, 'ka', '\"დიდი დიღომი\"', '<p>.</p>\n', '<p>მარშრუტის პირველი გავლა - ბიძინა გუჯაბიძე და ალექსანდრე გუჯაბიძე</p>\n', '', NULL, NULL, '', '<p>.</p>', NULL, NULL, '2022-08-23 19:40:16', '2024-12-16 18:10:50'),
(32, 'ka', 'კამერუნი კლასიკა (3A)', '<p>AD, M1, 600M, 5A (3A - RUS)</p>\n', '<p>კამერუნის კლასიკური მარშრუტი ერთერთი საინტერესო და განსხვავებული მარშრუტია ჭაუხის მასივში. მარშრუტი საინტერესო იქნება დამწყებ და საშუალო დონის ალპინისტებისთვის</p>\n', '<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"height:106px; width:100%\">\n	<tbody>\n		<tr>\n			<td>Pitch</td>\n			<td>Grade</td>\n			<td>Height</td>\n		</tr>\n		<tr>\n			<td>P0</td>\n			<td>M2</td>\n			<td>500m</td>\n		</tr>\n		<tr>\n			<td>P1</td>\n			<td>5A</td>\n			<td>50m</td>\n		</tr>\n		<tr>\n			<td>P2</td>\n			<td>5B</td>\n			<td>40m</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>&nbsp;</p>\n\n<p>P0 - მარშრუტი იწყება ასათიანი - კამერუნის კულუარის დასაწყისში. გრძელი კულუარით ავდივართ უნაგირზე (კულუარის გავლის საშუალო დრო 2-3 საათი.) კულუარის მარცხენა კედელზე ვიყყებთ ცოცვას.</p>\n\n<p>P1 -&nbsp;ვიწყებთ ცოცვას კედელზე, თანდათან შევდვართ მარცხენა მხარეს. უნაგირიდან 10მ-ში ვპოულობთ პალოს აქედან ისევ მარცხნივ ცოცვით შევდივართ ქვიან ქედზე სადაც ვპოულობთ პალოებზე აწყობილ სადგურს.</p>\n\n<p>P2 - ვაგრძელებთ ცოცვას ზემოთ და გავდივართ ქედზე. ვატრავერსებთ მარცხნივ და ქედის ყველაზე მაღალ წერტილში ვპოულობთ ქიმზე აწყობილ სადგურს.&nbsp;</p>\n\n<p>TOP -&nbsp;სადგურინან ჩავდივართ 8-9 მეტრს ქვემოთ და ვხვდებით სწორ ბაქანზე (თაროზე). აქედან ერთდროული სიარულით ვაგრძელებთ მწვერვალისკენ სიარულს. მწვერვალს ვუვლით&nbsp;მარჯვენა მხრიდან და ავდივართ ვიწრო მოსწორებული ზედაპირის მწვერვალზე (მწვერვალზე გვხდება ტური)</p>\n', NULL, NULL, '<p>მარშრუტზე დაგჭირდებათ:</p>\n\n<ol>\n	<li>თოკი 50მ</li>\n	<li>ზაკლადკები 4-5ც საშუალო ზომები</li>\n	<li>ფრენდები 3-4ც საშუალო ზომები</li>\n	<li>ექსპრესი 4-5ც</li>\n	<li>კარაბინი 3-4ც და თვითდაცვა</li>\n	<li>დაცვის-დასაშვები სისტემა</li>\n	<li>დაცვის ქამარი და ჩაფხუტი</li>\n	<li>წრიაპი წერაყინი (დამოკიდებულია თოვლის სიმრავლეზე კულუარში)</li>\n</ol>\n\n<p>ზამთრის პერიოდში დამატებით დაგჭირდებათ&nbsp;</p>\n\n<ol>\n	<li>თოვლის ფეხსაცმელი (სნეგასტუპები)</li>\n	<li>ყინულის ბური 2-3ც</li>\n</ol>\n', '<p>.</p>\n', NULL, NULL, '2022-08-23 19:45:32', '2024-05-06 01:49:41'),
(33, 'ka', 'მწვერვალი ასათიანი სამხრეთიდან', '<p>D M1 5A 200M (4A; RUSS)</p>\n', '<p>.</p>\n', '<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:100%\">\n	<tbody>\n		<tr>\n			<td>Pitch</td>\n			<td>Pitch Height</td>\n			<td>Inclination of<br />\n			the wall</td>\n			<td>Grade (UIAA)</td>\n			<td>Grade (ftr)</td>\n		</tr>\n		<tr>\n			<td>R5</td>\n			<td>30</td>\n			<td>50</td>\n			<td>III</td>\n			<td>4-</td>\n		</tr>\n		<tr>\n			<td>R4</td>\n			<td>20</td>\n			<td>10-20</td>\n			<td>II</td>\n			<td>4-</td>\n		</tr>\n		<tr>\n			<td>R3</td>\n			<td>30</td>\n			<td>70</td>\n			<td>IV</td>\n			<td>4</td>\n		</tr>\n		<tr>\n			<td>R2</td>\n			<td>40</td>\n			<td>60</td>\n			<td>III</td>\n			<td>4-</td>\n		</tr>\n		<tr>\n			<td>R1</td>\n			<td>40</td>\n			<td>70</td>\n			<td>IV</td>\n			<td>5</td>\n		</tr>\n	</tbody>\n</table>\n\n<p><strong>ცირკიდან</strong> <strong>ჯავახიშვილის კულუარის მარჯვნივ&nbsp;</strong>ასვლა იწყება თოვლიანი კულუარით უნაგირამდე (400 მ).</p>\n\n<p>უნაგირიდან ასვლას ვიწყებთ სამიანი სირთულის კედელზე (50 მ) მარჯვენა მხარეს, აქ განთავსებულია სადგური, რომელიც პიტონებითაა დაკრული. გააკეთეთ 2-3 მ. ტრავერსი მარჯვენა მხარეს და მოხვდებით ფართო &bdquo;ცეცხლის ადგილზე&ldquo;. 60 მ. თოვლიანი და ქვით ჩამოყრილი &bdquo;ცეცხლის ადგილიდან&ldquo; გადადით ნაკლებად თოვლიან ჩანგულზე. კედლის მხარეს მდებარეობს სადგური. ჩანგულიდან მარცხნივ გადაიხარეთ 40 მ. და შეაღწიეთ ვიწრო გადახრილ &bdquo;ცეცხლის ადგილს&ldquo;. ამაღლდით გრძელი ვიწრო პლატფორმით და აქ განთავსებულია სადგური, რომელიც პიტონებითაა დაკრული. 20 მ. ტრავერსი მარჯვენა მხარეს, პატარა &bdquo;ცეცხლის ადგილთან&ldquo; ქვედა პლატფორმისკენ. გახსნილი კუთხით &bdquo;ცეცხლის ადგილიდან&ldquo; გადადით მთის ქედზე. მიყვით ჩანგულს მთის ქედზე და მიხვდებით მწვერვალამდე.</p>\n\n<p><strong>დაშვება:</strong> იგივე მარშრუტით. <strong>დრო:</strong> 8-9 საათი.</p>\n', NULL, NULL, '', '<p>.</p>', NULL, NULL, '2022-08-23 20:01:40', '2025-01-23 01:52:14'),
(34, 'ka', 'მყინვარწვერის კლასიკური მარშრუტი', '<p>PD (2A RUSS)</p>\n', '<p>მყინვარწვერის კლასიკური მარშრუტი ყველაზე პოპულარული გზაა მწვერვალისკენ, რომელზეც ყოველწლიურად ათასობით ალპინისტი ადის.</p>\n\n<p>მარშრუტი ტექნიკურად საკმაოდ მარტივია, თუმცა აუცილებელია კარგი ფიზიკური მომზადება და შესაბამისი აკლიმატიზაცია.</p>\n\n<p>აკლიმატიზაციისთვის რეკომენდებულია ერთი დღე დასვენება ბეთლემის ქოხში. ამ დღეს სასურველია მცირე გასვლა ბეთლემის ეკლესიისკენ &mdash; როგორც მსუბუქი აქტივობა, ასევე ხედებისა და გარემოს გასაცნობად.</p>\n', '<p>მარშრუტი იწყება ბეთლემის ქოხიდან (მეტეოსადგურიდან). აქედან მივდივართ ჩრდილოეთის მიმართულებით და მივუყვებით ფერდობს მყინვარის გასწვრივ. მეტეოდან გასვლის შემდეგ გზაზე გხვდება საბანაკე ადგილი &mdash; ჯვრის საბანაკე, რომელსაც ავუვლით გვერდს და ვაგრძელებთ მოძრაობას ჩრდილოეთისკენ.</p>\n\n<p>ცოტა ხნის სიარულის შემდეგ მივდივართ &bdquo;ხმაურასთან&ldquo;, სადაც ხშირია ქვათაცვენა. ამიტომ აუცილებელია ჩაფხუტის დაფარება და საჭიროების შემთხვევაში &mdash; წრიაპის ჩაცმა. &bdquo;ხმაურის&ldquo; გავლის შემდეგ აუცილებელია თოკში ჩაბმა.</p>\n\n<p>შემდეგ მივდივართ მყინვარის პლატოზე, საიდანაც გეზს ვიღებთ ჩრდილო-აღმოსავლეთისკენ და მივუყვებით დასავლეთის ფერდს. ხშირი ნაპრალების გამო აუცილებელია თოკში ჩაბმულად სიარული, ასევე &mdash; წრიაპის ჩაცმა და საჭიროების შემთხვევაში წერაყინით გადაადგილება.</p>\n\n<p>ფლატოდან გადავდივართ სამხრეთისკენ დახრილ ფერდობზე (დახრილობა დაახლოებით 25-35 გრადუსი) და შევდივართ ორ მწვერვალს შორის მდებარე უნაგირზე (ჩრდილოეთ და სამხრეთ მწვერვალებს შორის).</p>\n\n<p>აქედან, ყინულის ფერდობით (დაახლ. 35-40 გრადუსი) მივდივართ ჩრდილოეთისკენ და გავდივართ მწვერვალზე.</p>\n\n<p><strong>მეტეოდან გასვლის დრო</strong>: ღამის 2 საათი.<br />\n<strong>მარშრუტის ხანგრძლიობა (ბეთლემის ქოხიდან - მწვერვალამდე)</strong>: 8-10 საათი<br />\n<strong>დაშვება</strong>: იმავე მარშრუტით.</p>\n', NULL, NULL, '', '<p>.</p>', NULL, NULL, '2022-08-23 21:03:42', '2025-07-04 18:35:12'),
(36, 'ka', 'ცოცვა გველეთში', '<p>.</p>\n', '<p><strong>გველეთში ცოცვა</strong><br />\nმანძილი ყაზბეკიდან: 8 კმ (დარიალის ხეობაში). ადგილზე არის 2&nbsp;მარშრუტი.</p>\n', '<p>ამ რეგიონში მუდმივად ვამატებთ ახალ მარშრუტებს. მარშრუტები 5A- დან 7A- მდეა. აგრეთვე გვაქვს 3-4&nbsp;თოკიანი მარშრუტი (მულტიპიჩი).</p>\n\n<p>უსაფრთხოების მიზნით, გამოიყენეთ ჩაფხეტი!</p>\n\n<p>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია !<br />\nიმ შემთხვევაში, თუ თქვენ აპირებთ მატშტუტების გაკეთებას ჭიათურაში აუცილებლად შეატყობინეთ ადგილობრივ მეკლდეურებს. წინააღმდეგ შემთხვევაში თქვენი მარშრუტი შესაძლებელია დემონტაჟს დაექვემდებაროს.</p>\n\n<p>&quot;Drytooling&quot;-ის ცოცვა რეგიონში სასტიკად აკრძალულია!</p>\n', '', '<p>ივნისი-ოქტომბერი, მაგრამ თუ კარგი ამინდია შესაძლებელია ზამთარშიც ცოცვა.</p>\n', '<p>20 ექსპრესი<br />\nთოკი 60მ<br />\nდაცვის ქამარი<br />\nდაცვის სისტემა<br />\nჩაფხუტი<br />\nსაცოცი ფეხსაცმელი (სკალნი) &amp; მაგნეზიის ტომატა</p>\n', '<p>თემო: Mail - samsonadze.temo9@gmail.com, Tel - (+995) 598 45 70 48</p>\n\n<p>გუგა: Mail - gugadabrunda@gmail.com,&nbsp;Tel: (+995) 557 300 700.</p>\n', NULL, NULL, '2022-09-05 13:30:21', '2023-04-13 11:18:31'),
(37, 'ka', 'ცოცვა ანანურთან', '<p>.</p>\n', '<p>ცოცვა ანანურთან</p>\n', '<h2><strong>საცოც რეგიონში მარშრუტების კეთება(დაშლამბურება) ადგილობრივი მეკლდეურების გარეშე სასტიკად აკრძალულია&nbsp;!</strong></h2>\n\n<p><br />\nიმ შემთხვევაში, თუ აპირებთ მარშრუტების გაკეთებას ამ რეგიონში, გთხოვთ, აცნობოთ ადგილობრივ მეკლდეურებს თქვენი გეგმების შესახებ, წინააღმდებ შემთხვევაში თქვენი მაშრუტები შესაძლებელია დემონტაჟს დაექვემდებაროს.</p>\n\n<p><strong>აგრეთვე აკრძალულია Drytooling-ის ცოცვაც!</strong></p>\n\n<p><strong>გამოიყენეთ ჩაფხუტი თქვენი უსაფრთხოებისათვის !</strong></p>\n', '', '', '<ol>\n	<li>10&nbsp;ექსპრესი</li>\n	<li>თოკი 40მ</li>\n	<li>დაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხუტი</li>\n	<li>საცოცი ფეხსაცმელი (სკალნი) &amp; მაგნეზიის ტომატა</li>\n</ol>\n', '<p><strong>Guga -</strong>&nbsp;Mail: gugadabrunda@gmail.com&nbsp; &nbsp; Tel: (+995) 557 300 700.</p>\n\n<p><strong>Temo</strong>&nbsp;- Mail; samsonadze.temo9@gmail.com&nbsp; &nbsp; &nbsp;Tel: (+995) 598 45 70 48</p>\n', NULL, NULL, '2022-09-05 13:41:36', '2025-06-05 18:40:47'),
(38, 'ka', 'Advanture 2022 - ჭიათურის ტურისტული ფესტივალი', NULL, '<p><img alt=\"📢\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t39/1/16/1f4e2.png\" style=\"height:16px; width:16px\" />&nbsp;16-17-18 სექტემბერი&nbsp;<img alt=\"📢\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t39/1/16/1f4e2.png\" style=\"height:16px; width:16px\" /></p>\r\n\r\n<p><img alt=\"🫵\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tc8/1/16/1faf5.png\" style=\"height:16px; width:16px\" />&nbsp;მოდი ჭიათურის ტურისტულ ფესტივალზე და მოიწყვე დაუვიწყარი თავგადასავალი</p>\r\n\r\n<p><img alt=\"🚀\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tc6/1/16/1f680.png\" style=\"height:16px; width:16px\" />&nbsp;აღმოაჩინე სხვა ჭიათურა:</p>\r\n\r\n<p><img alt=\"✔️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/2714.png\" style=\"height:16px; width:16px\" />&nbsp;ქემფინგი/ Camping;<br />\r\n<img alt=\"✔️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/2714.png\" style=\"height:16px; width:16px\" />&nbsp;კლდეზე ცოცვა (მოყვარული) / Rock Climbing (amateur);<br />\r\n<img alt=\"✔️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/2714.png\" style=\"height:16px; width:16px\" />&nbsp;კლდეზე ცოცვა (პროფესიონალი) / Rock Climbing (professional);<br />\r\n<img alt=\"✔️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/2714.png\" style=\"height:16px; width:16px\" />&nbsp;ჰაილაინი / Highline;<br />\r\n<img alt=\"✔️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/2714.png\" style=\"height:16px; width:16px\" />&nbsp;ნაოსნობა ტბაზე / Lake Boating;<br />\r\n<img alt=\"✔️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/2714.png\" style=\"height:16px; width:16px\" />&nbsp;სპელეოტურიზმი ძუძუანას და კოტიას მღვიმეში / Speleotourism in Dzudzuana and Kotika caves;<br />\r\n<img alt=\"✔️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/2714.png\" style=\"height:16px; width:16px\" />ველოშეჯიბრი მანდაეთში/Cycling competition in Mandaeti.</p>\r\n\r\n<p>ფესტივალის განრიგი :</p>\r\n\r\n<p>16 სექტემბერი</p>\r\n\r\n<p><img alt=\"📍\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t2d/1/16/1f4cd.png\" style=\"height:16px; width:16px\" />&nbsp;ჭიათურა</p>\r\n\r\n<p><img alt=\"🕚\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t59/1/16/1f55a.png\" style=\"height:16px; width:16px\" />&nbsp;11:00 - პრეზენტაცია და პანელ - დისკუსია, ჭიათურის კულტურის სახლში.</p>\r\n\r\n<p><img alt=\"🕛\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tda/1/16/1f55b.png\" style=\"height:16px; width:16px\" />&nbsp;12:00 - ტური &ldquo;ჯორჯიან მანგანეზის&rdquo; ტურისტულ პროექტში (საბაგირო, კორტი და სხვა).</p>\r\n\r\n<p><img alt=\"🕘\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tb0/1/16/1f558.png\" style=\"height:16px; width:16px\" />&nbsp;21:00 - გალა კონცერტი Loud Speakers</p>\r\n\r\n<p><img alt=\"📍\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t2d/1/16/1f4cd.png\" style=\"height:16px; width:16px\" />&nbsp;კაცხი</p>\r\n\r\n<p><img alt=\"🕛\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tda/1/16/1f55b.png\" style=\"height:16px; width:16px\" />&nbsp;12:00 - 13:00 რეგისტრაცია კლდეზე ცოცვის შეჯიბრში (მოყვარულები)</p>\r\n\r\n<p><img alt=\"🕐\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/ta8/1/16/1f550.png\" style=\"height:16px; width:16px\" />&nbsp;13:00 - 18:00 შეჯიბრი</p>\r\n\r\n<p><img alt=\"📍\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t2d/1/16/1f4cd.png\" style=\"height:16px; width:16px\" />&nbsp;სვერი</p>\r\n\r\n<p><img alt=\"🕛\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tda/1/16/1f55b.png\" style=\"height:16px; width:16px\" />&nbsp;12:00 - 13:00 რეგისტრაცია კლდეზე ცოცვის შეჯიბრში (პროფესიონალები)</p>\r\n\r\n<p><img alt=\"🕐\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/ta8/1/16/1f550.png\" style=\"height:16px; width:16px\" />&nbsp;13:00 - 18:00 შეჯიბრი</p>\r\n\r\n<p><img alt=\"🕛\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tda/1/16/1f55b.png\" style=\"height:16px; width:16px\" />&nbsp;12:00 - 18:00 ჰაილაინის შოუ</p>\r\n\r\n<p><img alt=\"🕚\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t59/1/16/1f55a.png\" style=\"height:16px; width:16px\" />&nbsp;11:00 - 17:00 ვია ფერატა ინფო ტური (​​მონაწილეები დაიყოფიან ოთხ ჯგუფად)</p>\r\n\r\n<p><img alt=\"👉\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;17 სექტემბერი</p>\r\n\r\n<p><img alt=\"📍\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t2d/1/16/1f4cd.png\" style=\"height:16px; width:16px\" />&nbsp;სვერი</p>\r\n\r\n<p><img alt=\"🕛\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tda/1/16/1f55b.png\" style=\"height:16px; width:16px\" />&nbsp;12:00 - 13:00 რეგისტრაცია კლდეზე ცოცვის შეჯიბრში (პროფესიონალები)</p>\r\n\r\n<p><img alt=\"🕐\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/ta8/1/16/1f550.png\" style=\"height:16px; width:16px\" />&nbsp;13:00 - 18:00 შეჯიბრი</p>\r\n\r\n<p><img alt=\"📍\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t2d/1/16/1f4cd.png\" style=\"height:16px; width:16px\" />&nbsp;ძუძუანას და კოტიას მღვიმე</p>\r\n\r\n<p><img alt=\"🕘\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tb0/1/16/1f558.png\" style=\"height:16px; width:16px\" />&nbsp;09:00 - 10:00 რეგისტრაცია ლაშქრობაში (მონაწილეები დაიყოფიან სამ ჯგუფად)</p>\r\n\r\n<p><img alt=\"📍\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t2d/1/16/1f4cd.png\" style=\"height:16px; width:16px\" />&nbsp;კოტიას მღვიმე</p>\r\n\r\n<p><img alt=\"🕘\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tb0/1/16/1f558.png\" style=\"height:16px; width:16px\" />&nbsp;21:00 - სპექტაკლი &ldquo;დოვინ დოვენ დოვლი&rdquo;</p>\r\n\r\n<p><img alt=\"👉\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;18 სექტემბერი</p>\r\n\r\n<p><img alt=\"📍\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t2d/1/16/1f4cd.png\" style=\"height:16px; width:16px\" />&nbsp;მანდაეთის ტბა</p>\r\n\r\n<p><img alt=\"🕙\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t31/1/16/1f559.png\" style=\"height:16px; width:16px\" />&nbsp;10:00 ველო შეჯიბრი</p>\r\n\r\n<p><img alt=\"🕛\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tda/1/16/1f55b.png\" style=\"height:16px; width:16px\" />&nbsp;12:00 - 18:00 ნავებით შეჯიბრი ტბაზე</p>\r\n\r\n<p><img alt=\"📍\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t2d/1/16/1f4cd.png\" style=\"height:16px; width:16px\" />&nbsp;ჭიათურის ცენტრი</p>\r\n\r\n<p><img alt=\"🕘\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tb0/1/16/1f558.png\" style=\"height:16px; width:16px\" />&nbsp;21:00 - გალა კონცერტი Tamada</p>\r\n\r\n<p><img alt=\"🏕\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tdc/1/16/1f3d5.png\" style=\"height:16px; width:16px\" />16 სექტემბერს 10:00 საათზე გაიხსნება ქემფინგ ზონა ჩამოსული სტუმრებისთვის, რომელიც იფუნქციონირებს 18 სექტემბრის ჩათვლით.</p>\r\n\r\n<p><img alt=\"🎶\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t1f/1/16/1f3b6.png\" style=\"height:16px; width:16px\" />&nbsp;TAMADA და Loudspeakers</p>\r\n\r\n<p><img alt=\"🥪\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tfc/1/16/1f96a.png\" style=\"height:16px; width:16px\" /><img alt=\"🥤\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t4f/1/16/1f964.png\" style=\"height:16px; width:16px\" />&nbsp;სთრით ფუდი და გამაგრილებელი სასმელები</p>\r\n\r\n<p><img alt=\"💥\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t40/1/16/1f4a5.png\" style=\"height:16px; width:16px\" />&nbsp;ჭიათურაში ამაღელვებელი, მომნუსხველი, გემრიელი და მისტიკით სავსე 3 დღე გელოდება.</p>\r\n\r\n<p><img alt=\"✔️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/2714.png\" style=\"height:16px; width:16px\" />&nbsp;ჭიათურის ტურისტული ფესტივალის გენერალური სპონსორია &quot;ჯორჯიან მანგანეზი&quot;</p>\r\n\r\n<p><img alt=\"🤝\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t64/1/16/1f91d.png\" style=\"height:16px; width:16px\" />პარტნიორები: ჭიათურის მუნიციპალიტეტის მერია, სვერის სათავგადასავლო ბანაკი და DMO იმერეთი.</p>\r\n\r\n<p><img alt=\"🔗\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tb3/1/16/1f517.png\" style=\"height:16px; width:16px\" />&nbsp;მხარდამჭერები: ტურიზმის ეროვნული ადმინისტრაცია.&nbsp;</p>\r\n', NULL, NULL, NULL, NULL, 'guga - ', NULL, NULL, NULL, NULL),
(40, 'ka', 'ახალი საცოცი სექტორი ანანურთან', '<p>.</p>\n', '<p>გუგა დაბრუნდაშვილმა და სოფო ცელიძემ ანანურთან 3 ახალი მარშრუტი გააკეთეს. ახლა რეგიონში მხოლოდ 3 მარშრუტი, მაგრამ შესაძლებელია მეტი მარშრუტის დამატება.</p>\n\n<p>დამატებითი ინფორმაციისთვის სექტორის მდებარეობისა და მარშრუტების შესახებ იხილეთ ამ - <a href=\"https://climbing.ge/outdoor/Climbing_near_Ananuri\">გვერდზე</a>.</p>\n', NULL, NULL, NULL, NULL, '<p>Guga: Mail - gugadabrunda@gmail.com,&nbsp;Tel: (+995) 557 300 700.</p>\n', NULL, NULL, '2022-09-05 16:06:23', '2023-05-19 21:49:38'),
(41, 'ka', 'ახალი საცოცი მარშრუტები გველეთში', '<p>.</p>', '<p>გუგა დაბრუნდაშვილმა გველეთში ახალი სპორტული ცოცვის მარშრუტები გააკეთა.</p>\n\n<p>იხილეთ მეტი ინფორმაცია კლდეების შესახებ ამ - <a href=\"https://climbing.ge/outdoor/Climbing_in_Gveleti\">გვერდზე</a>.</p>', NULL, NULL, NULL, NULL, '<p>Guga: Mail - gugadabrunda@gmail.com,&nbsp;Tel: (+995) 557 300 700.</p>', NULL, NULL, '2022-09-05 16:16:02', '2022-09-05 16:23:23'),
(42, 'ka', 'ახალი საცოცი საქტორი და 5 ახალი საცოცი მარშრუტი ბორჯომთან, სოფელ მზეთამზესთან.', '<p>.</p>', '<p>თემო სამსონაძემ სოფელ მზეთამზეში, ბორჯომთან ახლოს, ახალი სექტორი&nbsp;და 5 ახალი სპორტული ცოცვის მარშრუტი გააკრა.</p>\n\n<p>დამატებითი ინფორმაცია ამ ტერიტორიის შესახებ იხილეთ ამ - <a href=\"https://climbing.ge/outdoor/Climbing_near_Borjomi\">გვერდზე</a>.</p>', NULL, NULL, NULL, NULL, '<p>Temo - Tel - (+995) 598457048. Email - samsonadze.temo9@gmail.com</p>', NULL, NULL, '2022-09-05 16:24:07', '2022-09-05 16:36:05'),
(43, 'ka', 'ახალი საცოცი მარშრუტევი ციხისძირში ხღვის ნაპირას', '<p>.</p>', '<p>თემო სამსონაძემ ციხისძირში ზღვის ნაპირას ახალ სექტორში 3 ახალი მარშრუტი გააკეთა.</p>\n\n<p>მეტი ინფორმაცია იხილეთ ამ - <a href=\"https://climbing.ge/outdoor/Climbing_At_The_Black_Sea_Coast\">გვერდზე</a>.</p>', NULL, NULL, NULL, NULL, '<p>Temo - Tel - (+995) 598457048. Email - samsonadze.temo9@gmail.com</p>', NULL, NULL, '2022-09-05 16:36:13', '2022-09-05 16:49:52'),
(44, 'ka', 'ქართველმა მთამსვლელებმა ოქროს წერაყინით დააჯილდოვეს', '<p>ქართველი მთამსვლელები ოქროს წერიყინით&nbsp;დააჯილდოვეს პაკისტანში, პაკისტანში&nbsp;მწვერვალ სარაგრზე&nbsp;ასვლისთვის პირველი ასვლისთვის.</p>\n', '<p>სარაგრარის ჩრდილო-დასავლეთი, პირველი ასვლა ჩრდილო-დასავლეთით, 2,300 მ,</p>\n\n<p>ED2 ან რუსული/კავკასიური შეფასება 6B, 6b M5+ A3+ 80-90&deg;,</p>\n\n<p>2021 წლის 3-10 სექტემბრიდან.</p>\n\n<p>სარაგრარის მასივს, ავღანეთის საზღვრის სამხრეთით, დღევანდელ&nbsp;პაკისტანის &quot;ჰინდუ კუში&quot; - ს&nbsp;აქვს რამდენიმე მწვერვალი, მაგრამ მხოლოდ რამდენიმე მთამსვლელმა მიაღწია მათ. დღემდე მხოლოდ სარაგრარის ჩრდილო-დასავლეთი კედელზე არც ერთი წარმატებული ასვლა არ ყოფილა (7,300 მ),&nbsp;მიუხედავად ხანგრძლივი და გამბედავი მცდელობებისა სამხრეთ-დასავლეთის კედელზე სამი ძლიერი ესპანური ექსპედიციის მიერ 1970-იან და 80-იანი წლების დასაწყისში. მათგან უკანასკნელი ჩრდილო-დასავლეთის ქედზე დაახლოებით 7150 მეტრზე ავიდა.&nbsp;ამ ადგილს,&nbsp;მათ დაარქვეს სარაგრარი ჩრდილო-დასავლეთი II. ქართველმა ალპინისტებმა&nbsp;არჩილ ბადრიაშვილმა, ბაქარ გელაშვილმა და გიორგი ტეფნაძემ აირჩიეს მანამდე აუსვლელი ჩრდილო-დასავლეთი კედელი.&nbsp;საკვანძოა ამ კედლის&nbsp;ზედა ციცაბო ნაწილი, რომელიც ერწყმის ჩრდილო-დასავლეთ ქედს. მათ&nbsp;გადაწყვიტეს მცდელობა გაეკეთებინათ სექტემბერში, იმაზე უფრო გვიან, ვიდრე ჩვეულებრივ.&nbsp;დღის სიცხის შესამცირებლად და&nbsp;შესაბამისად, ქვათაცვენმის შესამცირებლად.</p>\n\n<p>საბაზო ბანაკიდან დაახლოებით 4200 მეტრზე - &quot;როშ გოლში&quot; და მცირე წინასწარი აკლიმატიზაციის პირობებში სამივე &bdquo;გახურდა&ldquo; სამხრეთის და აღმოსავლეთის ქედის პირველი აღმართით (1800 მ, TD 60&deg;-ყინული 75&deg;- თოვლი) ლანგუტა-ე-ბარფის (6,833 მ), ერთი ბივუაკით 6,400 მ. ეს იყო მწვერვალზე მეოთხე ასვლა, მაგრამ პირველი პაკისტანიდან.</p>\n\n<p>3 სექტემბერს, ალპინისტებმა დაიწყეს ასვლა - სარაგრარის&nbsp;ჩრდილო-დასავლეთის კედელზე. დაახლოებით&nbsp;5000 მეტრზე,&nbsp;განაგრძეს მარშრუტი ყინულის უზარმაზარი კულუარით, რომელიც ახასიათებს ქვედა ნახევარს, რათა გაეკეთებინათ პირველი ბივუაკი 6200 მეტრზე. ზემო ნაწილის უმეტესობას შეადგენდა ციცაბო გრანიტის კედელი. რთული მონაკვეთის თავისუფალი და დამხმარე საყრდენებით ცოცვით&nbsp;გადალახვის შემდენ,&nbsp; მათ ჰქონდათ რამდენიმე ღამის თენება კედელზე: 6400 მეტრზე, 6600 მეტრზე, 6.750 მეტრზე, 6.850 მეტრზე და დაახლოებით 7000 მეტრზე კედლის თავზე. მეხუთე და მეექვსე დღეები დაეთმო 250 მეტრიანი &quot;ჰედვოლის&quot; გადალახვას.</p>\n\n<p>ბოლო ბივუაკი გააკეთეს&nbsp;ესპანეთის მარშრუტის გასასვლელთან და მერვე დღეს ავიდნენ&nbsp;მწვერვალზე. მათ იმავე დღეს შეძლეს დიდი კედლის თავზე&nbsp;მდებარე ბივუაკში&nbsp;დაბრუნება და მეორე დილით დაიწყეს ჩრდილო-დასავლეთის მხარეს დაშვება, რომელიც გაგრძელდა მთელი ღამის განმავლობაში, სანამ არ მიაღწიეს მარშრუტის სათავეს.</p>\n\n<p>Info from -&nbsp;<a href=\"https://pioletsdor.net/index.php/en/home/2022-honoured-ascents/141-saraghrar-northwest-7-300m?mibextid=Zxz2cZ\" target=\"_blank\">pioletsdor.net</a></p>\n', NULL, NULL, NULL, NULL, '<div data-oembed-url=\"https://www.instagram.com/p/ClLYMMXo6HS/?utm_source=ig_web_copy_link\">\n<div style=\"max-width: 660px;\">\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 63%; padding-top: 284px;\"><iframe allowfullscreen=\"\" src=\"//if-cdn.com/QN2CKdu?app=1\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n<script async=\"\" charset=\"utf-8\" src=\"//if-cdn.com/embed.js\"></script></div>\n\n<p>&nbsp;</p>\n', NULL, NULL, '2022-11-20 10:22:07', '2023-08-02 16:20:31'),
(101, 'ru', 'Скалолазание в Свери (Чиатура)', '<p>Зона для скалолазания Свери расположена в небольшой причудливой деревне в районе Имерети на западе Грузии.<br />\nСкалолазание - относительное занятие в этой области.</p>\n', '<p>Зона для скалолазания Свери расположена в небольшой причудливой деревне в районе Имерети на западе Грузии.<br />\nСкалолазание - относительное занятие в этой области. Большинство маршрутов проложены совсем недавно, а все маршруты были открыты в 2018 году.</p>\n\n<p>ПОХОД</p>\n\n<p>Остановиться можно в палатках возле альпинистской зоны.<br />\nСтавить палатки прямо под камнями не рекомендуется из-за риска.<br />\nкамнепада, а также его небольшая площадь под линиями для установки палатки</p>\n\n<p><br />\nЗАПАСЫ ЕДЫ</p>\n\n<p>Продовольственные магазины можно сделать в городе Чиатура.<br />\nЗдесь есть большой местный фермерский рынок и множество магазинов и множество пекарен, предлагающих свежий хлеб, выпекаемый ежедневно.<br />\nК сожалению, в Свери нет продуктового рынка, поэтому вы должны<br />\nВозьмите с собой все свои принадлежности перед тем, как отправиться в зону восхождения.<br />\nВ качестве источника воды рядом с местом для скалолазания есть несколько источников, или вы можете<br />\nТакже попросите воды у дружелюбных местных жителей.<br />\nВесной дикие фрукты можно найти в случайных местах, или можно спросить дружелюбных местных жителей, не хотите ли вы сорвать фрукты.</p>\n\n<p>ДЕНЬ ОТДЫХА</p>\n\n<p>В Свери есть несколько старых замков и монастырей, а также много хороших мест для посещения.<br />\nТакже город Чиатура - еще одно отличное место для изучения с его длинными<br />\nистория добычи полезных ископаемых, пронизанная множеством пещер.<br />\nЕсть также водопады, в которых можно купаться в жаркие летние дни.<br />\nБольшинство местных жителей очень дружелюбны, как и во всей Грузии.</p>\n', '<p>К зоне скалолазания относительно легко добраться.<br />\nСкалы в Свери обращены на север. Отсутствие прямого солнечного света в течение дня приводит к тому, что на северных склонах прохладнее.<br />\nБольшинство маршрутов большую часть дня находятся в тени, что делает Свери, а идеальным для лазания являются жаркие летние дни.<br />\nБольшинство маршрутов имеют длину 10-25 метров с отметками от 5A до 7C.<br />\nЭтот район по-прежнему имеет большой потенциал и открыт для новых заведений.<br />\nЕсли вы решите открыть и закрепить новые стропы или вам понадобится гид по скалолазанию, пожалуйста, свяжитесь с нашим местным пионером скалолазания Гуга Дабрунда.</p>\n\n<p>Высота линий от 10м до 25м. Оценки от 5а до 7с Оценка Франции.</p>\n', '<p>Поселок Свери находится недалеко от ближайшего крупного города Чиатура в 170 км от Тбилиси.<br />\nДоехать до Свери можно на маршрутке Маршрутка на станции Дидубе в Тбилиси до города Чиатура. Из Чиатуры вы можете сесть на маршрутку или такси до города Свери, который находится дальше 11 км.<br />\nОт автобусной остановки в деревне Свери до места для скалолазания около 400 метров.<br />\nРайон не обозначен полностью, но совершенно очевидно, что можно найти место для лазания, следя за скалами.<br />\nВ конце села указатель &laquo;Зона скалолазания&raquo;, а оттуда еще метров 50 до скал.<br />\nВы также можете спросить у местных, как добраться до скал &laquo;клдекари&raquo;.</p>\n', '<p>За исключением зимы, альпинизм в Свери идеален с весны до осени. Северные скалы обеспечивают прохладу даже в жаркие летние дни.<br />\nСредняя температура по Цельсию весной: Высокая 24 &deg; / Низкая 11 &deg;.<br />\nЛетом высокая 30 &deg; / низкая 18 &deg; и осень высокая 20 &deg; / 8 &deg;</p>\n', '', '<p>Guga - Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p>Temo - Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 11:04:04', '2023-10-12 01:34:28'),
(106, 'ru', 'Скалолазание в Кацхи (Чиатура)', '<p>Кацхи - одно из самых популярных и лучших мест для восхождения в Грузии. Качество скалы идеально подходит для разных вершин лазания.</p>\n', '<p>Кацхи - одно из самых популярных и лучших мест в Грузии. Качество скалы отличное для разных видов лазания. Есть как отрицательные маршруты, так и прямые плитки, что позволяет спортсмену максимально развиваться и прочувствовать все стили лазания.</p>\n', '<p>Маршруты классифицируются по французской системе. С 5а по 8б.</p>\n\n<p><strong>Используйте шлем для вашей безопасности!</strong></p>\n\n<p><strong>напивание маршрутов в регионе, ​​категорически запрещено!</strong><br />\nЕсли вы планируете набивать маршруты в этом регионе, сообщите о своих планах местным скалолазам, в противном случае ваши маршруты могут быть разобраны.</p>\n\n<p><strong>Восхождение с драитулингам также запрещено!</strong></p>\n', '<p>Кацхи находится примерно в 180 км от столицы Тбилиси. На машине вам понадобится примерно 2 часа.</p>\n\n<p>от аэропорта Кутаиси 1 час</p>\n', '<p>Кацхи находится на высоте 700 м над уровнем моря. Лучшее время для восхождения с сентября по июль. Август - жаркое время для восхождений, но в тени или пасмурную погоду тоже приятно лазить. Есть солнечные и постоянно тенистые места для лазания.</p>\n\n<p>некоторые трассы покрыты сверху большими деревьями, а некоторые выступают над ними, так что по ним можно подняться даже в дождливую погоду.</p>\n', '<p>&nbsp;</p>\n\n<ol>\n	<li>12 оттяжка</li>\n	<li>Веревка 60 м</li>\n	<li>Обвязка</li>\n	<li>Страховочное устройство</li>\n	<li>Шлем</li>\n	<li>Обувь и сумка для мела</li>\n</ol>\n', '<p>Guga - Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p>Temo - Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 17:31:38', '2023-06-29 21:34:55'),
(107, 'ru', 'Скалолазание на Монументе Лоткина', '<p>Добро пожаловать к монумент Лоткину. Это 40-метровая бетонная конструкция.</p>\n', '<p>Добро пожаловать к монумент Лоткину.</p>\n\n<p>Это 40-метровая бетонная конструкция. Здание находится на окраине города, и попасть в суд не составит труда. Проект только начался, но после его завершения можно будет пройти 2-х канатный мульти-питч. Также можно лазить по нитке.</p>\n', '<p>На сегодняшний день существует 6 трасс для спортивного скалолазания и 1 трасса для скалолазания.</p>\n\n<p>Самая высокая из 2-х линий - 40 м, 1-я линия - 30 м и 3 линии - 20 м. класс 5с / 7а</p>\n\n<p>В середине 40-метровых линий - верхние цепи.</p>\n', '<p>Из метро &laquo;<a href=\"https://goo.gl/maps/Rjou6mefmr52\">Привокзальная площадь</a>&raquo; к верхнему выходу курсируют автобусы №110, №111, №48 (<a href=\"http://goo.gl/maps/EG9Emms68YN5yGvC7\">stop 1</a>) и №36 (<a href=\"https://goo.gl/maps/2XZPEGVgAEP7QezZ8\">stop 2</a>) до (<a href=\"https://www.google.com/maps/d/u/0/viewer?mid=1Nzu-J7c65ivpXrma5iAdWye1a7nhYslt&amp;ll=41.72681806910237%2C44.81414870000003&amp;z=15\">см. Карту</a>)</p>\n', '<p>Подниматься сюда можно круглый год, в зависимости от погоды.</p>\n', '<ol>\n	<li>20 оттяжек</li>\n	<li>(мин.) 40 м - (макс.) Веревка 80 м</li>\n	<li>Обвязка</li>\n	<li>Страховочное устройство</li>\n	<li>Шлем</li>\n	<li>Обувь и сумка для мела</li>\n</ol>\n', '<p><strong>Guga</strong> - Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p><strong>Temo </strong>- Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 17:36:24', '2023-06-29 21:33:42'),
(108, 'ru', 'Скалолазание в Чиатуре', '<p>Чиатура - одно из самых перспективных мест для скалолазания в Грузии.</p>\n', '<p>Чиатура - одно из самых перспективных мест для скалолазания в Грузии. На этой скале в 70-х и 80-х годах проходили чемпионаты Советского Союза.</p>\n', '<p>Эта область находится в стадии разработки. Маршруты бывают разной классификации от 5а до 7а. Есть только одна линейка 8а сорт. И еще 3 мульти-питча.</p>\n\n<p><strong>Для вашей безопасности используйте халмет!</strong></p>\n\n<p><strong>Площадка не свободна для крепления !!!</strong><br />\nВ случае, если вы планируете приехать на болтовню в Грузию, сообщите о своих планах местному сообществу.</p>\n\n<p>Любая строка, которая не соответствует нашим стандартам, будет удалена.</p>\n', '<p>Чиатура находится в 180 км от столицы Тбилиси. На машине вам понадобится примерно 2 часа.</p>\n\n<p>Остановиться в городе можно в общежитии или на альпинистской базе, расположенной в 9 км от центра в селе Кацхи.</p>\n', '<p>Зависит от погоды.</p>\n', '<ol>\n	<li>20 оттяжка</li>\n	<li>веревка 60 м</li>\n	<li>обвязка</li>\n	<li>Страховочное устройство</li>\n	<li>Шлем (используйте шлем для вашей безопасности!)</li>\n	<li>Обувь и сумка для мела</li>\n</ol>\n', '<p>Guga - Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p>Temo - Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 17:38:50', '2023-06-29 21:31:57'),
(109, 'ru', 'Скалолазание в Местии (Чалаади)', '<p>.</p>\n', '<p>Сванетия&nbsp;&mdash; одно из самых красивых мест в Грузии.</p>\n\n<p>Есть много видов активного спорта и исторических и красивых мест для посещения.</p>\n\n<p>Местия &mdash; центр Сванетии, расположенный на высоте 1500 м над уровнем моря и в 460 км в 8 часах езды от Тбилиси.</p>\n', '<h2><strong>в регионе набивка трасс запришина!!!</strong></h2>\n\n<p>в случае если вы хотите сделать свой маршрут\\трассу свяжитесь&nbsp;с местными спортсменами. в противном случае ваша трасса может быть демантирывана.</p>\n\n<p><strong>драйтулинг в региони также запрещено!!!</strong></p>\n\n<p><strong>Используйте шлем для вашей безопасности!</strong></p>\n', '', '<p>Лучшее время для восхождений конец лета начало осени. Район скалолазания легко добраться автостопом, он находится в 10 км от центра города.</p>\n', '<ol>\n	<li>14 оттяжка</li>\n	<li>веревка 70 м</li>\n	<li>обвязка</li>\n	<li>Страховочное устройство</li>\n	<li>Шлем (используйте шлем для вашей безопасности!)</li>\n	<li>Обувь и сумка для мела</li>\n</ol>\n', '<p>Guga - <strong>Mail</strong>: gugadabrunda@gmail.com &nbsp; &nbsp;<strong>Tel</strong>: (+995) 557 300 700</p>\n\n<p>Temo - <strong>Mail</strong>: samsonadze.temo9@gmail.com&nbsp;</p>\n', NULL, NULL, '2021-03-02 17:41:37', '2023-06-29 21:31:00'),
(110, 'ru', 'Скалолазание в Дзеври', '<p>.</p>\n', '<p>Трассы для скалолазания проходят очень близко к дороге, и большинство из них имеют комфортную стартовую площадку.</p>\n\n<p>Можно разбить лагерь в районе скалолазания.</p>\n\n<p>Рядом со скалами есть ресторан и рынок.</p>\n\n<p>Местные жители очень дружелюбны к сообществу альпинистов.</p>\n\n<p>Скала имеет различную экспозицию и даже в жару на солнце можно найти тенистое место для подъема.</p>\n', '<h2><strong>в регионе набивка трасс запришина!!!</strong></h2>\n\n<p>в случае если вы хотите сделать свой маршрут\\трассу свяжитесь&nbsp;с местными спортсменами. в противном случае ваша трасса может быть демантирывана.</p>\n\n<p><strong>драйтулинг в региони также запрещено!!!</strong></p>\n', '<p>Расстояние от Тбилиси 200 км 3 часа езды.</p>\n\n<p>Расстояние от кутаисского аэропорта &laquo;Копитнари&raquo; 60 км, 1 час езды. (Показать карту)</p>\n', '<p>Лучший сезон для восхождений начало лета и осень, но при хорошей погоде можно лазить в течение всего года.</p>\n', '<ol>\n	<li>14 оттяжка</li>\n	<li>веревка 60 м</li>\n	<li>обвязка</li>\n	<li>Страховочное устройство</li>\n	<li>Шлем (используйте шлем для вашей безопасности!)</li>\n	<li>Обувь и сумка для мела</li>\n</ol>\n', '<p>Guga - <strong>Mail</strong>: gugadabrunda@gmail.com &nbsp; &nbsp;<strong>Tel</strong>: (+995) 557 300 700</p>\n\n<p>Temo - <strong>Mail</strong>: samsonadze.temo9@gmail.com&nbsp;</p>\n', NULL, NULL, '2021-03-02 17:44:09', '2023-06-29 21:29:17'),
(111, 'ru', 'Скалолазание в Кутаиси(Чома)', '<p>В Кутаиси нет множества скалолазных трасс, но для приятного времяпровождения вполне достаточно. Сложность трасс колеблется от 5А до 7А , что идеально для начинающих скалолазов.</p>\n', '<p>Кутаиси второй по величине город в Грузии. Население --147&nbsp;635 человек.</p>\n\n<p>Кутаиси расположен на расстоянии 235 км. от Тбилиси. Высота над уровнем моря 125-300 метров. В городе нет множества скалолазных трасс, но для приятного времяпровождения вполне достаточно. Сложность трасс колеблется от 5А до 7А , что идеально для начинающих скалолазов.</p>\n', '', '<p>В Кутаиси можно легко доехать из любого города Грузии. Сюда едет муниципальный транспорт из всех городов Грузии. В случае путешествия на собственном автомобиле используйте GPS навигатор. Также в 5ти километрах от города находится аэропорт. Полёты осуществляются как внутри страны так и за рубеж.</p>\n\n<p>Для похода по скальным маршрутам воспользуйтесь картой.</p>\n\n<p>Заночевать можно в одной из гостинец в Кутаиси или в палатке непосредственно возле скал.</p>\n\n<p>&nbsp;</p>\n', '<p>Лучшее время для скалолазания здесь &ndash; весна и осень. Летом здесь очень жарко, а зимой холодно. Но в тёплые зимние дни возможно тренироваться.</p>\n', '<p>12 оттяжка<br />\nВеревка 60 м<br />\nОбвязка<br />\nСтраховочное устройство<br />\nШлем<br />\nОбувь и сумка для мела</p>\n', '<p>Guga - <strong>Mail</strong>: gugadabrunda@gmail.com &nbsp; &nbsp;<strong>Tel</strong>: (+995) 557 300 700</p>\n\n<p>Temo - <strong>Mail</strong>: samsonadze.temo9@gmail.com&nbsp;</p>\n', NULL, NULL, '2021-03-02 17:46:18', '2023-05-24 07:42:59'),
(112, 'ru', 'Скалолазание в Арша', '<p>Казбеги (Степанцминда), расположенный на севере и 1750 над уровнем моря, является одним из самых популярных и туристических мест в Грузии.</p>\n', '<p>Арша расположен на севере Грузии , от конца деревни Степанцминда в 5ти километрах и от Тбилиси в 160 ти километрах. Высота над уровнем моря 1500 метров, население 700 человек.</p>\n\n<p>Среди любителей экстримального туризма регион Степанцминда очень популярен. Здесь можно заняться как скалолазанием так и трекингом , велотуризмом, джомардингом, альпинизмом, полетать на параплане и многое другое. Любителям альпинизма советуем также посетить Казбегский и Чаухский районы. Также в 6ти километрах находится другой скалолазный массив &ndash; Цдо ,который также интересен для альпинистов.</p>\n\n<p>Сложность маршрутов в регионе колеблется от 5А до 7В ,поэтому это отличное место для начинающих спортсменов и любителей. Также возможно мультипическо лазание.</p>\n\n<p><br />\nРасстояние от Казбеги: 3 км. К региону недавно приехали, здесь 30 спортивных трасс. Возможны традиционные и многоступенчатые лазания. Высота стены: 120 м, ширина: 250 м.</p>\n', '<p>&nbsp;</p>\n\n<h2><strong>в регионе набивка трасс запришина!!!</strong></h2>\n\n<p>в случае если вы хотите сделать свой маршрут\\трассу свяжитесь&nbsp;с местными спортсменами. в противном случае ваша трасса может быть демантирывана.</p>\n\n<p><strong>драйтулинг в региони также запрещено!!!</strong></p>\n\n<p><strong>используете краску для вашей безопасности!!!</strong></p>\n', '<p>Для приезда в Аршу необходимо от Казбега доехать до Степанцминда муниципальным транспортом и отсюда пешком пройти 1,5 километра. Можно в Казбеги арендовать такси.</p>\n\n<p>В случае поездки на своём автомобиле &ndash; машина должна быть 4х4 (смотрите карту).</p>\n\n<p>В Степанцминда и в Арше множество гостиниц ,в которых можно остановиться на ночлег (цены от 30 лари). В Арше так же есть место для кемпинга ,в 10 -15 минутах ходьбы от скал.</p>\n', '<p>Так как этот скальный сектор расположен в высокогорном регионе ,тренировки здесь возможны в конце весны , летом и в начале осени. Зимой из за низкой температуры воздуха и частых снегопадов тренировки невозможны. Зимой советуем потренироваться на Гвелетском замёрзшем водопаде.</p>\n', '<p>Вам понадобится</p>\n\n<ol>\n	<li>\n	<p>20 оттяжка</p>\n	</li>\n	<li>\n	<p>веревка 60 м</p>\n	</li>\n	<li>\n	<p>обвязка</p>\n	</li>\n	<li>\n	<p>Страховочное устройство</p>\n	</li>\n	<li>\n	<p>Шлем (используйте шлем для вашей безопасности!)</p>\n	</li>\n	<li>\n	<p>Обувь и сумка для мела</p>\n	</li>\n</ol>\n', '<p>Guga - Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p>Temo - Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 17:51:02', '2023-06-29 21:26:09'),
(113, 'ru', 'Скалолазание на Черноморском побережье', '<p>Если вы хотите заняться скалолазанием на берегу моря, побережье Черного моря предлагает некоторые возможности для этого.</p>\n', '<p>Если вы хотите заняться скалолазанием на берегу моря, побережье Черного моря предлагает некоторые возможности для этого.</p>\n', '<p>На некоторых маршрутах есть новые болты, в то время как большинство было прикручено довольно давно. Поэтому лучше лезть по канату. В остальном качество камня достойное. Сложность маршрутов варьируется от 5А до 7A.</p>\n', '<p>Расстояние от столицы Тбилиси до Сарпи (прямо у турецкой границы) - 380 км. Как вариант, вы можете прилететь в аэропорт Батуми. Скалы для скалолазания находятся в 10 км отсюда, до них легко добраться на маршрутке.</p>\n\n<p>Где остановиться<br />\nВы можете остановиться в частных домах или в отелях в Сарпи, Гонио или Квариати (все они рядом). Цены начинаются от 25-30 лари (около 10-15 евро) и растут в зависимости от сезона.</p>\n', '<p>У вас есть возможность лазать как на солнце, так и в тени, хотя в летний сезон следует учитывать жару. Лучшее время<br />\nзаниматься альпинизмом май, июнь, сентябрь и октябрь.</p>\n', '<ol>\n	<li>20 оттяжка</li>\n	<li>веревка 60 м</li>\n	<li>обвязка</li>\n	<li>Страховочное устройство</li>\n	<li>Шлем (используйте шлем для вашей безопасности!)</li>\n	<li>Обувь и сумка для мела</li>\n</ol>\n', '<p><strong>Guga </strong>- Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p><strong>Temo </strong>- Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 17:53:23', '2023-06-29 21:25:16'),
(114, 'ru', 'скалолазание в биртвиском канёне', '<p>Биртвийский каньон расположен в 40 км.&nbsp;от Тбилиси.&nbsp;На скалолазном участке трассы в основном болдеринговые маршруты , но есть и спортивные трассы.</p>\n', '<p>Биртвийский каньон расположен в 40 километрах от Тбилиси . высота над уровнем моря&nbsp;1077 метров. Здесь вы сможете заняться скалолазанием ,трекинингом, каньёнингом. На скалолазном участке трассы в основном болдеринговые маршруты , но есть и спортивные трассы.</p>\n', '<p>Сложность маршрутов колеблется&nbsp;от&nbsp;5А до 7С,&nbsp;болдеринг&nbsp;V1 - V7,&nbsp;&nbsp;поэтому тренировки для любителей и начинающих спортсменов идеальны</p>\n\n<h2><strong>в регионе набивка трасс запришина!!!</strong></h2>\n\n<p>в случае если вы хотите сделать свой маршрут\\трассу свяжитесь&nbsp;с местными спортсменами. в противном случае ваша трасса может быть демантирывана.</p>\n\n<p><strong>драйтулинг в региони также запрещено!!!</strong></p>\n\n<p><strong>используете краску для вашей безопасности!!!</strong></p>\n', '<p>Дорога до скального сектора и каньона начинается от деревни Тбиси , здесь вам придётся оставить машину и пройти пешком 45 &ndash; 60 минут по лесной зоне ( см. карту ) Необходимо иметь машину 4х4. Ночёвка возможна здесь только в палатках. Место для палаток в середине скального участка и легко и быстро (5минут) можно добраться до маршрута . Воду можно набирать выше кемпинга по дороге протекает река .</p>\n', '<p>Наилучшее время для посещения Биртвийского каньона - весна и осень .В летнее время в каньоне очень жарко. А зимой достаточно холодно . но бывают и тёплые зимние дни . когда возможна тренировка</p>\n', '<p>Для спортивного скалолазания вам понадобятся:</p>\n\n<ol>\n	<li>Веревка 50 м</li>\n	<li>10 Экспресс</li>\n	<li>Страховочная устройство и&nbsp;обвязка</li>\n	<li>шлем</li>\n</ol>\n\n<p>Для боулдеринга вам понадобится &quot;крэшпад&quot;&nbsp; (<a href=\"https://images.app.goo.gl/X598rhKxzugftkZA8\">crash bad</a>)</p>\n', '<p>Guga: <strong>Tel</strong>. (+995)&nbsp;557 300 700 <strong>Mail</strong>.&nbsp;gugadabrunda@gmail.com</p>\n\n<p>Temo: <strong>Mail</strong>. samsonadze.temo9@gmail.com</p>\n', NULL, NULL, '2021-03-02 17:55:39', '2023-06-29 21:24:04');
INSERT INTO `locale_articles` (`id`, `locale`, `title`, `short_description`, `text`, `route`, `how_get`, `best_time`, `what_need`, `info`, `price_text`, `address`, `created_at`, `updated_at`) VALUES
(115, 'ru', 'Скалолазание в \"Тбилисском ботаническом саду\"', '<p>Грузинские альпинисты всех десятилетий занимались альпинизмом в Ботаническом саду - одном из лучших мест для скалолазания в Тбилиси.</p>\n', '<p>Ботанический сад прекрасное место для отдыха и хорошего времяпровождения. Основан в 1845 году и занимает площадь 126 гектаров. Ботанический сад расположен в исторической части города Тбилиси южнее хребта Сололаки , в долине реки Легвта - Хеви , из -за перепадов высоты по ходу русла реки можно полюбоваться водопадами.</p>\n\n<p>На территории ботанического сада имеется скалодром. Этот участок для скальных тренировок имеет свою историю. Грузинские спортсмены , прошлого века с 70х годов и до сегодняшнего дня тренируются здесь. Место прекрасное для тех кто никогда не тренировался на природных скалах.</p>\n', '<p>Помимо верхних веревочных маршрутов, маршрут № 9, 10, 13, 14, 15 и 22 закреплены болтами. № 1 и 2 - это проекты, которые еще предстоит закрепить. Маршруты боулдеринга не обозначены на скалах, но легко узнаваемы, их можно увидеть на фотографиях здесь.</p>\n\n<p>У вас также есть возможность пройти 80-метровый траверс через все скалы Ботанического сада.</p>\n', '<p>На скалодром можно обраться двумя путями.</p>\n\n<p>Первый : через главный вход ботанического сада войти может каждый желающий. Учтите , что вход платный.</p>\n\n<p>Второй : возле крепости Нарикала есть вход. Этим входом пользуются только работники ботанического сада и грузинские спортсмены &ndash; альпинисты, которые постоянно здесь тренируются и об этих людях у охраны есть сведения</p>\n', '<p>В ботаническом саду тренироваться можно в любое время года. В летнее время лучше всего тренироваться когда солнце не освещает скалы ( после 17.00). Зимой же наоборот - . в утренние часы до 15.00 , когда солнце согревает скалы и приятно лазать по маршрутам.</p>\n', '<p>вам понадобятся:</p>\n\n<ol>\n	<li>Веревка 50 м</li>\n	<li>10 Экспресс</li>\n	<li>Страховочная устройство и обвязка</li>\n	<li>шлем</li>\n</ol>\n', '<p>Guga - <strong>Mail</strong>: gugadabrunda@gmail.com &nbsp; &nbsp;<strong>Tel</strong>: (+995) 557 300 700</p>\n\n<p>Temo - <strong>Mail</strong>: samsonadze.temo9@gmail.com</p>\n', NULL, NULL, '2021-03-02 18:29:06', '2023-06-29 21:22:40'),
(116, 'ru', 'Скалолазание в Навардзети (чиатура)', '<p>Поселок &laquo;Навардзети&raquo; находится в 4,5 км от Чиатуры в направлении большого альпинистского района &laquo;каччи&raquo;.</p>\n', '<p>Поселок &laquo;Навардзети&raquo; находится в 4,5 км от Чиатуры в направлении большого альпинистского района &laquo;каччи&raquo;.</p>\n\n<p>Линии для скалолазания новые, регион находится в стадии разработки, поэтому на сегодняшний день у нас есть только 7 маршрутов, но вскоре наш клуб &laquo;Клуб грузинских альпинистов&raquo; планирует закрепить все возможные веревки в районе.</p>\n\n<p>Высота скалы 30/40 м, но максимальная высота линий 30 м.</p>\n\n<p>Оценка от главной дороги пешком около 200 м.</p>\n\n<p>На главной дороге возле площадки для скалолазания можно набрать родниковую воду.</p>\n\n<p>Вы можете использовать кемпинг альпинистов в качи, чтобы остаться во время путешествия.</p>\n', '<p>Площадка не свободна для крепления !!!<br />\nВ случае, если вы планируете приехать на болтовню в Грузию, сообщите о своих планах местному сообществу.</p>\n\n<p>Любая строка, не соответствующая нашим стандартам, будет удалена.</p>\n\n<p>На территории разрешено восхождение по традиции. В зоне для скалолазания запрещен сухой толлинг.</p>\n\n<p>кемпинг под веревками запрещен !!!!!!!</p>\n\n<p>для вашей безопасности всегда используйте шлем !!!!!!!!!</p>\n', '<p>Из Чиатуры в Навардзет ходит маршрутка. Также можно воспользоваться маршруткой до Кацхи и сойти возле села Навардзети.</p>\n', '<p>Большой плюс местности в том, что после 15:00 скала находится в тени, поэтому летом можно лазить в тени.</p>\n', '<ol>\n	<li>20 оттяжка</li>\n	<li>веревка 60 м</li>\n	<li>обвязка</li>\n	<li>Страховочное устройство</li>\n	<li>Шлем (используйте шлем для вашей безопасности!)</li>\n	<li>Обувь и сумка для мела</li>\n</ol>\n', '<p>Guga - Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p>Temo - Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 18:31:44', '2023-06-29 21:20:22'),
(117, 'ru', 'Скалолазание в Цдо', '<p>Цдо - небольшая деревня недалеко от Казбеги, красивое место. Это прекрасное место для занятий спортом и лазанием по многим веревкам.</p>\n', '<p>Горный туризм является основным направлением в Казбеги (вершина 5047 м), однако создание соответствующей инфраструктуры для восхождений продолжается. Деревня Цдо находится от казбека примерно в 7 км.</p>\n', '<p>Мы постоянно добавляем новые маршруты в этот регион. Маршруты варьируются от 5А до 8А. Также у нас есть 3, 2 веревочные маршруты (мультиплеер).</p>\n\n<p>В целях безопасности используйте долото!</p>\n\n<p>Совершать маршруты (саботаж) в районе Сацоц без местных слесарей категорически запрещено!<br />\nЕсли вы планируете делать матрас в Чиатуре, обязательно сообщите об этом местным пекарям. В противном случае ваш маршрут может быть разобран.</p>\n\n<p>Скалолазание &quot;Drytooling&quot; в регионе категорически запрещено!</p>\n', '', '<p>Июнь-октябрь, но при хорошей погоде можно подняться даже зимой.</p>\n', '<ol>\n	<li>20 оттяжка</li>\n	<li>веревка 60 м</li>\n	<li>обвязка</li>\n	<li>Страховочное устройство</li>\n	<li>Шлем (используйте шлем для вашей безопасности!)</li>\n	<li>Обувь и сумка для мела</li>\n</ol>\n', '<p>Guga - Mail: gugadabrunda@gmail.com &nbsp; &nbsp;Tel: (+995) 557 300 700</p>\n\n<p>Temo - Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 18:36:35', '2023-06-29 20:22:28'),
(118, 'ru', 'Скалолазание в лагере Чаухи', '<p>Помимо альпийского стиля, вы можете пройти спортивный маршрут на базовый лагерь Чаухи.</p>\n', '<p>Горы Чаухи - место в провинции Хевсурети. Ближайшая деревня - Джута. Скалистые горы построены из зеленых альпийских холмов. Альпинистские навыки очень близки к базовому лагерю. Здесь у очень маленьких массивных альпинистов есть всевозможные маршруты, которые интересны как новичкам, так и профессионалам. (информацию о альпинизме <a href=\"http://climbing.ge/mountaineering\">смотрите здесь</a>).</p>\n\n<p>В дополнение к альпийскому стилю, вы можете отправиться в поход по спортивной тропе в Bace Camp.</p>\n', '<p>Здесь небольшой маршрут (максимум 15 м), 3 трассы с болтовым креплением и канатная дорога. В основном этот маршрут предназначен для тренировок по восхождению в альпийском стиле, но он хорош для лазания с отдыхом на 3-4 часа. Район подходит для начинающих альпинистов.</p>\n', '<p>Маршрут Эври, ведущий к массиву Пик Каухи, начинается с одного лагеря (ЛАГЕРЬ 1). Маршрут по горному массиву Чаухи начинается в поселке Джута (2100 м). Пройдя деревню и доберитесь до кладбища Зета. в лагере можно принять душ, поесть и переночевать. От лагеря ехать по реке Каухи, трасса обозначена хорошо. Пройдя через покрытые травой плато и склоны, вы выйдете на высокое плато (cemp-1 2250м), на краю которого стоят три копания (10м). На dhese bolders есть колья и есть возможность заняться скалолазанием. Это плато отлично подходит для кемпинга.</p>\n', '<p>Лучшее время для восхождения на чаухи - с середины июля до середины сентября.</p>\n', '<p>Для скалолазания на базовый лагерь чаухи вам понадобятся:</p>\n\n<ol>\n	<li>6 оттяжка</li>\n	<li>Веревка 40 м</li>\n	<li>Обвязка</li>\n	<li>Страховочное устройство</li>\n	<li>Шлем (используйте шлем для вашей безопасности)</li>\n	<li>Обувь и сумка для мела</li>\n</ol>\n', '<p>For more information about climbing area contact me.</p>\n\n<p>Temo - Mail: samsonadze.temo9@gmail.com&nbsp; &nbsp; Tel; (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 18:39:32', '2023-06-29 20:21:05'),
(119, 'ru', 'Bouldering Club Tbilisi', '<p>Зал болдеринга на Вере при Федерации альпинизма.</p>\n', '<p>Верийский боулдеринговый зал находится под эгидой федерации альпинизма, это небольшой зал для болдеринга. Высота стены&nbsp;4,5 метра .Здесь множество стен с разнообразными рельефами, много различных маршрутов и приятная дружеская обстановка, которая даст вам стимул для тренировок и совершенствования техники скалолазания.</p>\n\n<p>В зале нет аренды инвентаря для тренировок и поэтому необходимо иметь с собой своё снаряжение.</p>\n', NULL, '<p>Зал расположен в здании дворца шахмат, на первом этаже. Вход с задней( парковочной )стороны. Адрес : г.Тбилиси улица Мераба Костава 37-А</p>\n', NULL, '', '<p>Oto -&nbsp;(+995)&nbsp;514 51 11 77</p>\n\n<p>Temo - (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-02 18:49:57', '2023-06-29 20:08:51'),
(120, 'ru', 'S.K.Lucky', '<p>Зал для тренировок по лазанию S.K.LUCKU. &ndash; один из лучших залов в Грузии. Здесь вы можете заняться как болдерингом так и маршрутами</p>\n', '<p>Зал для тренировок по лазанию S.K.LUCKU. &ndash; один из лучших залов в Грузии. Здесь вы можете заняться как болдерингом так и маршрутами. Высота стен для спортивного лазания 12 метров, для болдеринга 4 метра. В зале вас встретят инструкторы и помогут вам выбрать маршрут в зависимости от сложности и вашего опыта и обеспечат страховку в случае если вы пришли один и нет у вас партнёра.</p>\n\n<p>В зале есть всё необходимое снаряжение и оборудование для того , что бы вы комфортно себя чувствовали и насладились процессом тренировки. Учтите , что аренда снаряжения платная</p>\n', NULL, '<p>Зал находится по адресу: Тбилиси улица университетская 6 ,спорт комплекс Арена 2, второй этаж.</p>\n\n<p>Сюда можно добраться как городским транспортом так и на личном автомобиле или такси( смотрите карту).</p>\n', NULL, '', '<p>&nbsp;</p>\n\n<p>Tel: (+995) 574 80 95 02</p>\n', NULL, NULL, '2021-03-02 18:52:39', '2023-06-29 20:07:53'),
(121, 'ru', '.', '<p>..</p>\n', '<p>.</p>\n', NULL, '', NULL, '', '', NULL, NULL, '2021-03-02 18:54:34', '2023-11-20 01:09:22'),
(122, 'ru', 'Ледолазание в Гвелети', '<p>Ледолазание в Гвелети - одно из лучших мест для этого занятия.</p>\n', '<p>Ледолазание в Гвелети - одно из лучших мест для этого занятия. лазание на территории с использованием традиционных и сухих инструментов разрешено.</p>\n', '', '<p>Из Тбилиси вам нужно ехать до казбека &laquo;степанцминда&raquo; 160 км, а затем ехать в направлении владикавказ 9 км от казбека и повернуть налево, пока вы пересекаете мост в гвелети. Затем идите прямо к ледопаду. время прогулки 20/30 минут в зависимости от состояния снега.</p>\n', '<p>Лучшее время для восхождения - январь, февраль и начало марта в холодную погоду.</p>\n', '<ol>\n	<li>Веревка 60 м (2 шт.) Или 120 м (1 шт.)</li>\n	<li>Ледоруб</li>\n	<li>Кошки</li>\n	<li>Страховочное устройство</li>\n	<li>Карабины (4-5 шт.)</li>\n	<li>Обвязка</li>\n	<li>Шлем</li>\n</ol>\n\n<p>Для лазания</p>\n\n<ol>\n	<li>7-8 Ледобур и Quickdraw</li>\n</ol>\n', '<p><strong>Guga -</strong>&nbsp;Mail: gugadabrunda@gmail.com&nbsp; &nbsp; Tel: (+995) 557 300 700.</p>\n\n<p><strong>Temo</strong>&nbsp;- Mail; samsonadze.temo9@gmail.com&nbsp; &nbsp; &nbsp;Tel: (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-19 20:23:10', '2023-08-05 10:49:59'),
(123, 'ru', 'Ледолазание в долине Атени', '<p>Ледолазание - довольно устоявшаяся спортивная дисциплина в Грузии. Одно из лучших мест для занятий спортом - в долине Атени недалеко от деревни Бийс.</p>\n', '<p>Ледолазание - довольно устоявшаяся спортивная дисциплина в Грузии. Одно из лучших мест для занятий спортом - в долине Атени недалеко от деревни Бийс.</p>\n', '', '<p>От Тбилиси до Бийса потребуется около 1,5 часов, расстояние 130 км. Следуя по главному автомобильному маршруту, вы поворачиваете налево и въезжаете в деревню. Рекомендуется передвигаться на автомобиле 4 &times; 4, так как в этом случае вы сможете проехать еще 300 метров в деревню, не оставляя машину припаркованной на главной дороге из-за плохих уличных условий.</p>\n\n<p>Припарковав машину, вам нужно пройти 20 минут вверх по реке, пока не дойдете до замерзшего водопада высотой 60 метров и шириной 5-15 метров.</p>\n\n<p>Ближайшие города: 41 &deg; 51&#39;4 &quot;N 43 &deg; 59&#39;6&quot; E ►</p>\n\n<p>Где остановиться<br />\nМесто у подножия ледопада вполне подходит для кемпинга, но учтите, что ночью очень холодно!</p>\n', '<p>В зависимости от температуры года февраль - лучшее время для ледолазания.</p>\n', '<ol>\n	<li>Веревка 60 м (2 шт.) Или 120 м (1 шт.)</li>\n	<li>Ледоруб</li>\n	<li>Кошки</li>\n	<li>Страховочное устройство</li>\n	<li>Карабины (4-5 шт.)</li>\n	<li>Обвязка</li>\n	<li>Шлем</li>\n</ol>\n\n<p>Для лазания</p>\n\n<ol>\n	<li>7-8 Ледобур и Quickdraw</li>\n</ol>\n', '<p><strong>Guga -</strong>&nbsp;Mail: gugadabrunda@gmail.com&nbsp; &nbsp; Tel: (+995) 557 300 700.</p>\n\n<p><strong>Temo</strong>&nbsp;- Mail; samsonadze.temo9@gmail.com&nbsp; &nbsp; &nbsp;Tel: (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-19 20:47:03', '2023-08-05 10:50:48'),
(124, 'ru', 'Слэклайн в Грузии', '<p>В Грузии слэклайн - это не развитая дисциплина, но она развивается.</p>\n', '<p>Slacklining - это ходьба или балансировка по подвешенной длине плоской лямки, натянутой между двумя анкерами. Слаклайнинг похож на хождение по слабой веревке и хождение по канату. Слаклайны отличаются от канатов и канатов типом используемого материала и величиной натяжения, прилагаемого во время использования. Стропы стропы натянуты значительно меньше, чем канаты или канаты, чтобы создать динамичную стропу, которая будет растягиваться и подпрыгивать, как длинный и узкий батут. Натяжение можно регулировать в соответствии с потребностями пользователя, и в различных обстоятельствах могут использоваться различные ремни. Slacklining популярен благодаря своей простоте и универсальности; его можно использовать в различных средах с небольшим количеством компонентов.</p>\n\n<p>Slacline в Грузии - В Грузии Slackline - это не развитая дисциплина, но она развивается. По всей Грузии уже есть несколько высокогорных регионов (самый популярный из них - &laquo;9 джвари&raquo; в Раче). На сайте slacklinegeorgia.wordpress.com вы можете найти подробную информацию по всем регионам Грузии.</p>\n\n<p>Как найти нас?<br />\nВ Тбилиси мы чаще всего собираемся в &laquo;парке Ваке&raquo;, &laquo;Тбилисском ботаническом саду&raquo; (в районе скалолазания) и на &laquo;озере Лиси&raquo;. Мы информируем друг друга о месте встречи на странице факсбука &laquo;Слеклайн Грузия&raquo;.</p>\n\n<p>В Батуми мы чаще всего собираемся в &laquo;Парке 6 мая&raquo; и возле &laquo;Tema Caffe Bar&raquo;. Мы информируем друг друга о месте встречи на странице факсбука &laquo;Sleckline Batumi&raquo;.</p>\n\n<p>В Кутаиси мы чаще всего собираемся в &laquo;Чома&raquo; (в районе скалолазания). Вы можете связаться с местными парнями Темо Кутдиани на facebook.</p>\n\n<p>Информация:<br />\nСтраница Facebook: Slackline georgia</p>\n\n<p>Тбилиси -&gt; Почта: Iraklisixarulidze@gmail.com; Facebook: пыльные сапоги.</p>\n\n<p>Батуми -&gt; Facebook: Ирекле Чикваидзе.</p>\n\n<p>Кутаиси -&gt; Facebook: Темо Кутдиани.</p>\n', NULL, NULL, NULL, NULL, '<p><strong>Guga -</strong>&nbsp;Mail: gugadabrunda@gmail.com&nbsp; &nbsp; Tel: (+995) 557 300 700.</p>\n\n<p><strong>Temo</strong>&nbsp;- Mail; samsonadze.temo9@gmail.com&nbsp; &nbsp; &nbsp;Tel: (+995) 598 45 70 48</p>\n', NULL, NULL, '2021-03-19 21:01:44', '2024-04-15 20:34:50'),
(125, 'ru', 'Джавахишвили класика (3A)', '<p>AD, M1, 300M, 5A (3A - RUS)</p>\n', '<p>Для восхождения требуется всего три веревки и по сложности маршрут не превосходит 5А</p>\n\n<p>В0 &ndash; маршрут начинается с кулуара Леонидзе-Джавахишвили, оттуда поднимаемся до седловины ,где находится большой камень. Слева от камня видим собранную станцию.</p>\n\n<p>Р1-от станции возможны&nbsp;два варианта подъема Первый- от станции слева ,по камину ,придерживаясь правой стороны -выходим на полку. Второй- над станцией есть трещина, лезть по правой стороне трещины и&nbsp;выходим на полку.</p>\n\n<p>Р2- от станции идем направо по наклонной расщелине и выйдем на тонкую, с положительным уклоном скалу. На стене можно найти, продолжаем лезть и находим станцию, собранную на трех элементах.</p>\n\n<p>Р3- от станции продолжаем подъем и выходим на полку где находим станцию на валуне. От станции налево идем по тропинке ,которая выводит нас на вершину Джавахишвили. Классический маршрут Джавахишвили ,самый простой путь на вершину этой горы.</p>\n\n<p>&nbsp;</p>\n\n<p>Маршрут достаточно прост ,поэтому подойдет для начинающих альпинистов. Для тех кто только начинает восхождения в горах.</p>\n\n<p>От первого лагеря до основания кулуара требуется 2-2,5 часа времени. От второго лагеря 0,45-1,5 часа.</p>\n\n<p>&nbsp;</p>\n\n<p><strong>Среднее время от кулуара до вершины всего 4-5 часов.</strong></p>\n', '', NULL, '<p>Лучшее время для&nbsp;маршрута&nbsp;- лето. В это время выпадает меньше всего осадков, а температура самая высокая (от 12 до 0 градусов), но на маршрут&nbsp;можно выходить&nbsp;и зимой. Примечание: зимой в кулуаре&nbsp;намного больше снега и часты лавины. Диапазон температур от -15 до -25 градусов.</p>', '<p>На маршруте&nbsp;вам понадобятся:</p>\n\n<ol>\n	<li>Веревка 50 м</li>\n	<li>Закладка 4-5&nbsp;(средних размеров)</li>\n	<li>Камелоты 3-4 (средних размеров)</li>\n	<li>Оттяжки 4-5</li>\n	<li>Карабин 3-4с и самостраховка</li>\n	<li>Спусковое - страховачная устроиство</li>\n	<li>Обвязка и шлем</li>\n	<li>Кошки и ледоруб (в зависимости от количества снега в кулуаре)</li>\n</ol>\n\n<p>Зимой вам понадобится дополнительное снарежение</p>\n\n<ol>\n	<li>Снегастапы</li>\n	<li>Ледобуры 2-3 части</li>\n</ol>\n', '<p>Темо - samsonadze.temo9@gmail.com</p>\n', NULL, NULL, '2021-10-03 07:01:13', '2023-07-28 02:13:47'),
(126, 'ru', 'Скалолазание в муниципалитете Боржоми', '<p>Боржоми находится в Восточной Грузии, здесь можно заняться скалолазанием, а также различными видами активного отдыха.</p>\n', '<p>Боржоми находится в Восточной Грузии, З.Д. 900 м. Население ~ 10 000 человек. Муниципалитет Боржоми очень популярен среди любителей приключенческого туризма. Здесь можно заняться скалолазанием, а также различными видами деятельности: треккингом, велотуром, рафтингом и прочим.</p>\n\n<p>В 10 км от Боржоми находится поселок в поселке Тимотесубани. История области восходит к 80-м годам прошлого века, но в последние 20-25 лет никакой деятельности в области не велось. Зимой 2021 года началась реабилитация района. Изначально был пройден только 1 сектор и 8 маршрутов, но уже к лету 2022 года планируется сделать больше маршрутов.</p>\n', '<p>Зимой 2021 года началась реабилитация района. Изначально был пройден только 1 сектор и 8 маршрутов, но уже к лету 2022 года планируется сделать больше маршрутов.</p>\n\n<p>Камень - базальт</p>\n\n<h2><strong>в регионе набивка трасс запришина!!!</strong></h2>\n\n<p>в случае если вы хотите сделать свой маршрут\\трассу свяжитесь&nbsp;с местными спортсменами. в противном случае ваша трасса может быть демантирывана.</p>\n\n<p><strong>драйтулинг в региони также запрещено!!!</strong></p>\n\n<p><strong>Используйте шлем для вашей безопасности!!!</strong></p>\n', '<p>Едем из Боржоми в Бакуриани, через 9 км встретим село Цахвери. С центральной площади Цахвери поворачиваем налево и идем 700-1000 м в район села Тимоте. Справа встретим источник (и отметку источника). У истока находим мост через реку переходим мост и встречаем скалу. Здесь можно поставить машину. Подробности смотрите на карте.</p>\n', '<p>Лучшее время для лазания в регионе: поздний газ, лето до середины осени. Днем скала в основном находится в тени, поэтому днем ​​в основном холодно. Мы рекомендуем вам проверить погоду до прибытия в регион.</p>\n', '<ol>\n	<li>14 Экспресс</li>\n	<li>Веревка 60 м</li>\n	<li>Защитный пояс</li>\n	<li>Система защиты</li>\n	<li>шлем</li>\n	<li>Скутеры и помидоры Магнезия</li>\n</ol>\n', '<p>Temo - Tel - (+995) 598457048.&nbsp;Email - samsonadze.temo9@gmail.com</p>\n', NULL, NULL, '2021-11-21 18:30:47', '2023-06-29 20:10:57'),
(127, 'ru', 'Новые скалолазные сектора в Боржоми', '<p>Муниципалитет Боржоми - один из самых популярных у туристов и любителей активного отдыха. Недавно здесь был добавлен новый скалолазныей сектор.</p>', '<p>Боржоми находится в 150 км от Тбилиси. Муниципалитет Боржоми - один из самых популярных у туристов и любителей активного отдыха. Здесь можно посетить национальный парк Боржоми-Харагаули, где можно заняться трекингом, а также посетить серные бани и заняться рафтингом.</p>\n\n<p>В 20 км от Боржоми находится село Цеми, где находится одно из старейших скалолазныей сектор&nbsp;Грузии. Соревнования&nbsp;проводились еще в 80-х годах 20 века. Тем не менее, последние 20 лет регион был полностью забыт, и спортивные мероприятия здесь не проводились. Инфраструктуры в секторе не было, поэтому лазить сюда было невозможно.</p>\n\n<p>В ноябре 2021 года начались работы по обновлению сектора. На первом этапе было проложено всего 3 маршрута, но в ближайшее время работы будут продолжены и здесь будет проложено еще больше маршрутов движения.</p>\n\n<p><a href=\"https://climbing.ge/outdoor/climbing_near_borjomi\">Перейдите по ссылке, чтобы увидеть подробное описание региона.</a></p>', NULL, NULL, NULL, NULL, '<p><strong>Temo -</strong>&nbsp;&nbsp;<strong>Tel:</strong> (+995) 598 45 70 48. <strong>Mail:</strong> samsonadze.temo9@gmail.com</p>', NULL, NULL, '2021-11-23 17:24:11', '2021-11-23 18:28:29'),
(128, 'ru', 'Скалодром в Степанцминде (Казбеги)', '<p>.</p>', '<p>.</p>', NULL, NULL, NULL, NULL, '<p>.</p>', NULL, NULL, '2022-05-05 18:52:52', '2022-05-05 18:59:15'),
(129, 'ru', '\"Илиаун\"', '<p>.</p>\n', '<p>Маршрут начинается слева от кулуара Леонидзе - Джавахишвили. Поднимаемся по крутому склону к низу стены, находим трещину с левой стороны. Отсюда начинается маршрут.</p>\n\n<p>P1 - начинаем лезть в широкую щель (для защиты использовать крупногабаритные вставные элементы), проходим по узкому таро и делаем защиту на хим.</p>\n\n<p>От станции Р2 продолжаем подъем вправо. Проходим через 4-5 метровую стену к большому таро, идем направо и делаем станцию ​​на Химе, у подножия большой трубы.</p>\n\n<p>P3 - Начинаем лезть в камин, на правой и левой стенке камина много щелей, чтобы сделать защиту. Над камином потолок, образованный падением больших камней. С левой стороны находим узкий проход и идем к полке. Рядом с заправкой есть химическая станция.</p>\n\n<p>P3- P4- идем одновременно налево от станции, следуем по полке, взбираемся на простую стену высотой 5м и находим основание большой стены на существующем таро.</p>\n\n<p>P4- идём по канавке посередине большой стены (самая большая канавка), идём по канавке, с правой стороны находим полку и на 4м выше полки находим 2 палоса на которых ставим станцию.</p>\n\n<p>P5 &mdash; Продолжаем карабкаться по канавке, пока не приходим к зеленой стене с разбитой, разбитой скалой.</p>\n\n<p>На стене много узких канавок. Продолжаем карабкаться по середине стены и находим узкую полку, где делаем станцию ​​(выше этого делать станцию ​​не рекомендуется).</p>\n\n<p>P6 &mdash; Продолжаем подниматься прямо, пока не доберемся до большой полки под большим камином. Делаем станцию ​​у подножия камина.</p>\n\n<p>P7- Мы продолжаем подниматься по большому дымоходу, пока не пройдем еще одно большое таро. Отсюда мы начинаем идти одновременно.</p>\n\n<p>ВЕРХ - с полки продолжаем подъем одновременно, по легкому рельефу. Идем к подножию пика. Проходим пику по небольшой полке с западной стороны (идем налево) и находим камин. Как только выходим из камина, оказываемся наверху.</p>\n\n<p>Среднее время от начала маршрута до вершины 4-6 часов.</p>\n', '', NULL, '<p>Лучшее время для&nbsp;маршрута&nbsp;- лето. В это время выпадает меньше всего осадков, а температура самая высокая (от 12 до 0 градусов), но на маршрут&nbsp;можно выходить&nbsp;и зимой. Примечание: зимой в кулуаре&nbsp;намного больше снега и часты лавины. Диапазон температур от -15 до -25 градусов.</p>', '<p>На маршруте&nbsp;вам понадобятся:</p>\n\n<ol>\n	<li>Веревка 50 м</li>\n	<li>Закладка 4-5&nbsp;(средних размеров)</li>\n	<li>Камелоты 3-4 (средних размеров)</li>\n	<li>Оттяжки 4-5</li>\n	<li>Карабин 3-4с и самостраховка</li>\n	<li>Спусковое - страховачная устроиство</li>\n	<li>Обвязка и шлем</li>\n	<li>Кошки и ледоруб (в зависимости от количества снега в кулуаре)</li>\n</ol>\n\n<p>Зимой вам понадобится дополнительное снарежение</p>\n\n<ol>\n	<li>Снегастапы</li>\n	<li>Ледобуры 2-3 части</li>\n</ol>\n', '<p>Темо - samsonadze.temo9@gmail.com</p>\n', NULL, NULL, '2022-08-23 19:24:25', '2023-07-28 01:57:37'),
