(251, 'ka', 'კვანძები სპორტული ცოცვისთვის', '<p>.</p>\n', '<p>როგორ შევკრათ კვანძები? განმარტებითი დიაგრამები.</p>\n\n<div style=\"background:#eeeeee; border:1px solid #cccccc; padding:5px 10px\">\n<p><strong>ყურადღება</strong></p>\n\n<ul>\n	<li>ყურადღებით წაიკითხეთ გამოყენების ინსტრუქცია. აუცილებელია გაიაზროთ ყველა მოცემული მაგალითი.</li>\n	<li>ამ ტექნიკის დაუფლება მოითხოვს სპეციალურ მომზადებას. მიმართეთ რჩევისთვის პროფესიონალს, რათა დაადასტუროთ თქვენი უნარი.</li>\n	<li>ჩვენ გთავაზობთ ძირითადი ტექნიკის მაგალითებს. შეიძლება იყოს სხვებიც, რომლებსაც აქ არ აღვწერთ.</li>\n</ul>\n</div>\n\n<ul>\n</ul>\n\n<h3><strong>&quot;რვიანი&quot; კვანძი</strong></h3>\n\n<p>ერთი წვერით შეკვრა</p>\n\n<p><img alt=\"Figure eight knot for tying in\" src=\"https://www.petzl.com/sfc/servlet.shepherd/version/download/0681r0000071pqtAAA\" /></p>\n\n<p>2 წვერი წვერით შეკვრა</p>\n\n<p><img alt=\"Figure eight knot for the anchor\" src=\"https://www.petzl.com/sfc/servlet.shepherd/version/download/068w0000005t39sAAA\" style=\"width:60%\" /></p>\n\n<p>&nbsp;</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=GFlwrvggas0&amp;ab_channel=REI\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/ZF3uLTW\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<h3>&nbsp;</h3>\n\n<h3>&nbsp;</h3>\n\n<h3><strong>ორმაგი ბულინი</strong></h3>\n\n<p><img alt=\"steps showing how to tie double bowline\" src=\"https://cdn.climbing.com/wp-content/uploads/2022/02/double-bowline.jpg?width=730\" style=\"height:1040px; width:892px\" /></p>\n\n<p>&nbsp;</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=1uo_Ohq_gVg&amp;ab_channel=ClimbCulture\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/nOyLQbq\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n', '', '', '', '', '', NULL, NULL, '2023-04-13 18:45:38', '2024-04-08 20:06:18'),
