INSERT INTO `locale_articles` (`id`, `locale`, `title`, `short_description`, `text`, `route`, `how_get`, `best_time`, `what_need`, `info`, `price_text`, `address`, `created_at`, `updated_at`) VALUES
(305, 'ka', 'დრაითულინგი ლოტკინის მონუმენტზე', '<p>.</p>\n', '<p>კეთილი იყოს თქვენი მობრძანება ლოტკინის მონუმენტზე.</p>\n\n<p>ეს არის 40 მეტრიანი ბეტონის კონსტრუქცია. მონუმენტი მდებარეობს ქალაქის გარეუბანში და მაგრამ მასთან მისვლა არანაირ სირთულეს არ წარმოადგენს. მონუმენტი არის კარგი ადგილი საცოცად თბილისში. აქ გვაქვს 7 მარშრუტი 5B-7B. (იხილეთ მარშრუტების არჭერა)</p>\n', '<p><a href=\"https://climbing.ge/outdoor/Urban_Climbing_In_Tbilisi\">სპორტუი ცოცვის მარშრუტებისთვის ეწვიეთ გვერდს</a></p>\n', '<p>მონუმენტი მდებარეობს ქალაქის გარეუბანში და მაგრამ მასთან მისვლა არანაირ სირთულეს არ წარმოადგენს. მეტრო&nbsp;<a href=\"https://goo.gl/maps/Rjou6mefmr52\">&#39;სადგურის მოედნიდან</a>&#39; ზედა გასასვლელიდან მიდიან es110, №111, №48 (<a href=\"http://goo.gl/maps/EG9Emms68YN5yGvC7\">გაჩერება 1</a>) და №36 (<a href=\"https://goo.gl/maps/2XZPEGVgAEP7QezZ8\">გაჩერება 2</a>) ავტობუსებით (<a href=\"https://www.google.com/maps/d/u/0/viewer?mid=1Nzu-J7c65ivpXrma5iAdWye1a7nhYslt&amp;ll=41.72681806910237%2C44.81414870000003&amp;z=15\">იხილეთ რუკა</a>). თუ თქვენ პირადი მანქანით მიდიხართ მოგიწავთ მანქანის გაჩერება ქალაქის პარკინგზე. მონუმენტთან მისასვლე გზა გადაკეტილია!</p>\n', '', '<ol>\n	<li>20 ექსპრესი</li>\n	<li>(Min) 40m - (Max) 80m თოკი</li>\n	<li>დეაცვის ქამარი</li>\n	<li>დაცვის სისტემა</li>\n	<li>ჩაფხუტი</li>\n	<li>საცოცი ფეხსაცმელი(სკალნები) &amp; მაგნეზიის ტომარა</li>\n</ol>\n', '', NULL, NULL, '2023-05-29 18:14:23', '2023-11-18 00:50:23'),
(306, 'ru', '.', '<p>.</p>\n', '<p>.</p>\n', '', '', '', '', '', NULL, NULL, '2023-05-29 18:14:23', '2023-05-29 18:14:23'),
(307, 'us', 'Dry tooling on Lotkin monument', '<p>.</p>\n', '<p>Welcome to the Lotkin Monument, a 40-meter concrete structure located on the outskirts of Tbilisi. Accessing the court is easy, and there are no difficulties in reaching the location. Although the project is still in progress, once completed, it will be possible to climb two-rope multi-pitch routes. Additionally, you can also climb using threading techniques.</p>\n', '<p><a href=\"https://climbing.ge/outdoor/Urban_Climbing_In_Tbilisi\">For sport climbing routes visit this page</a></p>\n', '<p>From the&nbsp;<a href=\"https://goo.gl/maps/Rjou6mefmr52\">metro &#39;Station square&#39;</a>&nbsp; top exit rides&nbsp;buses&nbsp;№319</p>\n', '', '<ol>\n	<li>20 quickdraw</li>\n	<li>(Min) 40m - (Max) 80m roupe&nbsp;</li>\n	<li>Harnes&nbsp;</li>\n	<li>Belay device</li>\n	<li>Helmet (Use&nbsp;helmet for your safety !)</li>\n	<li>Shoes &amp;&nbsp;Chalk Bag</li>\n</ol>\n', '', NULL, NULL, '2023-05-29 18:14:23', '2023-11-18 00:50:23'),
(308, 'ka', 'ყინული და დრაითულინგი მცირე მიტარბის ჩანჩქერზე', '<p>.</p>\n', '<p><strong>პატარა მიტარბი</strong> &mdash; სოფელი ბორჯომის მუნიციპალიტეტში (ბაკურიანის თემში). მდებარეობს მდინარე მიტარბულას ნაპირებზე. ზღვის დონიდან 1300 მეტრი, ბორჯომიდან 30 კილომეტრში და თილისიდან 180. მოსახლეობა 50 ადამიანი. სოფელი მდებარეობს კლდეებით და არცთუისე მაღალი მთებით სავსე ულამაზეს ხოუბაში. ხეობის დასაწყისში გვხვდება ჩანჩქერი რომლის მიმდებარედ არის მოწყობილი საცოცი მარშრუტები.</p>\n', '<p>საცოცი მარშრუტები გათვლილია მხოლოდ &quot;Dry tooling&quot;-ის საცოცად&nbsp; (არა სპორტული ცოცვისთვის). ცოცვა მთელი წელი არის შესაძლებელი ზამთრის პერიოდში შესაძლებელია გაყინულ ჩანჩქერზე ცოცვაც (მინიმუმ 3 კვრა გადაბმულად 0-ზე დაბალი ტემპერატურისას). დრაი თულინგის ცოცვას შეძლებთ როგორც საცოცი წრიაპით ასევე უბრალო საცოცი ფეხსაცმლით (სკალნით).</p>\n', '<p>სოფელში მოსახვედრად ბორჯომიდან უნდა ვიმოძრაოთ ბაკურიანის მიმართულებით. დაბა წაღვერთან უნდა გადავუხვიოთ მიტარბის მიმართულებით. დიდი მიტარბიდან 15 კილომეტრში მივალთ მცირე მიტარბში. აუცილებელია 4X4 მანქანა, ზამთრის პერიოდში აუცილებელია ზამთრის საბურავები და მოცურების საწინააღმდეგო ჯაჭვები. იხილეთ რუკა.</p>\n', '<p>საუკეთესო პერიოდი როდესაც როგორც დრაითულინგის და ყინულზე ცოცვას შეძლებთ იანვრის დასაწყისიდან, მარტის დასაწყისამდეა. აუცილებლად იხილეთ ამინდები სექტორის სტუმრობამდე. დრაითულინგის ცოცვა მთელი წელია შესაძლებელი.</p>\n', '<p>დრაითულინგის საცოცდა აუცილებელია:</p>\n\n<ol>\n	<li>ექსპრესები 10ც</li>\n	<li>ჩაფხუტი</li>\n	<li>თოკი 50მ</li>\n	<li>დაცვის ქამარი</li>\n	<li>საცოცი წერაყინები (ice tools)</li>\n	<li>დაცვის სისტემა</li>\n</ol>\n\n<p>კინულზე საცოცად დამატებით აუცილებელია:</p>\n\n<ol>\n	<li>წრიაპი</li>\n	<li>ყინულის ბურები</li>\n</ol>\n', '', NULL, NULL, '2023-05-29 18:18:23', '2024-01-15 00:38:35'),
(309, 'ru', '.', '<p>.</p>\n', '<p>.</p>\n', '', '<p>.</p>\n', '', '', '', NULL, NULL, '2023-05-29 18:18:23', '2023-05-29 18:18:23'),
(310, 'us', 'Ice climbing & dry tooling in \"Patara Mitarbi\"', '<p>.</p>\n', '<p>.</p>\n', '', '<p>.</p>\n', '', '', '', NULL, NULL, '2023-05-29 18:18:23', '2024-01-15 00:34:03'),
(311, 'ka', 'Climbing Lizards', '<p>ცოცვის სკოლა ბავშვებისთვის</p>\n', '<p>&nbsp; &ldquo;Climbing Lizards&rdquo; აუტისტური სპექტრის და შეზღუდული შესაძლებლობის მქონე პირთა ცოცვა - სარეაბილიტაციო კლუბი, რომელიც მოიცავს კოგნიტური უნარების განვითარებას.</p>\n\n<p>&nbsp; კლუბის დამფუძნებელი ემილი სამსონიძე, ის პროფესიით ექიმია. წლებია აქტიურად არის დაკავებული მეკლდეურობით და ალპინიზმით. მისი კვლევების შედეგად, თუ რა შედეგებს იწვევს მეკლდეურობა ორგანიზმის და გონების განვითარებაში, სწორედ ეს გახდა მიზეზი კლუბის ჩამოყალიბების, რომელიც 2020 წელს დააფუძნა.</p>\n\n<p>&nbsp; მეკლდეურობა აჯანსაღებს ორგანიზმს, აძლევს სწორ მიმართულებას ძვლოვან სისტემას, ააქტიურებს მოტორულ ფუნქციებს და აქტიურს ხდის მას.</p>\n\n<p>&nbsp; &bdquo;Climbig Lizards&rdquo; - მისი დამფუძნებელი ემილი სამსონიძე 2023 წლის თებერვალში აღიარეს მსოფლიში პირველ ადამიანად, აუტისტური სპექტრის და შეზღუდული შესაძლებლობის მქონე პირთა პირველი კლუბის დაფუძნებაში.</p>\n', '', '', '', '', '<p>Tel: (+995) 599 133 397</p>\n\n<p><a href=\"https://www.facebook.com/ClimbingLizards\">Facebook</a></p>\n', NULL, NULL, '2023-07-19 14:31:32', '2023-07-19 15:24:13'),
(312, 'ru', '.', '<p>.</p>\n', '<p>.</p>\n', '', '', '', '', '', NULL, NULL, '2023-07-19 14:31:32', '2023-07-19 14:31:32'),
(313, 'us', 'Climbing Lizards X', '<p>Climbing school for kids</p>\n', '<p>&ldquo;Climbing Lizards&rdquo; &ndash; climbing and rehabilitation club for people with autistic spectrum and disabilities, that includes the development of cognitive skills.</p>\n\n<p>The founder of the club is Emily Samsonidze, she is a doctor by profession. She has been actively engaged in rock climbing and mountaineering for years. As a result of her research on the effects of rock climbing on the development of the body and mind, this was the reason for the formation of the club, which she founded in 2020.</p>\n\n<p>Rocking makes the body healthy, gives the right direction to the bone system, activates the motor functions and makes it active.</p>\n\n<p>&ldquo;Climbing Lizards&rdquo; &ndash; its founder Emily Samsonidze was recognized in February 2023 as the first person in the world to create the first club for people with autism and disabilities.</p>\n', '', '', '', '', '<p>Tel: (+995) 599 133 397</p>\n\n<p><a href=\"https://www.facebook.com/ClimbingLizards\">Facebook</a></p>\n', NULL, NULL, '2023-07-19 14:31:32', '2024-01-18 17:55:23'),
(314, 'ka', 'ახალი საცოცი მარშრუტები ჭაუხის საბაზო ბანაკში', '<p>5 ახალი საცოცი მარშრუტები ჭაუხის საბაზო ბანაკში</p>\n', '<p>ივლისის ბოლოს თემო სამსონაძემ ჭაუხის საბაზო ბანაკის სიახლოვეს, მიმდებარე ქვებზე 5 ახალი საცოცი მარშრუტი დაამატა. 4 მარშრუტი 6A/6B+ და ერთი საკმაოდ რთული დაახლოებით 9A-ს სირთულის მარშრუტი. პროექტი გახსნილია და მისი ცდა ნებისმიერ მსურველს შეუძლია.</p>\n\n<p>დამატებითი ინფორმაციისთვის<a href=\"https://climbing.ge/ka/outdoor/climbing_to_chaukhi_bace_camp\"> ეწვიეთ გვერდს</a></p>\n', '', '', '', '', '', NULL, NULL, '2023-09-02 00:23:37', '2023-09-02 00:33:28'),
(315, 'ru', '.', '<p>.</p>\n', '<p>.</p>\n', '', '', '', '', '', NULL, NULL, '2023-09-02 00:23:37', '2023-09-02 00:23:37'),
(316, 'us', 'New climbing routes in Chaukhi base camp', '<p>5 new climbing routes in Chaukhi base camp.</p>\n', '<p>At the end of July, Temo Samsonadze added 5 new sport climbing routes on the boulders near the Chaukhi base camp. 4 routes between 6A/6B+ and one fairly difficult route of about 9A. The project is open and anyone can try it.</p>\n\n<p>For more information, <a href=\"https://climbing.ge/outdoor/climbing_to_chaukhi_bace_camp\">visit the page</a></p>\n', '', '', '', '', '', NULL, NULL, '2023-09-02 00:23:37', '2023-09-02 00:33:28'),
(317, 'ka', 'ვია-ფერატა საქართველოში', '<p>.</p>\n', '<div data-oembed-url=\"https://www.google.com/maps/d/edit?mid=15P_pbT4bULInsAO7sf6qb-mXoAuvrcQ&amp;usp=sharing\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 75%;\"><iframe allowfullscreen=\"\" src=\"//if-cdn.com/DRYOe3Tm\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>სვერის &quot;ვია ფერატა&quot; არის პირველი ვია ფერატის პროექტი საქართველოსა და კავკასიის რეგიონში. მდებარეობს სოფელ სვერში, ბანაკიდან 700 მეტრში. ვია ფერატა არის მარშრუტი, რომელიც აღჭურვილია ფოლადის ტროშით და რკინის საფეხურებით 70 მეტრი სიმაღლით და 160 მეტრი სიგრძით სრული უსაფრთხოებით. ეს სათავგადასავლო ტური შესანიშნავია როგორც ერთი ადამიანი ასევე ოჯახის ან კორპორატიული ვიზიტორებისთვის. ორი მარშრუტი - მარტივი და საშუალო - შესანიშნავია როგორც დამწყებთათვის, ასევე გამოცდილი თავგადასავლების მოყვარულთათვის.</p>\n\n<p>ბილიკის ტექნიკური მახასიათებლები:</p>\n\n<p>&nbsp;&nbsp;&nbsp;&nbsp; მარშრუტის მანძილი &ndash; 230 მეტრი, 300 ნაბიჯი<br />\n&nbsp;&nbsp;&nbsp;&nbsp; მარშრუტის დრო &ndash; 70/90 წუთი<br />\n&nbsp;&nbsp;&nbsp;&nbsp; მარშრუტის სრული დრო &ndash; 2/2,5 საათი (თეორიული და პრაქტიკული სწავლება ბანაკში &ndash; 0,5 საათი, ფეხით ბანაკიდან &ndash; 15 წუთი, გავლის დრო &ndash; 70/90 წუთი, დაბრუნება &ndash; 15 წუთი)<br />\n&nbsp;&nbsp;&nbsp;&nbsp; ჯგუფში ვიზიტორების მაქსიმალური და მინიმალური რაოდენობა &ndash; 10/3<br />\n&nbsp;&nbsp;&nbsp;&nbsp; გიდი &ndash; ორი ინსტრუქტორი<br />\n&nbsp;&nbsp;&nbsp;&nbsp; მისასვლელი საცალფეხო და უკანა დამაკავშირებელი ბილიკის სიგრძე &ndash; 600 მეტრი<br />\n&nbsp;&nbsp;&nbsp;&nbsp; მარშრუტების რაოდენობა &ndash; 2, მარტივი და რთული</p>\n\n<p><strong>ფასის:</strong></p>\n\n<p>სვერის ვია ფერატის სტუმრობა შეაძლებელია მხოლოდ ჩვენ გიდებთან ერთად!</p>\n\n<p>ერთ ადამიანზე &ndash; 35 ევრო</p>\n\n<p>ფასში შედის:</p>\n\n<p>ჩაფხუტი, აღკაზმულობა, ლანგრები, ხელთათმანები და ფარები</p>\n\n<p>მეტი ინფორმაციისთვის ეწვიეთ ვებგვერდს.</p>\n\n<div data-oembed-url=\"https://campingeorgia.ge/hiking/\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.3333%; padding-top: 120px;\"><iframe allowfullscreen=\"\" src=\"//if-cdn.com/dB5sl38?app=1\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n<script async=\"\" charset=\"utf-8\" src=\"//if-cdn.com/embed.js\"></script></div>\n\n<p>&nbsp;</p>\n', '', '', '', '', '', NULL, NULL, '2024-01-07 19:12:17', '2025-07-15 11:52:41'),
(318, 'ru', '.', '<p>.</p>\n', '<p>.</p>\n', '', '', '', '', '', NULL, NULL, '2024-01-07 19:12:17', '2024-01-07 19:12:17'),
(319, 'us', 'Via-ferrata In Georgia', '<p>.</p>\n', '<div data-oembed-url=\"https://www.google.com/maps/d/edit?mid=15P_pbT4bULInsAO7sf6qb-mXoAuvrcQ&amp;usp=sharing\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 75%;\"><iframe allowfullscreen=\"\" src=\"//if-cdn.com/DRYOe3Tm\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p><strong>VIA FERRATA in SVERI </strong>is the first-ever Via Ferrata project in the Georgian and Caucasus region. It is located in the village of Sveri, 700 meters from the camp. The Via Ferrata is a route, equipped with steel ropes and iron steps 70 meters high and 160 meters long with full safety. Via Ferrata in Sveri offers a unique experience to active and extreme adventurers. This adventure tour is perfect for solo,&nbsp;family, as well as corporate visitors. Two route &ndash; easy and medium &ndash; is an excellent fit for beginners as well as experienced adventurers.</p>\n\n<p><strong>Technical and other characteristics of the trail:</strong>&nbsp;</p>\n\n<ul>\n	<li>Route distance &ndash; 230 meters, 300 steps</li>\n	<li>Route time &ndash; 70/90 minutes</li>\n	<li>Full time of the route &ndash; 2/2.5 hours (theoretical and practical instruction in the camp &ndash; 0.5 hours, walk from the camp &ndash; 15 minute, time of passage &ndash; 70/90 minutes, return &ndash; 15 minutes)</li>\n	<li>Maximum and minimum number of visitors in the group &ndash; 10/3</li>\n	<li>Guiding &ndash; two instructors</li>\n	<li>Length of access pedestrian path and back connecting path &ndash; 600 meters</li>\n	<li>Number of routes &ndash; 2, easy and difficult&nbsp;</li>\n</ul>\n\n<p><strong>Price info</strong><strong>:</strong></p>\n\n<p>Per person &ndash; 35 Euro</p>\n\n<p><strong>Price includes</strong><strong>:</strong></p>\n\n<p>Helmet, harness, lanyards, gloves and headlamp</p>\n\n<p>for more information visit wesite.</p>\n\n<div data-oembed-url=\"https://campingeorgia.ge/hiking/\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.3333%; padding-top: 120px;\"><iframe allowfullscreen=\"\" src=\"//if-cdn.com/dB5sl38?app=1\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n<script async=\"\" charset=\"utf-8\" src=\"//if-cdn.com/embed.js\"></script></div>\n\n<p>&nbsp;</p>\n', '', '', '', '', '', NULL, NULL, '2024-01-07 19:12:17', '2025-07-15 11:52:41'),
(320, 'ka', 'ახალი საცოცი მარშრუტების განვითარების ხელშეწყობა საქართველოში', '<p>ერთად განცავითაროდ საცოცი მარშრუტები ბუნებრივ კლდეზე მთელი საქართველოს მაშტაბით</p>\n', '<p>საქართველოში სპორტული ცოცვა ჯერ კიდევ საბჭოთა კავშირის დროიდან იღებს სათავეს, მაგრამ პირველი საცოცი მარშრუტი ბუნებრივ კლდეზე, საერთაშორისო სტანდარტების დაცვით მხოლოდ 2006 წელს გაკეთდა, გუგა დაბრუნდაშვილის მიერ. ამ დროიდან მოყოლებული ქართველი მეკლდეურები საკუთარი ხარჯებით განაგრძობენ საცოცი მარშრუტების დამატებას მთელი საქართველოს მაშტაბით.</p>\n\n<p>იმის გამო რომ სპორცმენებს არანაირი ხელშეწყოა არ აქვთ ამა თუ იმ ორგანიზაციების მხრიდან მათ უწევთ თავიანთი ხარჯები გაიღონ რათა სპორტული მარშრუტები დაემატოს ამა თუ იმ რეგიონში.</p>\n\n<p>დღეისთვის საქართველოში 400-ამდე სპორტული მარშრუტია.</p>\n\n<p>ჩვენი ორგანიზაცია მუდამ ცდილობს ფინანსების მოძიებას სხვადასხვა გზებით. მიუხედავად ამისა მცირედი დონაციების გამოკლებით არანაირი ფინანსური დახმარება არ ყოფილა გამოყოფილი საქართველოშ არცერთი საცოცი სექტორის განსავითარებლად.</p>\n\n<p>მიუხედავად ყველაფრისა ჩვენ მაინც არ ვნებდებით და ვცდილობთ ამ სფეროს განვითარებას საქართველოშ.</p>\n\n<p>თუ გაქვთ სურვილი შეიტანოთ თქვენი წვლილი საქართველოს მეკლდეურობის განვითარებაში შეგიძლიათ დაგვეხმაროთ ფინანსურად. ამისთვის შეგიძლიათ ჩვენ ანგარიშზე ჩაგვირიცხოთ თქვენთვის სასურველი თანხა. ჩვენ მადლობელები ვართ ყოველი ლარისთვის რადგან ეს ჩვენთვის ძალიან მნიშვნელოვანია.</p>\n\n<p>&nbsp;</p>\n\n<h2><strong>მოქმედებს ნაგარიში TBC ბანკში.</strong></h2>\n\n<h2><strong>GE08TB7019336515100044</strong></h2>\n\n<p>&nbsp;</p>\n\n<div data-oembed-url=\"https://www.youtube.com/shorts/2-Ic_6B5-84\">\n<div style=\"max-width: 56vh;\">\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 177.7778%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/jUNsRmbw\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n', '', '', '', '', '', NULL, NULL, NULL, '2026-02-08 00:56:14'),
