INSERT INTO `locale_articles` (`id`, `locale`, `title`, `short_description`, `text`, `route`, `how_get`, `best_time`, `what_need`, `info`, `price_text`, `address`, `created_at`, `updated_at`) VALUES
(382, 'ka', 'მყინვარწვერი აღმოსავლეთ ქედიდან', '<p>AD+, WI 3, 1200m, (3B RUSS)</p>\n', '<p>მყინვარწვერის აღმოსავლეთ ქედის მარშრუტი ერთ-ერთი ყველაზე საინტერესო და პოპულარული გზაა კლასიკური მარშრუტის შემდეგ.</p>\n\n<p>მარშრუტი კარგად შეეფერება საშუალო დონის ალპინისტებს. გაითვალისწინეთ, რომ ასვლამდე აუცილებელია კარგი აკლიმატიზაციის გავლა.</p>\n', '<p>მარშრუტი იწყება ბეთლემის ქოხიდან (მეტეოსადგურიდან). პირველ ეტაპზე მივდივართ ბეთლემის ეკლესიის მიმართულებით.</p>\n\n<p>ბეთლემის ეკლესიიდან გავდივართ აღმოსავლეთისკენ და შევდივართ დიდ თოვლიან ფერდზე (დაახლ. 25&ndash;30 გრადუსიანი დახრილობა), სადაც ზოგ შემთხვევაში შესაძლებელია მოძრაობა თოკში ჩაუბმელად. ფერდის გავლის შემდეგ მივდივართ კლდოვან მონაკვეთამდე, სადაც სიტუაციის მიხედვით ვარჩევთ უსაფრთხო გასავლელ ხაზს. კლდოვანი მონაკვეთის შემდეგ კვლავ გავდივართ თოვლიან ფერდზე და ვაგრძელებთ ასვლას, სანამ არ მოვხვდებით სამხრეთ ქედზე (&bdquo;პლეჩომდე&ldquo;). ქედის დასაწყისში შესაძლებელია კარვის გაშლა.</p>\n\n<p>ქედიდან ვაგრძელებთ მოძრაობას ჩრდილოეთის ფერდზე (დაახლ. 30&ndash;40 გრადუსიანი დახრილობა). ფერდის დასაწყისამდე აუცილებელია თოკში ჩაბმა. ასვლას ვაგრძელებთ კლდოვან კბილამდე.</p>\n\n<p>ამ ეტაპზე ფერდობი ციცაბო ხდება და გვხვდება ყინულის მონაკვეთები (დაახლ. 40&ndash;45 გრადუსი). შესაძლებელია საჭირო გახდეს ყინულის ბურებით დაცვითი წერტილების მოწყობა ან თოკის გაჭიმვა. ფერდის შუა ნაწილში ასვლის შემდეგ ვხვდებით ნალის ფორმის პატარა პლატოზე. აქედან, მცირე ყინულიანი ფერდის გავლით, გავდივართ დიდ პლატოზე. ამ პლატოდან ჩრდილოეთის მიმართულებით ფერდით მივდივართ მწვერვალზე.</p>\n\n<p><strong>მეტეოდან გასვლის დრო</strong>: ღამის 2 საათი.<br />\n<strong>მარშრუტის ხანგრძლიობა (ბეთლემის ქოხიდან - მწვერვალამდე)</strong>: 8-10 საათი<br />\n<strong>დაშვება</strong>: <a href=\"https://climbing.ge/ka/mountaineering/myinvartsveri_clasic_2a\">დაშვებას ვახორციელებთ კლასიკური მარშრუტით.</a><br />\n<br />\n&nbsp;</p>\n\n<div data-oembed-url=\"https://www.strava.com/activities/14921206429?utm_source=ios_share&amp;utm_medium=social&amp;share_sig=4624BC111751626923&amp;_branch_match_id=1380441986139316198&amp;_branch_referrer=H4sIAAAAAAAAA8soKSkottLXLy4pSixL1EssKNDLyczL1rdIq7IodE409wxNsq8rSk1LLSrKzEuPTyrKLy9OLbJ1zijKz00FANBthjs9AAAA\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 52.5%; padding-top: 120px;\"><iframe allowfullscreen=\"\" src=\"//if-cdn.com/Ly0YeXgW?app=1\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n<script async=\"\" charset=\"utf-8\" src=\"//if-cdn.com/embed.js\"></script>\n</div>\n\n<p>&nbsp;</p>\n', '', '', '<ol>\n	<li>ყინულის ინსტრუბენტები</li>\n</ol>\n', '', NULL, NULL, NULL, '2025-07-04 18:41:51'),
(383, 'us', 'Myinvartsveri from the eastern ridge', '<p>AD+, WI 3, 1200m, (3B RUSS)</p>\n', '<p>The route to Mount Kazbek from the eastern ridge is one of the most interesting and popular routes after the classic one.</p>\n\n<p>It is a good route for intermediate-level mountaineers. Keep in mind that proper acclimatization is essential before the ascent.</p>\n', '<p>The route begins at Bethlemi Hut (the meteorological station). From there, we head in the direction of the Bethlehem Church.</p>\n\n<p>From the Bethlehem Church, we go east and enter a large snowy slope (with a 25&ndash;30 degree incline, it is possible to walk without being roped in). We continue toward a rocky section, where depending on the situation, we choose a safe ascent path and then return to a snowy slope. We keep climbing until we reach the southern ridge (up to the &quot;plecho&quot;). (At the beginning of the ridge, it is possible to set up a tent.)</p>\n\n<p>From the ridge, we continue on the northern slope (with a 30&ndash;40 degree incline; roping up is necessary before reaching the start of the slope). We keep moving until we reach a rocky tooth formation.</p>\n\n<p>From here, the slope becomes steeper, and icy sections appear (40&ndash;45 degrees). You may need to set up ice protection using ice screws and/or rope up. We continue climbing through the middle of the slope and enter a horseshoe-shaped plateau. From there, we ascend a small icy slope to reach the large plateau. From the plateau, heading north on a final slope, we reach the summit.</p>\n\n<p><strong>Departure from Meteo Station</strong>: 2:00 AM<br />\n<strong>Route duration (from Bethlemi Hut to the summit)</strong>: 8&ndash;10 hours<br />\n<strong>Descent</strong>: <a href=\"https://climbing.ge/mountaineering/myinvartsveri_clasic_2a\">The descent is done via the classic route.</a><br />\n&nbsp;</p>\n\n<div data-oembed-url=\"https://www.strava.com/activities/14921206429?utm_source=ios_share&amp;utm_medium=social&amp;share_sig=4624BC111751626923&amp;_branch_match_id=1380441986139316198&amp;_branch_referrer=H4sIAAAAAAAAA8soKSkottLXLy4pSixL1EssKNDLyczL1rdIq7IodE409wxNsq8rSk1LLSrKzEuPTyrKLy9OLbJ1zijKz00FANBthjs9AAAA\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 52.5%; padding-top: 120px;\"><iframe allowfullscreen=\"\" src=\"//if-cdn.com/Ly0YeXgW?app=1\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n<script async=\"\" charset=\"utf-8\" src=\"//if-cdn.com/embed.js\"></script>\n</div>\n\n<p>&nbsp;</p>\n', '', '', '', '', NULL, NULL, NULL, '2025-07-04 18:41:51'),
(384, 'ka', 'ჭაუხის ტრავერსი', '<p>თემო სამსონაძემ და სოფო ჭელიძემ ჭაუხის სრული ტრავერსი გაიარეს</p>\n', '<p><strong>ჭაუხის მასივი</strong>, რომელსაც ხშირად &bdquo;ქართული დოლომიტები&ldquo; ეწოდება, ცნობილია თავისი სილამაზით და ტექნიკურად რთული მარშრუტებით. მაგრამ ამ საოცარი ხედების მიღმა იმალება ტრავერსი, რომელიც ცოტა ადამიანმა გაბედა სრულად გაევლო. <strong>25-27 ივლისს</strong> ჩვენ გადავწყვიტეთ სწორედ ამ ხაზის გავლა &mdash; <strong>ჭაუხის მასივის სრული ტრავერსი</strong>, <strong>თიკანაძის მწვერვალიდან ჯავახიშვილის მწვერვალამდე</strong>.</p>\n\n<p><strong>სამი ინტენსიური დღის და ორი ღამის</strong> განმავლობაში, გადავკვეთეთ <strong>11 მწვერვალი</strong> &mdash; <strong>9 ცნობილი</strong> და <strong>2 უცნობი ან დაუფიქსირებული</strong>. მარშრუტი მიჰყვებოდა ჭაუხის ქედს.</p>\n\n<p>ყოველი მწვერვალი გვიხსნიდა ყაზბეგის რეგიონის ახალ პერსპექტივას &mdash; ზოგჯერ ოქროსფერი მზის შუქში, ზოგჯერ ღრუბლებსა და ქარში მოქცეული. ღამეები იყო მშვიდი და ვარსკვლავებით სავსე.</p>\n\n<p>ტრავერსი მივუძღვენით ჩვენს მეგობარს, <strong>არჩილ ბადრიაშვილს</strong>, <strong>2015 წელს</strong> არჩილმა <strong>ჭაუხის სრული ტრავერსი მარტომ (სოლო)</strong> გაიარა. &mdash; რაც დღემდე ერთადერთი ტრავერსის გავლა იყო&nbsp;<strong>საპირისპირო მიმართულებით</strong>: ჯავახიშვილიდან თიკანაძისკენ. მისი მიღწევა დღემდე შთააგონებს მთამსვლელების ახალ თაობას &mdash; მათ შორის ჩვენც.</p>\n\n<p>განსაკუთრებული მადლობა ჩემს დას, <strong>ქეთი სამსონაძეს</strong>, რომელმაც უზრუნველყო <strong>წყლის მარაგი</strong> და <strong>კავშირზე ყოფნა</strong> ტრეკის განმავლობაში. მისი დახმარება იყო გადამწყვეტი ჩვენი უსაფრთხოებისა და წარმატებისთვის.</p>\n\n<p>ასევე, უდიდესი პატივისცემა ჩემს პარტნიორს, <strong>Popo Popo</strong>-ს &mdash; თოკისა და გადაწყვეტილების თანაზიარი იყო.</p>\n\n<hr />\n<p>📍 <strong>მარშრუტი:</strong> თიკანაძე &rarr; ჯავახიშვილი<br />\n📆 <strong>დრო:</strong> 25&ndash;27 ივლისი<br />\n🥾 <strong>ხანგრძლივობა:</strong> 3 დღე / 2 ღამე<br />\n⛰️ <strong>წვერები:</strong> სულ 11 (9 ცნობილი, 2 უცნობი)<br />\n🎗️ <strong>ეძღვნება:</strong> არჩილ ბადრიაშვილს</p>\n\n<div data-oembed-url=\"https://www.facebook.com/share/p/1F6JjTHpqJ/\">\n<div style=\"max-width: 640px;\">\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 50%;\"><iframe allowfullscreen=\"\" src=\"//if-cdn.com/f6kzok4p?app=1\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n<script async=\"\" charset=\"utf-8\" src=\"//if-cdn.com/embed.js\"></script></div>\n\n<p>&nbsp;</p>\n', '', '', '', '', '', NULL, NULL, NULL, '2025-08-14 01:19:42'),
(385, 'us', 'Chaukhi travers', '<p>Temo Samsonadze and Sopo Chelidze as the climbers who completed the Chauki full traverse</p>\n', '<p><strong>The Chauki Massif</strong>, often referred to as the &ldquo;<strong>Georgian Dolomites</strong>,&rdquo; is renowned for its beauty and technically demanding routes. But behind these stunning views lies a traverse that few have dared to complete. <strong>From July 25&ndash;27</strong>, we set out to walk that very line &mdash; the <strong>full traverse of the Chauki Massif</strong>, <strong>from Mt. Tikandze to Mt. Javakhishvili</strong>.</p>\n\n<p>Over the course of <strong>three intense days and two nights</strong>, we crossed <strong>11 summits</strong> &mdash; <strong>9 known</strong> and <strong>2 unknown or undocumented</strong>. The route followed the Chauki ridge.</p>\n\n<p>Each peak revealed a new perspective of the Kazbegi region &mdash; sometimes glowing in golden sunlight, other times shrouded in clouds and wind. The nights were calm and full of stars.</p>\n\n<p>We dedicated the traverse to our friend, <strong>Archil Badriashvili</strong>, who in <strong>2015</strong> completed the <strong>full Chauki traverse solo</strong> &mdash; the only recorded traverse done in the <strong>opposite direction</strong>, from Javakhishvili to Tikandze. His achievement continues to inspire a new generation of mountaineers &mdash; including us.</p>\n\n<p>Special thanks to my sister, <strong>Keti Samsonadze</strong>, who provided <strong>water resupply</strong> and <strong>communication support</strong> throughout the trek. Her help was crucial to our safety and success.</p>\n\n<p>And the deepest respect to my partner, <strong>Popo Popo</strong> &mdash; a true companion in rope and resolve.</p>\n\n<hr />\n<p>📍 <strong>Route:</strong> Tikandze &rarr; Javakhishvili<br />\n📆 <strong>Date:</strong> July 25&ndash;27<br />\n🥾 <strong>Duration:</strong> 3 days / 2 nights<br />\n⛰️ <strong>Summits:</strong> 11 total (9 known, 2 unknown)<br />\n🎗️ <strong>Dedicated to:</strong> Archil Badriashvili</p>\n\n<div data-oembed-url=\"https://www.facebook.com/share/p/1F6JjTHpqJ/\">\n<div style=\"max-width: 6400px;\">\n<div style=\"left: 0; width: 100%; height: 100%; position: relative; padding-bottom: 50%;\"><iframe allowfullscreen=\"\" src=\"//if-cdn.com/f6kzok4p?app=1\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n<script async=\"\" charset=\"utf-8\" src=\"//if-cdn.com/embed.js\"></script></div>\n', '', '', '', '', '', NULL, NULL, NULL, '2025-08-02 15:05:24'),
(386, 'ka', 'მწვერვალ ასათიანის აღმოსავლეთ კედელი უნაგირიდან', '<p>AD 300m (Russ. 3a)</p>\n', '<p>.</p>\n', '', '', '', '', '', NULL, NULL, NULL, '2025-10-31 16:55:24'),
