INSERT INTO `locale_bisneses` (`id`, `locale`, `title`, `short_description`, `text`, `created_at`, `updated_at`) VALUES
(1, 'ka', 'Sveri Adventure Camp', '<p>.</p>\n', '<p>Sveri Adventure Camp მდებარეობს იმერეთის რაიონის ძალიან მომხიბვლელ და ისტორიულ სოფელ სვერში. ქუთაისის საერთაშორისო აეროპორტიდან 113 კმ, მანქანით 1,5 საათი და თბილისიდან 180 კმ, 2 საათის სავალზე. ბანაკი ქალაქ ჭიათურიდან 11 კილომეტრშია. ბანაკის მდებარეობა მონიშნულია ცენტრალურ გზაზე, გზა მთლიანად ჩაფლულია კლდის ხეობაში და ხეობის ბოლოს, გზის მარჯვნივ შეამჩნევთ ბანაკის ნიშანს.</p>\n\n<p>ბანაკს აქვს ყველა საჭირო ინფრასტრუქტურა - ხის კოტეჯები, კარვის ფართი, საერთო სასადილო ოთახი, სამზარეულო, საშხაპე და ტუალეტები, აღჭურვილობის დაქირავება, ჰამაკი, გასართობი ზონა ბატუტით, ცოცვის კედელი, აუზი, მაგიდის ჩოგბურთი, სლეკლინი, ფრისბი, ფრენბურთი და ბადმინტონი. . ბანაკში შესაძლებელია ხის კოტეჯში 7 სტუმრის განთავსება, კარვის ტერიტორიაზე 30 სტუმრის განთავსება. ბანაკიდან 70 მეტრში არის ასვლა ზონა და კლდის გამოქვაბულში არსებული ისტორიული ეკლესია. ბანაკის ირგვლივ 5 კმ-ში არის უამრავი სათავგადასავლო ადგილი, სადაც ჩვენ ვთავაზობთ ტურებს ჩვენს მომხმარებლებს, როგორიცაა კლდეზე ცოცვა, ველოსიპედი, გამოქვაბულის ტური, ლაშქრობა, ნავით ტური, ისტორიული და კულტურული ტური და Via Ferrata ტური, პირველი ექსტრემალური ბილიკი. კავკასიაში.</p>\n\n<h2>კემპინგი</h2>\n\n<p>აღმოაჩინეთ კომფორტული და ხელმისაწვდომი განსახლების ვარიანტების სპექტრი ჩვენს ბანაკში. მიუხედავად იმისა, ეძებთ გუმბათოვანი გუმბათის ფუფუნებას, ხის კოტეჯის რუსტიკულ ხიბლს, თუ კარვებში კემპინგის თავგადასავალს, ჩვენ გვაქვს რაღაც ყველასთვის.</p>\n\n<p><a href=\"https://campingeorgia.ge/camp-services/\">მეტი ინფორმაციისთვის ეწვიეთ ვებგვერდს</a></p>\n\n<h2>VIA FERRATA სვერში</h2>\n\n<p>არის პირველი Via Ferrata პროექტი საქართველოსა და კავკასიის რეგიონში. მდებარეობს სოფელ სვერში, ბანაკიდან 700 მეტრში. Via Ferrata არის მარშრუტი, რომელიც აღჭურვილია ფოლადის თოკებით და რკინის საფეხურებით 70 მეტრი სიმაღლით და 160 მეტრი სიგრძით სრული უსაფრთხოებით. Via Ferrata სვერში უნიკალურ გამოცდილებას სთავაზობს აქტიურ და ექსტრემალურ ავანტიურისტებს. ეს სათავგადასავლო ტური შესანიშნავია მარტო,&nbsp;ოჯახისთვის, ასევე კორპორატიული ვიზიტორებისთვის. ორი მარშრუტი - მარტივი და საშუალო - შესანიშნავია როგორც დამწყებთათვის, ასევე გამოცდილი ავანტიურისტებისთვის.</p>\n\n<div data-oembed-url=\"https://www.viaferrata.ge/\">\n<div>\n<div style=\"left: 0; width: 100%; height: 140px; position: relative;\"><iframe allowfullscreen=\"\" src=\"//if-cdn.com/77aR7hG?app=1\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n<script async=\"\" charset=\"utf-8\" src=\"//if-cdn.com/embed.js\"></script></div>\n\n<p>&nbsp;</p>\n\n<div id=\"gtx-trans\" style=\"position: absolute; left: -11px; top: 200.516px;\">\n<div class=\"gtx-trans-icon\">&nbsp;</div>\n</div>\n', '2023-04-15 02:14:48', '2023-11-20 02:26:30'),
(2, 'ru', 'სვერის სათავგადასავლო ბანაკი', '<p>.</p>\n', '<h1>Sveri Adventure Camp</h1>\n', '2023-04-15 02:14:48', '2023-04-15 02:14:48'),
(3, 'us', 'Sveri Adventure Camp', '<p>Camping and advencher place</p>\n', '<p>Sveri Adventure Camp is located in the very charming and historic village of Sveri in Imereti district. 113 km from Kutaisi International Airport, a 1.5-hour drive,&nbsp;and 180 km from Tbilisi, a 2-hour drive. The camp is 11 km from the city of Chiatura. The location of the camp is marked on the central road, the road is completely immersed in the rock valley and at the end of the valley, you will notice the camp mark to the right of the road.</p>\n\n<p>The camp has all the necessary infrastructure &ndash; wooden cottages, tent area, common dining room, kitchen, shower and toilets, equipment rent, hammock, entertainment zone with trampoline, climbing wall, pool, table tennis, slackline, Frisbee, volleyball, and badminton. The camp can accommodate 7 guests in a wooden cottage and 30 guests in a tent area. 70 meters walk from the camp is the climbing zone and the historic church in the rock cave. Within 5 km around the camp, there are lots of adventure places where we offer tours to our customers, such as rock climbing, cycling, cave tour, hiking, boat tour, historical and cultural tour, and Via Ferrata tour, a first extreme trail in the Caucasus.</p>\n\n<h2>Camp Services</h2>\n\n<p>Discover a range of comfortable and affordable accommodation options at our camp. Whether you&rsquo;re seeking the luxury of a glamping dome, the rustic charm of a wood cottage, or the adventure of tent camping, we have something for everyone.</p>\n\n<p><a href=\"https://campingeorgia.ge/camp-services/\">For more informatione visit ouer website.</a></p>\n\n<h2>VIA FERRATA in SVERI&nbsp;</h2>\n\n<p>is the first-ever Via Ferrata project in the Georgian and Caucasus region. It is located in the village of Sveri, 700 meters from the camp. The Via Ferrata is a route, equipped with steel ropes and iron steps 70 meters high and 160 meters long with full safety. Via Ferrata in Sveri offers a unique experience to active and extreme adventurers. This adventure tour is perfect for solo,&nbsp;family, as well as corporate visitors. Two route &ndash; easy and medium &ndash; is an excellent fit for beginners as well as experienced adventurers.</p>\n\n<div data-oembed-url=\"https://www.viaferrata.ge/\">\n<div>\n<div style=\"left: 0; width: 100%; height: 140px; position: relative;\"><iframe allowfullscreen=\"\" src=\"//if-cdn.com/77aR7hG?app=1\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n<script async=\"\" charset=\"utf-8\" src=\"//if-cdn.com/embed.js\"></script></div>\n\n<p>&nbsp;</p>\n', '2023-04-15 02:14:48', '2023-11-20 02:26:30'),
(4, 'ka', 'Climbing Lizards', '<p>ცოცვის სკოლა ბავშვებისთვის</p>\n', '<h2>&nbsp;</h2>\n\n<p>&ldquo;Climbing Lizards&rdquo; აუტისტური სპექტრის და შეზღუდული შესაძლებლობის მქონე პირთა ცოცვა - სარეაბილიტაციო კლუბი, რომელიც მოიცავს კოგნიტური უნარების განვითარებას.</p>\n\n<p>კლუბის დამფუძნებელი ემილი სამსონიძე, ის პროფესიით ექიმია. წლებია აქტიურად არის დაკავებული მეკლდეურობით და ალპინიზმით. მისი კვლევების შედეგად, თუ რა შედეგებს იწვევს მეკლდეურობა ორგანიზმის და გონების განვითარებაში, სწორედ ეს გახდა მიზეზი კლუბის ჩამოყალიბების, რომელიც 2020 წელს დააფუძნა.</p>\n\n<p>მეკლდეურობა აჯანსაღებს ორგანიზმს, აძლევს სწორ მიმართულებას ძვლოვან სისტემას, ააქტიურებს მოტორულ ფუნქციებს და აქტიურს ხდის მას.</p>\n\n<p>&bdquo;Climbig Lizards&rdquo; - მისი დამფუძნებელი ემილი სამსონიძე 2023 წლის თებერვალში აღიარეს მსოფლიში პირველ ადამიანად, აუტისტური სპექტრის და შეზღუდული შესაძლებლობის მქონე პირთა პირველი კლუბის დაფუძნებაში.</p>\n\n<h2>&nbsp;</h2>\n', '2023-04-15 02:24:17', '2023-04-17 22:15:05'),
(5, 'ru', 'Climbing Lizards', '<p>Школа скалолазания для детей</p>\n', '<p>Клуб скалолазания и реабилитации &quot;Climbing Lizards&quot; для людей с аутистическим спектром и инвалидностью, включающий развитие когнитивных способностей.</p>\n\n<p>Основатель клуба Эмили Самсонидзе, врач по профессии. Много лет активно занимается скалолазанием и альпинизмом. В результате ее исследования влияния скалолазания на развитие тела и разума это стало причиной создания клуба, который она основала в 2020 году.</p>\n\n<p>Скалолазание оздоровляет тело, дает правильное направление костной системе, активизирует двигательные функции и делает их активными.</p>\n\n<p>&laquo;Climbig Lizards&raquo; - ее основательница Эмили Самсонидзе была признана в феврале 2023 года первым человеком в мире, создавшим первый клуб для людей с аутизмом и инвалидностью.</p>\n', '2023-04-15 02:24:17', '2023-04-17 22:15:05'),
(6, 'us', 'Climbing Lizards X', '<p>Climbing school for kids</p>\n', '<h2>&nbsp;</h2>\n\n<p>&ldquo;Climbing Lizards&rdquo; &ndash; climbing and rehabilitation club for people with autistic spectrum and disabilities, that includes the development of cognitive skills.</p>\n\n<p>The founder of the club is Emily Samsonidze, she is a doctor by profession. She has been actively engaged in rock climbing and mountaineering for years. As a result of her research on the effects of rock climbing on the development of the body and mind, this was the reason for the formation of the club, which she founded in 2020.</p>\n\n<p>Rocking makes the body healthy, gives the right direction to the bone system, activates the motor functions and makes it active.</p>\n\n<p>&ldquo;Climbing Lizards&rdquo; &ndash; its founder Emily Samsonidze was recognized in February 2023 as the first person in the world to create the first club for people with autism and disabilities.</p>\n\n<h2>&nbsp;</h2>\n', '2023-04-15 02:24:17', '2024-01-18 18:16:29'),
