INSERT INTO `locale_events` (`id`, `locale`, `title`, `short_description`, `text`, `info`, `created_at`, `updated_at`) VALUES
(1, 'ru', 'ი. გელდიაშვილის მემორიალი სწრაფ და რთ.ცოცვაში', '<p>ი. გელდიაშვილის მემორიალი სწრაფ და რთ.ცოცვაში</p>\n', '<p>ი. გელდიაშვილის მემორიალი სწრაფ და რთ.ცოცვაში</p>\n', '', '2023-04-13 20:43:35', '2023-04-13 20:43:35'),
(2, 'ka', 'ი. გელდიაშვილის მემორიალი სწრაფ და რთ.ცოცვაში', '<p>ი. გელდიაშვილის მემორიალი სწრაფ და რთ.ცოცვაში</p>\n', '<p>ი. გელდიაშვილის მემორიალი სწრაფ და რთ.ცოცვაში</p>\n', '', '2023-04-13 20:43:35', '2023-04-13 20:43:35'),
(3, 'us', 'Irakli Gildiashvili memorial competition 2023', '<p>Irakli Gildiashvili memorial competition 2023</p>\n', '<p>Irakli Gildiashvili memorial competition 2023</p>\n', '', '2023-04-13 20:43:35', '2023-04-13 20:43:35'),
(4, 'ru', 'საქ. ჩემპიონატი ბოლდერინგში და რთულ ცოცვაში 2023', '<p>.</p>\n', '<p>ივნისი ჩატარდება <strong>საქართველოს ჩემპიონატი ბოლდერინგში და რთულ ცოცვაში 2023</strong>. ფესტივალი ჩატარდება ქუთაისში არსებულ დარბაზში.</p>\n\n<p>გაითვალისწინეთ რომ ღონისძიების ჩატარების თარიღი და ზუსტი ჩატარების ადგილი დაკორეკტირდება ღონისძიებამდე 2 კვიღით ადრე.</p>\n', '', '2023-04-13 22:16:35', '2023-05-27 00:59:27'),
(5, 'ka', 'Чемпионат по боулдерингу и сложному лазанию 2023', '<p>Чемпионат по боулдерингу и сложному лазанию 2023</p>\n', '<p>Чемпионат по боулдерингу и сложному лазанию 2023</p>\n', '', '2023-04-13 22:16:35', '2023-05-27 00:59:27'),
(6, 'us', 'Championship in bouldering and lead climbing 2023', '<p>.</p>\n', '<p>The <strong>Georgian couldering and lead climbing championship 2023</strong> will be held in June. The festival will be in Kutaisi climbing gym.</p>\n\n<p>Please note that the event date and exact venue will be adjusted 2 weeks before the event.</p>\n', '<p>ss</p>\n', '2023-04-13 22:16:35', '2023-05-27 00:59:27'),
(7, 'ru', 'მიხეილ ხერგიანის მემორიალი 2023', '<p>.</p>\n', '<p>ივნისი ჩატარდება&nbsp;<strong>მიხეილ ხერგიანის მემორიალური შეჯიბრი 2023.</strong>&nbsp;შეჯიბრი ჩატარდება მესრიაში არსებულ დარბაზში და ბუნებრივ კლდეზე.</p>\n\n<p>გაითვალისწინეთ რომ ღონისძიების ჩატარების თარიღი და ზუსტი ჩატარების ადგილი დაკორეკტირდება ღონისძიებამდე 2 კვიღით ადრე.</p>\n', '', '2023-04-13 22:21:24', '2023-05-27 01:09:00'),
(8, 'ka', 'Михаил Хергиани, мемориальный конкурс 2023', '<p>.</p>\n', '<p>Михаил Хергиани, мемориальный конкурс 2023</p>\n', '', '2023-04-13 22:21:24', '2023-05-27 01:09:00'),
(9, 'us', 'Mikheil khergini momorial competition 2023', '<p>.</p>\n', '<p>In June, the <strong>Mikheil Khergiani Memorial Competition 2023</strong> will be held. The competition will be in the Mesria climbing gym and outdoor climbing routes routes.</p>\n\n<p>Please note that the event date and exact venue will be adjusted 2 weeks before the event.</p>\n', '', '2023-04-13 22:21:24', '2023-05-27 01:09:00'),
(10, 'ru', 'საქართველოს ახალგაზ. ფესტ. ბუნებრივ კლდეებზე 2023', '<p>,</p>\n', '<p>აგვისტოში ჩატარდება საქართველოს ახალგაზრდული ფესტივალი ბუნებრივ კლდეებზე. ფესტივალი ჩატარდება ჭიათურის რეგიონში ერთერთ სექტორში.</p>\n\n<p>გაითვალისწინეთ რომ ღონისძიების ჩატარების თარიღი და ზუსტი ჩატარების ადგილი დაკორეკტირდება ღონისძიებამდე 2 კვიღით ადრე.</p>\n', '', '2023-04-13 22:29:10', '2023-05-27 00:41:39'),
(11, 'ka', 'Фестиваль скалолазания среди юниоров 2023', '<p>.</p>\n', '<p>Фестиваль скалолазания среди юниоров 2023</p>\n', '', '2023-04-13 22:29:10', '2023-05-27 00:41:39'),
(12, 'us', 'Georgian uniors outdoor climbing festival 2023', '<p>.</p>\n', '<p>In August, the Georgian Youth Festival will be held on rocks. The festival will be held in one of the sectors in Chiaturi region.</p>\n\n<p>Please note that the event date and exact venue will be adjusted 2 weeks before the event.</p>\n', '', '2023-04-13 22:29:10', '2023-05-27 00:41:39'),
(13, 'ru', 'საქართველოს ბოლდერინგის ჩემპიონატი 2023', '<p>,</p>\n', '<p>აგვისტოში ჩატარდება<strong> საქართველოს ჩემპიონატი ბოლდერინგში</strong>. ფესტივალი ჩატარდება ყაზბეგის საცოც დარბაზში.</p>\n\n<p>გაითვალისწინეთ რომ ღონისძიების ჩატარების თარიღი და ზუსტი ჩატარების ადგილი დაკორეკტირდება ღონისძიებამდე 2 კვიღით ადრე.</p>\n', '<p>ыыыыы</p>\n', '2023-04-14 00:03:31', '2023-05-27 01:18:08'),
(14, 'ka', 'Чемпионат Грузии по боулдерингу 2023', '<p>.</p>\n', '<p>.</p>\n', '', '2023-04-14 00:03:31', '2023-05-27 01:18:08'),
(15, 'us', 'Bouldering сhampionship of Georgia 2023', '<p>.</p>\n', '<p><strong>Georgian championship in bouldering</strong> will be in August. The festival will be in Stepantsminda climbing gym.</p>\n\n<p>Please note that the event date and exact venue will be adjusted 2 weeks before the event.</p>\n', '', '2023-04-14 00:03:31', '2023-05-27 01:18:08'),
(16, 'ru', 'საქართველოს ახალგაზრდული პირველობა 3 ასაკში 2023', '<p>.</p>\n', '<p>სექტემბერში <strong>ჩატარდება საქართველოს ახალგაზრდული პირველობა 3 ასაკში 2023</strong>. ფესტივალი ჩატარდება ყაზბეგის რეგიონში.</p>\n\n<p>გაითვალისწინეთ რომ ღონისძიების ჩატარების თარიღი და ზუსტი ჩატარების ადგილი დაკორეკტირდება ღონისძიებამდე 2 კვიღით ადრე.</p>\n', '', '2023-04-14 00:13:11', '2023-05-27 01:27:31'),
(17, 'ka', 'Молодежный чемпионат Грузии в 3-х возрастных группах 2023', '<p>.</p>\n', '<p>Молодежный чемпионат Грузии в 3-х возрастных группах 2023</p>\n', '', '2023-04-14 00:13:11', '2023-05-27 01:27:31'),
(18, 'us', 'Georgian youth championship in 3 age groups 2023', '<p>.</p>\n', '<p>In September, the <strong>2023 Georgian Youth Championship in 3 age groups</strong> will be held. The festival will be in the Kazbegi region.</p>\n\n<p>Please note that the event date and exact venue will be adjusted 2 weeks before the event.</p>\n', '', '2023-04-14 00:13:11', '2023-05-27 01:27:32'),
(25, 'ka', 'კლდის ვეფხვების ფესტივალი 2023', '<p>.</p>\n', '<p>ფესტივალი ჩატარდება 4 ივნისს (2 ივნისის ნაცვლად), ლოტკინის მონუმენტზე.</p>\n\n<p>ფესტივალი ტარდება, 2 ასაკობრივ კატეგორიაში</p>\n\n<p>2014-2015 წ.</p>\n\n<p>2016-2017 წ.</p>\n\n<p>სტუმრებს, მათი ასაკის მიუხედავად, შესაძლებლობა ექნებათ გამოსცადონ სხვადასხვა სირთულის საცოცი ბილიკები.&nbsp;</p>\n', '', '2023-05-27 01:33:08', '2023-05-27 01:33:08'),
(26, 'ru', '.', '<p>.</p>\n', '<p>.</p>\n', '', '2023-05-27 01:33:08', '2023-05-27 01:33:08'),
(27, 'us', 'Rock Tiger Festival 2023', '<p>.</p>\n', '<p>The festival will be held on June 4 (instead of June 2), at the Lotkin monument.</p>\n\n<p>The festival is held in 2 age categories</p>\n\n<p>2014-2015</p>\n\n<p>2016-2017</p>\n\n<p>Visitors, regardless of their age, will have the opportunity to try climbing trails of various levels of difficulty.</p>\n', '', '2023-05-27 01:33:08', '2023-05-27 01:33:08'),
(28, 'ka', 'ცოცვის ფესტივალი სვერში', '<p>.</p>\n', '<p>15 და 16 ივლისს სვერის სათავგადასავლო ბანაკისა და საქართველოს მეკლდეურობის ეროვნული ფედერაციის ორგანიზებით იმართება ცოცვის ფესტივალი სვერში. ღონისძიების მხარდამჭერია საქართველოს კულტურის სპორტისა და ახალგაზრდობის სამინისტრო.</p>\n\n<p>ფესტივალის პროგრამა:</p>\n\n<p>15 ივლისი</p>\n\n<p>17:00 &ndash; 23:00<br />\nფესტივალის გახსნა, ქემფინგი, პიკნიკი, კოცონი, მუსიკა, თამაშები, გართობა, მეგობრული და განმტვირთავი გარემო</p>\n\n<p>16 ივლისი</p>\n\n<p>შეჯიბრის დაწყება: 12:00<br />\nშეჯიბრის დასრულება: 17:00<br />\nდაჯილდოვება: 18:00<br />\nფესტივალის საზეიმო დახურვა: 19:00</p>\n\n<p>ფესტივალის აღწერა:</p>\n\n<p>ფესტივალზე მონაწილეობის მიღება შეუძლია ყველა მეკლდეურს, როგორც პროფესიონალს ისე მოყვარულს, წინასწარი რეგისტრაციის შედეგად. მონაწილეებს მოეთხოვებათ ქვედა დაცვით ცოცვის გამოცდილება. 2009 წელს (13-14 წელი) დაბადებულები და უფრო უმცროსი ასაკის ბავშები ფესტივალზე არ დაიშვებიან.<br />\nფესტივალის მონაწილეები ვალდებულნი არიან იქონიონ სრული ეკიპირება !!!<br />\nმათ ადგილზე დაურიგდებათ მონაწილის ბარათები, სადაც შეტანილი იქნება 40-მდე საცოცი ლაინი. მონაწილის მიერ ლაინის გავლა ფასდება მხოლოდ მსაჯის ხელმოწერით.<br />\nმონაწილის ბარათის ჩაბარების ბოლო ვადაა 17:00 საათი.</p>\n\n<p><img alt=\"🏆\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tbe/1/16/1f3c6.png\" style=\"height:16px; width:16px\" />გოგოებში და ვაჟებში, საუკეთესო სამეული გამოვლინდება დაგროვილი ქულების ჯამით.<br />\nფესტივალში მონაწილეობის მიღების მსურველებმა გთხოვთ რეგისტრაცია გაიაროთ ქვემოთ მოცემულ ბმულზე&nbsp;<img alt=\"👉\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;<a href=\"https://shorturl.at/FGIU1?fbclid=IwAR3wnm9zZpuGNl-fOI9AHwrSiNzS1qKEMiCXPPAtQ1GWNwo4ItcDtiWKpQM\" target=\"_blank\">https://shorturl.at/FGIU1</a></p>\n\n<p>რეგისტრაციის ბოლო ვადაა 12 ივლისი, 2023 წელი.</p>\n\n<p>ფესტივალის პირველ დღეს, 15 ივლისს, რეგისტრირებულ მონაწილეს შეუძლია ბანაკში ჩამოსვლა, რისთვისაც ბანაკი მათ უზუნველყოფს საკარვე ადგილით, სველ წერტილიზე, საშხაპესა და Wi-Fi -ზე წვდომით (საკარვე აღჭურვილობა, კვება და ტრანსპორტირება უნდა უზრუნველყოს თვითონ).</p>\n\n<p>საღამოს განმავლობაში და ფესტივალის დღეს, ბანაკის ტერიტორიაზე დაუკრავს დიჯეი.</p>\n\n<p><img alt=\"🏆\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tbe/1/16/1f3c6.png\" style=\"height:16px; width:16px\" />ფესტივალის გამარჯვებულები დასაჩუქრდებიან ფასიანი საჩუქრებითა და სიგელებით.</p>\n\n<p><img alt=\"🚌\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t79/1/16/1f68c.png\" style=\"height:16px; width:16px\" />ფესტივალის რეგისტრირებულ მონაწილეებს სურვლის შემთხვევაში შეუძლიათ ისარგებლონ მიკროავტობუსით, რომელიც უზრუნველყოფს ტრანსპორტირებას 16 ივლისს თბილისი-სვერი-თბილისი.</p>\n\n<p>შეკრების ადგილი ვარდების მოედანი (ველოსიპედის ძეგლთან) 16 ივლისი.</p>\n\n<p><img alt=\"✅\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t33/1/16/2705.png\" style=\"height:16px; width:16px\" />შეკრება - 07:30<br />\n<img alt=\"✅\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t33/1/16/2705.png\" style=\"height:16px; width:16px\" />მიკროავტობუსების გასვლა თბილისიდან სვერში -08:00<br />\n<img alt=\"✅\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t33/1/16/2705.png\" style=\"height:16px; width:16px\" />გამგზავრება სვერიდან თბილისში - 20:00</p>\n\n<p>16 ივნისს ფესტივალის მსვლელობისას რეგისტირებული მონაწილეებითვის უფასოდ დარიგდება ხილი, ტკბილეული, წყალი, ენერგეტიკული სასმელი.<br />\nბანაკის ტერიტორიაზე ფესტივალის სტუმრებისთვის ხელმისაწვდომი იქნება გამაგრილებები და ცხელი სასმელები, ასევე სხვადასხვა სახის საკვები პროდუქცია.<br />\n<img alt=\"☀️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6d/1/16/2600.png\" style=\"height:16px; width:16px\" /><img alt=\"☀️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6d/1/16/2600.png\" style=\"height:16px; width:16px\" /><img alt=\"☀️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6d/1/16/2600.png\" style=\"height:16px; width:16px\" /><img alt=\"☀️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6d/1/16/2600.png\" style=\"height:16px; width:16px\" /><img alt=\"☀️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6d/1/16/2600.png\" style=\"height:16px; width:16px\" /></p>\n\n<p><img alt=\"🚫\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6f/1/16/1f6ab.png\" style=\"height:16px; width:16px\" />საცოც ტერიტორიაზე არ დაიშვებიან უჩაფხუტო და არაფხიზელ მდგომარეობაში მყოფი სტუმრები.</p>\n\n<p>ღონისძიებაში მონაწილეობის მიღება შეუძლია ნებისმიერ მსურველს (16 წლამდე ასაკის მონაწილეს აუცილებელია ახლდეს მეურვე).</p>\n\n<p>დამატებითი ინფორმაციისთვის დაგვიკავშირდით :</p>\n', '<p><img alt=\"📞\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t4d/1/16/1f4de.png\" style=\"height:16px; width:16px\" />&nbsp;557 300 700 გუგა დაბრუნდაშვილი</p>\n\n<p><img alt=\"📞\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t4d/1/16/1f4de.png\" style=\"height:16px; width:16px\" />&nbsp;599 780 067 ლევან გოგოლაძე</p>\n\n<p><img alt=\"📩\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tc0/1/16/1f4e9.png\" style=\"height:16px; width:16px\" />&nbsp;<a href=\"mailto:adventurecampgeorgia@gmail.com\">adventurecampgeorgia@gmail.com</a></p>\n\n<p>&nbsp;</p>\n\n<p>საცოც რეგიონზე მეტი ინფორმაციის მისაღებად ეწვირთ გვერდს -&nbsp;<a href=\"https://climbing.ge/ka/outdoor/Climbing_In_Sveri(Chiatura)\">ცოცვა სვერში</a></p>\n', '2023-07-08 17:51:21', '2023-07-08 17:51:21'),
(29, 'ru', '.', '<p>.</p>\n', '<p>.</p>\n', '<p>.</p>\n', '2023-07-08 17:51:22', '2023-07-08 17:51:22'),
(30, 'us', 'Climbing Festival in Sveri', '<p>.</p>\n', '<p>On July 15 and 16, Sveri Adventure Camp and the National Rock Climbing Federation of Georgia is organizing climbing festival in Sveri. The event is supported by the Ministry of Culture, Sports and Youth of Georgia.</p>\n\n<p>Festival program:</p>\n\n<p>July 15</p>\n\n<p>17:00 &ndash; 23:00 Opening of the festival, camping, picnic, bonfire, music, games, entertainment, friendly and relaxing environment</p>\n\n<p>July 16</p>\n\n<p>Competition start: 12:00<br />\nEnd of the competition: 17:00<br />\nAward ceremony: 18:00<br />\nCeremonial closing of the festival: 19:00</p>\n\n<p>Description of the festival</p>\n\n<p>All climbers, both professionals and amateurs, can participate in the festival based on online registration. Participants are required to have experience in lead climbing. participants born in 2009 (13-14 years) and younger are not allowed to the festival.</p>\n\n<p><img alt=\"🧗‍♂️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t94/1/16/1f9d7_200d_2642.png\" style=\"height:16px; width:16px\" />&nbsp;It is mandatory for all participants to have their own equipment!!!<br />\nOn the location they will be provided with the participant card containing information up to 40 climbing lines. Completing line by the climber will be ranked only by a referee&rsquo;s signature.<br />\nDeadline for returning of the participant card is 17:00pm</p>\n\n<p><img alt=\"🏆\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tbe/1/16/1f3c6.png\" style=\"height:16px; width:16px\" />In female and male categories winners will be awarded according to the total score.</p>\n\n<p>Participants of the festival should register on the link below:<br />\n<img alt=\"👉\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t51/1/16/1f449.png\" style=\"height:16px; width:16px\" />&nbsp;<a href=\"https://l.facebook.com/l.php?u=https%3A%2F%2Fshorturl.at%2FFGIU1%3Ffbclid%3DIwAR3PkgueRkUHTp52HlaJUDIi0gEGg75X9DoDAFRUmavrUOTTzvcNMDQkojo&amp;h=AT1g0H6ZgpG-jLMguWrcnl9Z9DU48KEJYB9yiwLMDQ1SvwfLk2sY02N5NkeVKB7XyfUiKxLvLOrqjTSmofun35LLs6NR2NFdm-7OPZoSae3jLo7vNIA6nYBnyhgS&amp;__tn__=q&amp;c[0]=AT0hpi58AhdnqLmaWJFvza9g2tH1mtoHZmGOHTdokRr_2nzDz4FirfX3sGQFcfuuvjZJgKAet1yIdiFOHUfvwDC-zBvbeXv1YGYJpCTI18Y0MrNUWaPoMkm6fUaCoGNdAPAoTV7iUSy3wMLLbMf5e_xW7R6C\" target=\"_blank\">https://shorturl.at/FGIU1</a></p>\n\n<p>-------</p>\n\n<p>Deadline for the registration is 12 July, 2023.</p>\n\n<p>On the first day of the festival, July 15, the registered participant can arrive at the camp, for which the organizers will provide them with tent site, WC, shower and Wi-Fi for free (Transportation, tent equipment, and food are not included).</p>\n\n<p>During whole evening and festival day, Dj will play a music.</p>\n\n<p><img alt=\"🏆\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tbe/1/16/1f3c6.png\" style=\"height:16px; width:16px\" />&nbsp;The winners will be awarded with gifts and certificates.</p>\n\n<p><img alt=\"🚌\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t79/1/16/1f68c.png\" style=\"height:16px; width:16px\" />&nbsp;Registered participants of the festival, can use the minibuses scheduled by festival organizers on July 16, Tbilisi-Sveri-Tbilisi. Place of meeting Rose Square (Bicycle monument).</p>\n\n<p><img alt=\"✅\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t33/1/16/2705.png\" style=\"height:16px; width:16px\" />Gathering - 07:30<br />\n<img alt=\"✅\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t33/1/16/2705.png\" style=\"height:16px; width:16px\" />Departure from Tbilisi to Sveri -08:00<br />\n<img alt=\"✅\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t33/1/16/2705.png\" style=\"height:16px; width:16px\" />Departure from Sveri to Tbilisi- 19:00</p>\n\n<p>During the festival, participants will be provided with snacks.</p>\n\n<p>In the camp territory for the guests, there will be available soft and hot drinks as well as food products.</p>\n\n<p><img alt=\"☀️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6d/1/16/2600.png\" style=\"height:16px; width:16px\" /><img alt=\"☀️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6d/1/16/2600.png\" style=\"height:16px; width:16px\" /><img alt=\"☀️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6d/1/16/2600.png\" style=\"height:16px; width:16px\" /><img alt=\"☀️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6d/1/16/2600.png\" style=\"height:16px; width:16px\" /><img alt=\"☀️\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6d/1/16/2600.png\" style=\"height:16px; width:16px\" /></p>\n\n<p><img alt=\"🚫\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6f/1/16/1f6ab.png\" style=\"height:16px; width:16px\" />People in drunk condition and without helmets will not be allowed in climbing zone.</p>\n\n<p>Everyone can take part in the event (under 16 year, participants should be accompanied by official guardian).</p>\n\n<p>For more information, please contact:</p>\n', '<p><img alt=\"📞\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t4d/1/16/1f4de.png\" style=\"height:16px; width:16px\" />&nbsp;557 300 700 Guga Dabrundashvili</p>\n\n<p><img alt=\"📞\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t4d/1/16/1f4de.png\" style=\"height:16px; width:16px\" />&nbsp;599 780 067 Levan Gogoladze</p>\n\n<p><img alt=\"📩\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tc0/1/16/1f4e9.png\" style=\"height:16px; width:16px\" />&nbsp;<a href=\"mailto:adventurecampgeorgia@gmail.com\">adventurecampgeorgia@gmail.com</a></p>\n\n<p>&nbsp;</p>\n\n<p>For More information about climbing routes visit paga -&nbsp;<a href=\"https://climbing.ge/outdoor/Climbing_In_Sveri(Chiatura)\">Climbing In Sveri</a></p>\n', '2023-07-08 17:51:22', '2023-07-08 17:51:22'),
(31, 'ka', 'ცოცვის ფესტივალი სვერში 2023', '<p>.</p>\n', '<p>სეხტემბერში სოფელ სვერში ჩატარდება სპორტული ცოცვის ფესტივალი. მეტი ინფორმაცია დაემატება ღონისძიებამდე 2 კვირით ადრე.</p>\n', '', '2023-07-17 18:17:00', '2023-07-17 18:17:00'),
(32, 'ru', '.', '<p>.</p>\n', '<p>.</p>\n', '', '2023-07-17 18:17:00', '2023-07-17 18:17:00'),
(33, 'us', 'Climbing festival in Sveri 2023', '<p>.</p>\n', '<p>In september in sveri will be sport climbing festival. More information about event coming 2 week before event.</p>\n', '', '2023-07-17 18:17:00', '2023-07-17 18:17:00');
