(21, 'ka', 'საჭიდიs kit 2', '<p>საჭიდიs kit 2</p>', '<p>საჭიდიs kit 2</p>', NULL, '2021-08-26 05:27:10', '2021-08-26 05:29:13'),
(22, 'ka', 'საჭიდი 14', '<p>საჭიდი 14</p>\n', '<p>საჭიდი 14</p>\n', NULL, '2021-08-26 05:29:26', '2024-04-08 20:31:59'),
(23, 'ka', '1 საჭიდიანი ფინგერბორდი', '<p>.</p>\n', '<p>.</p>\n', 'ხე', '2021-08-26 05:31:39', '2025-10-01 23:15:41'),
(24, 'ka', 'საჭიდის ბოლტი', '<p>გამძლე ფოლადის, ხელოვნურ საცოც კედელზე საჭიდების მისაყენებელი ბოლტი ექსსფოთის თავით.</p>\n', '<p>გამძლე ფოლადის, ხელოვნურ საცოც კედელზე საჭიდების მისაყენებელი ბოლტი ექსსფოთის თავით, რაც მონტაჟსა და მოხსნას მარტივს ხდის<br />\nბოლტი იდეალურია T-Nuts-ებთან ერთად ხის დაფებზე გამოყენებისთვის და უზრუნველყოფს საიმედო დამაგრებას.</p>\n\n<p><strong>მთავარი მახასიათებლები:</strong></p>\n\n<ul>\n	<li>\n	<p><strong>მასალა:</strong> მაღალი გამძლეობის ფოლადი.</p>\n	</li>\n	<li>\n	<p><strong>დიზაინი:</strong> ექსსფოთის თავიანი ბოლტი მარტივი მონტაჟისა და მოხსნისთვის.</p>\n	</li>\n	<li>\n	<p><strong>თავსებადობა:</strong> შექმნილია T-Nuts-ებთან ხის დაფებზე.</p>\n	</li>\n	<li>\n	<p><strong>ფინიში:</strong> კოროზიისგან დამცავი ფენით.</p>\n	</li>\n</ul>\n\n<p>თუ აწყობ კლდეზე კედელს ან განაახლებ უკვე არსებულს, ეს ბოლტი გთავაზობს სანდოობას და შესანიშნავ შესრულებას.</p>\n', NULL, '2021-08-26 15:19:14', '2025-06-20 18:03:19'),
(25, 'ka', 'საჭიდი 15', '<p>საჭიდი 15</p>', '<p>საჭიდი 15</p>', NULL, '2021-08-26 15:27:18', '2021-08-26 15:30:29'),
(26, 'ka', 'საჭიდი 16', '<p>საჭიდი 16</p>\n', '<p>საჭიდი 16</p>\n', NULL, '2021-08-26 15:30:50', '2024-04-08 20:33:51'),
(27, 'ka', 'საჭიდი 17', '<p>საჭიდი 17</p>\n', '<p>საჭიდი 17</p>\n', NULL, '2021-08-26 15:37:50', '2024-04-08 20:35:02'),
(28, 'ka', 'ხის ხრახნი (პაუკი)', '<p>ცინკით დაფარული 4-კბილიანი ხის ხრახნი (პაუკი), ხელოვნურ საცოც კედელზე საჭდების მყარად დასამაგრებლად.</p>\n', '<p>ხელოვნურ საცოც კედელზე საჭდების მყარად დასამაგრებლად&nbsp;ხის ხრახნი (პაუკი). დამზადებულია ცინკით დაფარული ფოლადისგან და მათ აქვთ 4 კბილიანი დიზაინი, რომელიც მყარად ებჯინება ხის დაფას, უშლის მათ შემობრუნებას და უზრუნველყოფს სტაბილურ დაჭერას.</p>\n\n<p><strong>მთავარი მახასიათებლები:</strong></p>\n\n<ul>\n	<li>\n	<p><strong>მასალა:</strong> ზინკით დაფარული ფოლადი, რომელიც ასუსტებს კოროზიას და ამაღლებს გამძლეობას.</p>\n	</li>\n	<li>\n	<p><strong>დიზაინი:</strong> 4-კბილიანი კონფიგურაცია უზრუნველყოფს მყარ დასაჭერად ხის დაფაში.</p>\n	</li>\n	<li>\n	<p><strong>თავსებადობა:</strong> შექმნილია სტანდარტული კლდეზე საჭდების ბოლტებისთვის.</p>\n	</li>\n	<li>\n	<p><strong>მონტაჟი:</strong> მარტივად იწვება წინასწარ ჭრილ ხვრელში სწრაფი დამონტაჟებისთვის.</p>\n	</li>\n</ul>\n', NULL, '2021-08-26 15:41:06', '2025-06-20 17:52:26'),
(30, 'ka', 'საჭიდი 18', '<p>.</p>\n', '<p>.</p>\n', NULL, '2021-12-15 21:04:05', '2024-04-08 20:35:54'),
(31, 'ka', 'საჭიდი 19', '<p>.</p>', '<p>.</p>', NULL, '2021-12-15 21:15:11', '2021-12-15 21:20:34'),
(32, 'ka', 'საჭიდი 20', '<p>.</p>', '<p>.საშუალო ზომის ხელოვნური საჭიდები</p>\n\n<p>გამოიყენება საცოც დარბაზებში, ხელოვნურ კლდეებზე და სახლში ხელოვნურ კედელზე დასამაგრებლად და სავარჯიშოდ.</p>', NULL, '2021-12-15 21:20:52', '2022-05-06 14:48:01'),
(33, 'ka', 'საჭიდი 21', '<p>.</p>', '<p>ხელოვნური საჭიდები, საშუალო ზომის, ჩანაჭდევებით.</p>\n\n<p>გამოიყენება ხელოვნურ კლდეებზე, საცოც&nbsp;დარბაზებში, სახლში საცოც კედელზე დასამაგრებლად და სავარჯიშოდ.</p>', NULL, '2021-12-15 21:29:54', '2022-05-06 14:44:50'),
(34, 'ka', 'საჭიდების კომპლექტი 1', '<p>.</p>', '<p>ხელოვნური, ფერადი საჭიდების სეტი, დიდი &nbsp;ზომის, ღრმა&nbsp;&nbsp;ჯიბეებით. გამოიყენება ხელოვნურ კლდეზე დასამაგრებლად (საცოც დარბაზებში, ბაღებში, სკვერებში განთავსებულ ხელოვნურ კლდებზე, ასევე სახლში გაკეთებულ საცოც კედელზე).</p>', NULL, '2021-12-15 21:31:53', '2022-05-06 11:54:01'),
(35, 'ka', 'საჭიდების კომპლექტი 2', '<p>.</p>', '<p>ხელოვნური, ფერადი საჭიდების სეტი, პატარა ზომის. გამოიყენება ხელოვნურ კლდეზე დასამაგრებლად (საცოც დარბაზებში, ბაღებში, სკვერებში განთავსებულ ხელოვნურ კლდებზე, ასევე სახლში გაკეთებულ საცოც კედელზე).</p>', NULL, '2021-12-15 21:35:38', '2022-05-06 11:52:55'),
(36, 'ka', 'საჭიდების კომპლექტი 3', '<p>.</p>', '<p>ხელოვნური, ფერადი საჭიდების სეტი, დიდი და საშუალო ზომის და სიღრმის ჯიბეებით. გამოიყენება ხელოვნურ კლდეზე, საცოც დარბაზებში, ბაღებში, სკვერებში განთავსებულ ხელოვნურ კლდეებზე, ასევე სახლში გაკეთებულ საცოც კედელზე დასამაგრებლად და სავარჯიშოდ.</p>', NULL, '2021-12-16 20:39:23', '2022-05-06 11:50:07'),
(37, 'ka', 'საჭიდი 22', '<p>.</p>', '<p>წითელი ფერის, მოგრძო ფორმის, დიდი ზომის ხელოვნური საჭიდი.</p>\n\n<p>გამოიყენება დარბაზებში, ხელოვნურ კლდეებზე და სახლში გაკეთებულ საცოც კედლებზე დასამაგრებლად.</p>\n\n<p>მზადდება შეკვეთით</p>', NULL, '2021-12-16 20:41:51', '2022-05-06 11:48:18'),
(38, 'ka', 'საჭიდი 23', '<p>.</p>', '<p>მრგვალი ფორმის, პატარა ზომის ხელოვნური საჭიდი.</p>\n\n<p>გამოიყენება დარბაზებში, ხელოვნურ კლდეებზე და სახლში გაკეთებულ საცოც კედლებზე დასამაგრებლად.</p>\n\n<p>მზადდება შეკვეთით</p>', NULL, '2021-12-16 20:44:49', '2022-05-06 11:47:14'),
(39, 'ka', 'საჭიდი 24', '<p>.</p>\n', '<p>ლურჯი ფერის ხელოვნური საჭიდი, მცირედი ჩანაჭდევებით.</p>\n\n<p>გამოიყენება დარბაზებში, ხელოვნურ კლდეებზე და სახლში გაკეთებულ საცოც კედლებზე დასამაგრებლად.</p>\n\n<p>მზადდება შეკვეთით</p>\n', NULL, '2021-12-16 20:46:44', '2026-01-19 00:55:00'),
(40, 'ka', 'ძალიან პატარა საჭიდები 1', '<p>1 საჭიდის ღირებულება 2.5 ლარი</p>', '<p>პატარა ზომის ხელოვნური, ფერადი&nbsp; საჭიდები. გამოიყენება, ხელოვნურ კლდეზე დასამაგრებლად და საცოცად. ასეთ მცირე ზომის საჭიდებზე ვარჯიშისას კარგად ვითარდება თითების მომხრელი და გამშლელი კუნთები.</p>\n\n<p>მზადდება შეკვეთით</p>\n\n<p>&nbsp;</p>\n\n<p>1 საჭიდის ღირებულება 2.5 ლარი</p>', NULL, '2021-12-16 20:52:41', '2022-05-06 11:41:19'),
(41, 'ka', 'მაგნეზიის ტომარა', '<p>გამძლე და პრაქტიკული მაგნეზიის ჩანთა, ფართო ღიობით და კომფორტული ქამრით.</p>\n', '<p>მაგნმეზიის ჩანთა აუცილებელი აღჭურვილობაა კლდეზე ცოცვისთვის, რომელიც უზრუნველყოფს ხელების სიმშრალეს და უკეთეს მოჭერას. ჩანთა დამზადებულია გამძლე მასალისგან და აღჭურვილია ფართო ღიობით. რეგულირებადი ქამარი უზრუნველყოფს კომფორტულ და მყარ მორგებას. ზოგიერთი მოდელი შეიძლება შეიცავდეს დამატებით ჯიბეებს პირადი ნივთების შესანახად.</p>\n', NULL, '2022-02-07 21:09:14', '2025-06-20 17:47:18'),
(42, 'ka', 'თოკის ჩანთა', '<p>გამძლე და ფართო თოკის ჩანთა ზურგზე გადასაკიდი ქამრით და დამატებითი განყოფილებით.</p>\n', '<p>მოაწესრიგე და დაიცავი შენი თოკი და აღჭურვილობა ამ გამძლე თოკის ჩანთით. დამზადებულია მტკიცე, რიფსტოპ ნეილონისგან და გააჩნია ფართო ელვაშესაკრავი ღიობი, რაც ამარტივებს თოკის ჩალაგებასა და ამოღებას.</p>\n\n<p>ჩანთას აქვს რბილი ზურგზე გადასაკიდი ქამარი და გამაგრებული სახელური &mdash; კომფორტული ტრანსპორტირებისთვის, იქნება ეს დარბაზში წასვლა თუ კლდეზე გასვლა. შიგნით განთავსებულია ცალკე სექცია აღჭურვილობისთვის (მაგ. ქვიქდროები, ცარცი, პირადი ნივთები), ხოლო ბადის გვერდითი ჯიბეები წყლის ბოთლის ან საჭმლისათვისაა განკუთვნილი.</p>\n\n<p>წყალგაუმტარი ძირი იცავს შიგთავსს ტენიანი ზედაპირებისგან, იქნება ეს კლდის შელესილი პლატო თუ დარბაზის იატაკი.</p>\n\n<p>მცირე წონის მიუხედავად, ჩანთა შექმნილია ხანგრძლივი და მრავალმხრივი გამოყენებისთვის &mdash; იდეალურია ნებისმიერი კლაიმბერისთვის, ვინც აფასებს ორგანიზებულობას, გამძლეობასა და მოხერხებულობას.</p>\n\n<p>&nbsp;</p>\n', NULL, '2022-02-07 21:13:35', '2025-06-20 17:43:29'),
(43, 'ka', 'დაზღვევის სათვალე', '<p>პრიზმული ბილეის სათვალე &mdash; ამცირებს კისრის დაძაბვას და შეიცავს ქეისს და სამაგრს.</p>\n', '<p>იზრუნე შენს კომფორტზე დაცვაზე დგომის დროს ამ პრიზმული სათვალეებით. სამკუთხა პრიზმების მეშვეობით, ისინი გაძლევენ საშუალებას მაღლა იყურო ისე, რომ თავი ჩვეულად გეჭიროს &mdash; შენ იზოგავ კისერს და უფრო კონცენტრირებული ხარ ცოცვის პროცესზე.</p>\n\n<ul>\n	<li>\n	<p><strong>ერგონომიული კომფორტი</strong>: რბილი რეზინის ან პოლიკარბონატის ჩარჩოები მარტივად ერგება ცხვირს და ამცირებს წნევას ხანგრძლივი ბილეის დროს.</p>\n	</li>\n	<li>\n	<p><strong>მდგრადი პრიზმები</strong>: მაღალი ხარისხის BK7 ან მინის პრიზმები უზრუნველყოფს მკაფიო და არადამახინჯებულ ხედვას, თუნდაც მრავალჯერადი გამოყენების შემდეგ.</p>\n	</li>\n	<li>\n	<p><strong>სრული ხილვადობა</strong>: ცენტრალური ხედვის ზონა მუდმივად ფოკუსში ამყოფებს მძლავრელს, ხოლო გვერდითი ხედვა შენარჩუნებულია უსაფრთხოებისა და თოკის კონტროლისთვის.</p>\n	</li>\n	<li>\n	<p><strong>სრული კომპლექტი</strong>: შეიცავს მყარ ქეისს (ხშირად კარაბინით), რბილ ჩანთას, სამაგრსა და საწმენდ ჩვრებს &mdash; კომფორტული ტრანსპორტირებისა და მოვლისთვის.</p>\n	</li>\n	<li>\n	<p><strong>უფრო უსაფრთხო ბილეი</strong>: კისრის დაძაბვის გარეშე შენ უფრო ყურადღებიანი ხარ, რაც ზრდის ცოცვის უსაფრთხოებას და ეფექტურობას.</p>\n	</li>\n</ul>\n\n<p>იდეალურია დარბაზში ხანგრძლივი დაცვაზ დგომისას, ლიდზე მუშაობისთვის ან მულტი-პიჩ მარშრუტებისთვის. მცირედი მიჩვევის შემდეგ, ბევრი კლაიმბერი ამბობს, რომ ვეღარ ბილავენ სათვალის გარეშე.</p>\n', NULL, '2022-02-07 21:34:23', '2025-06-20 17:41:09'),
(44, 'ka', 'სახლში სავარჯიშო სტენდი', '<p>სახლში სავარჯიშო სტენდი</p>', '<p>სახლში სავარჯიშო ხის &nbsp;სტენდი &bdquo;ტურნიკით&ldquo;, რომელზეც მაგრედება როგორც&nbsp; სხვადასხვა ზომის ხელოვნური საჭიდები, ასევე &bdquo; ჰენგბორდი&rdquo;</p>\n\n<p>დაფის ზომა: 80x40x40 სმ</p>\n\n<p>&quot;ტურნიკის&quot; ზომა 80 სმ</p>\n\n<p>მზადდება შეკვეთით</p>\n\n<p>&nbsp;</p>', NULL, '2022-03-01 20:33:31', '2022-05-06 11:37:48'),
(45, 'ka', 'რელიეფები', '<p>საცოცი რელიეფების დამზადება</p>', '<p>საცოცი რელიეფების დამზადება შეკვეთით</p>', NULL, '2022-06-17 06:47:58', '2022-06-17 06:55:57'),
(101, 'ru', 'Birtvisi 2', '<p>dd</p>', '<pre>\nHANGBOARD - Упражнение для пальцев, доска с тремя надрезами разного размера. Развивает мышцы пальцев, предплечий, бицепсы, укрепляет запястья и укрепляет лучезапястные сухожилия.\nМатериал: дерево.\nРазмеры: 120X150 мм (глубина насечек 18 мм, 25 мм, 30 мм</pre>', NULL, '2021-03-02 21:05:28', '2022-05-06 14:36:29'),
(102, 'ru', 'Mono hengboard', '<p>.</p>', '<pre>\nMICRO HANGBOARD - Этот тренажер предназначен для упражнений одним пальцем. Это поможет вам тренировать отдельные пальцы рук и укреплять сухожилия. Лучший способ &mdash; тренироваться на отдельных пальцах.\nМатериал: дерево.\nРазмеры: 80X50 мм (диаметр отверстия 25 мм)</pre>', NULL, '2021-03-04 20:58:51', '2022-05-06 14:31:07'),
(103, 'ru', 'Climbing Power Pistons', '<p>.</p>', '<p>POWER PISTONS - Помогает тренировать запястья, предплечья и бицепсы.</p>\n\n<p>Материал: дерево.</p>\n\n<p>Размеры: 200X55 мм На заказ</p>', NULL, '2021-03-04 21:03:30', '2022-05-06 14:33:49'),
(104, 'ru', 'Climbing Brush', '<p>.</p>', '<p>Щетка для чистых зацепок</p>', NULL, '2021-03-04 21:07:14', '2021-03-04 21:10:47'),
(105, 'ru', 'Liquid Chalk For Climbing', '<p>.</p>', '<p>Что такое жидкий магнезия? Жидкий магнезия для лазания - это стандартный магнезия для лазания, смешанный с жидкостью - обычно в форме спирта - которая испаряется при контакте с воздухом. ... Как только это будет сделано, вы получите блестящий и ровный слой магнезии, который очень хорошо проникает в щели на ваших пальцах.</p>', NULL, '2021-03-04 21:11:24', '2021-03-04 21:15:25'),
(106, 'ru', 'Домашняя тренировочная зона', '<p>.</p>', '<p>Отдельно стоящая конструкция, к которой можно прикрепить фингерборд и другие аксессуары и с их помощью выполнять упражнения.</p>\n\n<p>Высота 240см.</p>', NULL, '2021-03-20 09:04:41', '2021-03-20 09:12:23'),
(107, 'ru', 'Зацепка 1', '<p>Малый зацеп для лазанья</p>\n', '<p>Малый зацеп для лазанья</p>\n', NULL, '2021-05-07 18:48:43', '2024-04-07 00:14:59'),
(108, 'ru', 'Зацепка 1', '<p>Малый зацепка&nbsp;для лазанья</p>\n', '<p>Малый зацепка&nbsp;для лазанья</p>\n', NULL, '2021-05-07 18:52:56', '2024-04-07 00:37:22'),
(109, 'ru', 'зацепка 3', '<p>зацепка&nbsp;для лазанья</p>\n', '<p>зацепка&nbsp;для лазанья</p>\n', NULL, '2021-05-19 19:38:24', '2024-04-07 00:38:36'),
