(201, 'us', 'Handboard', '<p>.</p>\n', '<p>HANGBOARD- A finger exercise, a hangboard with three different sized incisions. Develops the muscles of the fingers, forearms, biceps, strengthens the wrists and strengthens the wrist tendons.<br />\nMaterial: wood.<br />\nDimensions: 120X150 mm (depth of incisions 18 mm, 25 mm, 30 mm</p>\n', NULL, '2021-03-02 21:05:28', '2024-12-17 01:44:04'),
(202, 'us', 'Mono hengboard', '<p>.</p>\n', '<p>MICRO HANGBOARD - This simulator is designed for one-finger exercises. It will help you to exercise the individual fingers of the hand and strengthen the tendons. The best way is to practice lifting on individual fingers.<br />\nMaterial: wood.<br />\nDimensions: 80X50 mm (hole diameter 25 mm)</p>\n', NULL, '2021-03-04 20:58:51', '2025-10-01 23:03:45'),
(203, 'us', 'Climbing Power Pistons', '<p>.</p>', '<p>POWER PISTONS - Helps you train your wrists, forearms and biceps.</p>\n\n<p>Material: wood.</p>\n\n<p>Dimensions: 200X55 mm</p>\n\n<p>Made to order</p>', NULL, '2021-03-04 21:03:30', '2022-05-06 14:28:35'),
(204, 'us', 'Climbing Brush', '<p>Durable climbing brush with ergonomic handle, ideal for cleaning holds and removing excess chalk.</p>\n', '<p>The Climbing Brush is designed to effectively clean climbing holds by removing excess chalk and debris. Its ergonomic handle ensures a comfortable grip during use, while the durable bristles provide thorough cleaning without damaging the holds. Whether you&#39;re training indoors or tackling outdoor routes, this brush is an essential tool for maintaining optimal grip and performance.</p>\n', NULL, '2021-03-04 21:07:14', '2025-06-20 18:18:03'),
(205, 'us', 'Liquid Chalk For Climbing', '<p>Alcohol-based liquid chalk that enhances grip and reduces mess during climbing sessions</p>\n', '<p>This liquid chalk is designed to improve grip and reduce hand moisture during climbing. Its alcohol-based formula dries quickly, leaving a thin layer of chalk that enhances friction between your hands and climbing holds. Ideal for both indoor and outdoor climbing, it minimizes mess and is particularly beneficial for gyms that have restrictions on loose chalk.</p>\n\n<p><strong>Key Features:</strong></p>\n\n<ul>\n	<li>\n	<p><strong>Enhanced Grip:</strong> Improves friction for better control on climbing holds.</p>\n	</li>\n	<li>\n	<p><strong>Quick Drying:</strong> Dries rapidly to provide immediate benefits.</p>\n	</li>\n	<li>\n	<p><strong>Mess Reduction:</strong> Minimizes chalk dust and residue.</p>\n	</li>\n	<li>\n	<p><strong>Hygienic:</strong> Alcohol content helps in sanitizing hands.</p>\n	</li>\n	<li>\n	<p><strong>Eco-Friendly:</strong> Reduces environmental impact compared to traditional chalk.</p>\n	</li>\n</ul>\n\n<p>Whether you&#39;re a beginner or an experienced climber, this liquid chalk offers a convenient and effective solution to enhance your climbing experience.</p>\n', NULL, '2021-03-04 21:11:24', '2025-06-20 18:16:04'),
(206, 'us', 'Home training zone', '<p>Modular climbing wall system for personalized home training, adaptable to various skill levels.</p>\n', '<p>The Home Training Zone is a versatile climbing wall system designed for indoor use.</p>\n\n<p><strong>Key Features:</strong></p>\n\n<ul>\n	<li>\n	<p><strong>Modular Design:</strong> Allows for customizable setups to fit available space and training needs.</p>\n	</li>\n	<li>\n	<p><strong>High-Quality Materials:</strong> Constructed with durable materials to withstand rigorous training sessions.</p>\n	</li>\n	<li>\n	<p><strong>Compact Footprint:</strong> Designed to maximize training space without occupying excessive room.</p>\n	</li>\n</ul>\n\n<p>Whether you&#39;re a beginner aiming to build foundational strength or an advanced climber seeking to refine techniques, the Home Training Zone provides a flexible and effective solution for indoor climbing training.</p>\n', NULL, '2021-03-20 09:04:41', '2025-06-20 18:10:06'),
