(250, 'ka', 'დინამიური თოკი (RGRD9.7)', '<p>წყალგაუმტარი საცოცი თოკი</p>\n', '<p>ტიპი: წყალგაუმტარი დინამიური თოკი</p>\n\n<p>სისქე: 9.7 მმ</p>\n\n<p>დანიშნულება: იდეალურია როგორც სპორტული ცოცვისთვის, ასევე ალპინიზმისთვის.</p>\n\n<p>პროდუქტის დეტალები: დამატებითი ტექნიკური მახასიათებლების სანახავად ეწვიეთ&nbsp;<a href=\"https://ridgegear.com/product/9-7mm-dynamic-rope/\">ოფიციალურ საიტს</a></p>\n', '', NULL, '2026-01-28 03:31:32'),
(251, 'us', 'Dynamic Rope (RGRD9.7)', '<p>Waterproof Dynamic Rope</p>\n', '<p>Type: Waterproof Dynamic Rope</p>\n\n<p>Diameter: 9.7 mm</p>\n\n<p>Best For: Ideal for both sport climbing and mountaineering.</p>\n\n<p>Product Details: For more technical specifications, visit the&nbsp;<a href=\"https://ridgegear.com/product/9-7mm-dynamic-rope/\">official website</a>.</p>\n', '', NULL, '2026-01-28 03:31:32'),
(252, 'ka', 'თავისუფლად მდგომი საცოცი კედელი (4.5x4.5 მეტრი, 35 გრადუსი)', '<p>.</p>\n', '<p>.</p>\n', '', NULL, '2026-05-14 16:29:34'),
(253, 'us', 'Stand free climbing wall (4.5x4.5 Meters, 35 Degree )', '<p>.</p>\n', '<p>.</p>\n', '', NULL, '2026-05-14 16:29:34'),
(254, 'ka', 'სადგომი', '<p>.</p>\n', '<p><strong>Handstand Push-Up Stand &ndash; ტრიპოდის სტენდი</strong></p>\n\n<p>მტკიცე და სტაბილური სტენდი, რომელიც შექმნილია <strong>handstand push-up-ისა და tripod პოზიციის სავარჯიშოდ</strong>. ეს მოწყობილობა სპორტსმენებს ეხმარება სწორ პოზიციაში ვარჯიშის დროს, რაც აუმჯობესებს ბალანსს, ძალას და კონტროლს.</p>\n\n<p>ტრიპოდის კონსტრუქცია ქმნის სტაბილურ სამკუთხედს თავსა და ხელებს შორის, რაც უზრუნველყოფს უსაფრთხო ვარჯიშს <strong>handstand push-up პოზიციაში</strong>. Handstand push-up არის რთული სხეულის წონაზე დაფუძნებული ვარჯიში, რომელიც ამაგრებს მხრებს, ხელებსა და კორს.</p>\n\n<p>ეს სტენდი იდეალურია <strong>კალისთენიქსის, ტანვარჯიშის, CrossFit-ის და handstand ვარჯიშებისთვის</strong>. ის საშუალებას გაძლევთ უსაფრთხოდ განავითაროთ მხრების სტაბილურობა და ზედა სხეულის ძალა.</p>\n\n<h3>მახასიათებლები</h3>\n\n<ul>\n	<li>\n	<p>სტაბილური ტრიპოდის დიზაინი უსაფრთხო ვარჯიშისთვის</p>\n	</li>\n	<li>\n	<p>უზრუნველყოფს ხელებისა და თავის სწორ პოზიციას</p>\n	</li>\n	<li>\n	<p>აუმჯობესებს ბალანსს, ძალას და კონტროლს</p>\n	</li>\n	<li>\n	<p>იდეალურია კალისთენიქსისა და ძალოვანი ვარჯიშისთვის</p>\n	</li>\n	<li>\n	<p>გამძლე და მტკიცე კონსტრუქცია</p>\n	</li>\n</ul>\n\n<h3>გამოყენება</h3>\n\n<ul>\n	<li>\n	<p>Handstand push-up ვარჯიში</p>\n	</li>\n	<li>\n	<p>Tripod headstand პოზიციის ვარჯიში</p>\n	</li>\n	<li>\n	<p>ბალანსისა და კონტროლის გაუმჯობესება</p>\n	</li>\n	<li>\n	<p>მხრებისა და ზედა სხეულის გაძლიერება</p>\n	</li>\n</ul>\n', '', NULL, '2026-03-10 22:56:03'),
(255, 'us', 'Handstand Push-Up Stand Tripod Holder', '<p>Handstand Push-Up Stand Tripod Holder</p>\n', '<p><strong>Handstand Push-Up Stand &ndash; Tripod Holder</strong></p>\n\n<p>A strong and stable stand designed for practicing <strong>handstand push-ups and tripod training</strong>. This holder helps athletes maintain proper positioning while performing inverted exercises, improving balance, strength, and control.</p>\n\n<p>The tripod structure creates a stable base for the head and hands, helping athletes safely train the <strong>handstand push-up position</strong>. Handstand push-ups are an advanced bodyweight exercise that builds powerful shoulders, arms, and core strength.</p>\n\n<p>This stand is perfect for <strong>calisthenics athletes, gymnasts, CrossFit practitioners, and handstand training</strong>. It allows you to train safely while developing shoulder stability and upper-body power.</p>\n\n<h3>Features</h3>\n\n<ul>\n	<li>\n	<p>Stable tripod design for safe handstand push-up training</p>\n	</li>\n	<li>\n	<p>Supports correct head and hand positioning</p>\n	</li>\n	<li>\n	<p>Helps improve balance, strength, and control</p>\n	</li>\n	<li>\n	<p>Ideal for calisthenics, gymnastics, and strength training</p>\n	</li>\n	<li>\n	<p>Durable and stable construction</p>\n	</li>\n</ul>\n\n<h3>Use For</h3>\n\n<ul>\n	<li>\n	<p>Handstand push-ups</p>\n	</li>\n	<li>\n	<p>Tripod headstand training</p>\n	</li>\n	<li>\n	<p>Balance and control exercises</p>\n	</li>\n	<li>\n	<p>Shoulder and upper-body strength training</p>\n	</li>\n</ul>\n', '', NULL, '2026-03-10 22:56:03'),
(256, 'ka', 'თეიფი', '<p>თეიფი</p>\n', '<p>თეიფი</p>\n', '', NULL, '2025-10-10 15:12:51'),
(257, 'us', 'Climbing Tape', '<p>Climbing Tape</p>\n', '<p>Climbing Tape</p>\n', '', NULL, '2025-10-15 14:35:27'),
(258, 'ka', 'ფინგერბორდი \"ერთი\"', '<p>.</p>\n', '<p>Fingerboard &quot;one&quot; &ndash; მეკლდეურის სავარჯიშო დაფა</p>\n\n<p>გააუმჯობესეთ თქვენი ცოცვის შედეგები Fingerboard &quot;one&quot;-ის დახმარებით. ეს არის პროფესიონალური სავარჯიშო ინსტრუმენტი, რომელიც სპეციალურად შექმნილია თითების სიძლიერის, ჩაჭიდების გამძლეობისა და ზედა ტანის კუნთების გასავითარებლად. იგი იდეალურია როგორც სახლში სავარჯიშოდ, ასევე კლდეზე გასვლის წინ მოსახურებლად.</p>\n\n<p>ძირითადი მახასიათებლები:</p>\n\n<p>მიზნობრივი ვარჯიში: შექმნილია თითების მყესებისა და წინამხრის კუნთების იზოლირებული ვარჯიშისთვის, რაც დაგეხმარებათ რთული მარშრუტების დაძლევაში.</p>\n\n<p>მაღალი ხარისხის მასალა: დამზადებულია გამძლე და კანისთვის სასიამოვნო ხისგან, რომელიც უზრუნველყოფს ბუნებრივ მოჭიდებას და ამცირებს კანის გაღიზიანებას ხანგრძლივი ვარჯიშისას.</p>\n\n<p>კომპაქტური და პორტაბელური: დახვეწილი დიზაინის წყალობით, მისი დამონტაჟება მარტივია სახლის პირობებში, ხოლო კომპაქტურობა საშუალებას გაძლევთ თან ატაროთ ნებისმიერ ადგილას.</p>\n\n<p>მრავალფეროვანი ჩაჭიდებები: მოიცავს სხვადასხვა სიღრმის კიდეებსა და ზედაპირებს, რაც მას შესაფერისს ხდის როგორც დამწყები, ისე პროფესიონალი მეკლდეურებისთვის.</p>\n\n<p>ადგილობრივი წარმოება: წარმოადგენს Climbing In Georgia-ს პროექტის ნაწილს და შექმნილია საქართველოში, ადგილობრივი მეკლდეურების გამოცდილების გათვალისწინებით.<br />\n<br />\nზომა 50 სმ X 15 სმ</p>\n\n<ul>\n	<li>\n	<p>სამი <strong>4-თითიანი ჯიბე</strong>: 16 მმ, 20 მმ, 25 მმ, 35მმ</p>\n	</li>\n	<li>\n	<p>ორი <strong>3-თითიანი ჯიბე</strong>: 20 მმ, 25 მმ</p>\n	</li>\n	<li>\n	<p>ერთი <strong>2-თითიანი ჯიბე</strong>: 20 მმ</p>\n	</li>\n	<li>\n	<p>ერთი <strong>მონო ჯიბე (1 თითი)</strong>: 20 მმ</p>\n	</li>\n</ul>\n', 'ხე', NULL, '2026-03-10 22:33:16'),
(259, 'us', 'Fingerboard \"one\"', '<p>.</p>\n', '<p>Fingerboard &quot;one&quot; &ndash; Essential Climbing Training Tool</p>\n\n<p>Elevate your climbing performance with the Fingerboard &quot;one&quot;, a professional-grade training tool designed specifically for climbers looking to improve finger strength, grip endurance, and upper body power. Whether you are warming up at the crag or training at home, this compact and versatile hangboard is an essential addition to any climber&#39;s routine.</p>\n\n<p>Key Features:</p>\n\n<p>Targeted Training: Designed to isolate and strengthen finger tendons and forearm muscles, helping you conquer more challenging routes.</p>\n\n<p>High-Quality Material: Crafted from durable, skin-friendly wood that provides a natural grip and reduces the risk of skin irritation during long sessions.</p>\n\n<p>Compact &amp; Portable: Its sleek design makes it easy to mount at home or carry in your gym bag for on-the-go training.</p>\n\n<p>Versatile Holds: Features a variety of edge depths and grip types to accommodate all skill levels, from beginners to advanced athletes.</p>\n\n<p>Locally Crafted: Proudly part of the Climbing In Georgia project, supporting the local climbing community.</p>\n\n<p>Size 50 cm X 15 cm</p>\n\n<ul>\n	<li>\n	<p>Three <strong>4-finger pockets</strong>: 16 mm, 20 mm, 25 mm, 35 mm</p>\n	</li>\n	<li>\n	<p>Two <strong>3-finger pockets</strong>: 20 mm, 25 mm</p>\n	</li>\n	<li>\n	<p>One <strong>2-finger pocket</strong>: 20 mm</p>\n	</li>\n	<li>\n	<p>One <strong>mono pocket (1 finger)</strong>: 20 mm</p>\n	</li>\n</ul>\n\n<p>&nbsp;</p>\n', 'Wood', NULL, '2026-03-10 22:33:16'),
(260, 'ka', 'სამოგზაურო ფინგერბორდი', '<p>.</p>\n', '<p><strong>სამოგზაურო ფინგერბორდი</strong></p>\n\n<p>კომპაქტური და მსუბუქი სამოგზაურო ფინგერბორდი, რომელიც იდეალურია ცოცვამდე თითების გასახურებლად ან თითების ძალის სავარჯიშოდ. შეგიძლიათ გამოიყენოთ კლდეზე, დარბაზში ან სახლში.</p>\n\n<p>ფინგერბორდს აქვს სხვადასხვა სიღრმის ჯიბეები, რაც საშუალებას გაძლევთ ავარჯიშოთ სხვადასხვა ტიპის გრიფები და გააძლიეროთ თითების და წინამხრის კუნთები. მისი პორტატული დიზაინი საშუალებას იძლევა მარტივად დაკიდოთ ტურნიკზე, ხის ტოტზე, ბოლტზე ან სხვა მყარ საყრდენზე.</p>\n\n<p>იდეალურია ცოცვის წინ გასახურებლად და რეგულარული სავარჯიშოებისთვის.</p>\n\n<h3>ჯიბეების სიღრმე</h3>\n\n<ul>\n	<li>\n	<p>2 &times; 25 მმ ჯიბე</p>\n	</li>\n	<li>\n	<p>2 &times; 16 მმ ჯიბე</p>\n	</li>\n	<li>\n	<p>1 &times; შუა ჯიბე &ndash; 25 მმ</p>\n	</li>\n</ul>\n\n<h3>მახასიათებლები</h3>\n\n<ul>\n	<li>\n	<p>პორტატული და მსუბუქი დიზაინი</p>\n	</li>\n	<li>\n	<p>იდეალურია გასახურებლად და თითების ძალის გასაძლიერებლად</p>\n	</li>\n	<li>\n	<p>სხვადასხვა სიღრმის ჯიბეები სხვადასხვა გრიფისთვის</p>\n	</li>\n	<li>\n	<p>შესაფერისია დამწყები და გამოცდილი კლაიმბერებისთვის</p>\n	</li>\n	<li>\n	<p>შესაძლებელია გამოყენება როგორც შიგნით, ასევე გარეთ</p>\n	</li>\n</ul>\n', 'ხე', NULL, '2026-03-10 22:48:59'),
(261, 'us', 'Fingerboard For Traveling', '<p>.</p>\n', '<p><strong>Travel Fingerboard &ndash; Portable Climbing Training Board</strong></p>\n\n<p>A compact and lightweight travel fingerboard designed for climbers who want to warm up or train anywhere. Perfect for use at the crag, gym, or at home, this board helps develop finger strength, grip power, and forearm endurance.</p>\n\n<p>The board features several pocket depths for different difficulty levels, allowing climbers to train multiple grip types and improve finger control. Its portable design makes it easy to hang on a pull-up bar, tree branch, bolt, or any strong anchor point.</p>\n\n<p>Ideal for warming up before climbing or for regular finger training sessions.</p>\n\n<h3>Pocket Depths</h3>\n\n<ul>\n	<li>\n	<p>2 &times; 25 mm pockets</p>\n	</li>\n	<li>\n	<p>2 &times; 16 mm pockets</p>\n	</li>\n	<li>\n	<p>1 &times; middle pocket &ndash; 25 mm</p>\n	</li>\n</ul>\n\n<h3>Features</h3>\n\n<ul>\n	<li>\n	<p>Portable and lightweight design</p>\n	</li>\n	<li>\n	<p>Perfect for warm-ups and finger strength training</p>\n	</li>\n	<li>\n	<p>Multiple pocket depths for different grip styles</p>\n	</li>\n	<li>\n	<p>Suitable for beginners and advanced climbers</p>\n	</li>\n	<li>\n	<p>Can be used indoors or outdoors</p>\n	</li>\n</ul>\n', 'Wood', NULL, '2026-03-10 22:48:59'),
(262, 'ka', 'მაგნეზია', '<p>პრემიუმ კლასის 55 გრამიანი მაგნეზიის კუბიკი&mdash; იდეალურია მოჭიდების გასაუმჯობესებლად და ტენიანობის შესამცირებლად.</p>\n', '<p>აიმაღლე მოჭიდების დონე ჩვენი 55 გრამიანი პრემიუმ მაგნეზიით. სპეციალურად შექმნილია ტენიანობის შესაწოვად და ცურების თავიდან ასაცილებლად &mdash; ინარჩუნებს ხელებს მშრალად და დაცულად ნებისმიერი მოძრაობისას. შესაფერისია როგორც დამწყებისთვის, ისე პროფესიონალი კლაიმბერებისთვის. კომპაქტური ფორმა უზრუნველყოფს მარტივ ტრანსპორტირებას და ხანგრძლივ მოხმარებას.</p>\n\n<ul>\n	<li>\n	<p><strong>ოპტიმალური ზომა და წონა</strong>: თითოეული ბლოკი 55 გრამს იწონის &mdash; საკმარისად მსუბუქი ჩანთისთვის, მაგრამ გამძლე ხანგრძლივი გამოყენებისთვის.</p>\n	</li>\n	<li>\n	<p><strong>ტენიანობის ეფექტური კონტროლი</strong>: ეფექტურად შთანთქავს ოფლს, აუმჯობესებს მოჭიდებას და ამცირებს ხელახლა წასმის საჭიროებას.</p>\n	</li>\n	<li>\n	<p><strong>უნივერსალური გამოყენება</strong>: შესაძლებელია როგორც ცალკე, ასევე თხევად ცარცთან ერთად გამოყენება მაქსიმალური სიმშრალის მისაღებად.</p>\n	</li>\n	<li>\n	<p><strong>ეკონომიური არჩევანი</strong>: ფასი მერყეობს 10&ndash;დან 75 ლარამდე &mdash; შეარჩიე მოცულობა შენი ვარჯიშის სტილზე მორგებით.</p>\n	</li>\n</ul>\n\n<p>იქნება ეს დარბაზში ვარჯიში თუ ღია სივრცეში კლდეზე ცოცვა &mdash; ეს ცარცი შენს ხელებს ყოველთვის საიმედოდ დაგიჭერს.</p>\n', '', NULL, '2025-06-20 17:21:06'),
(263, 'us', 'Chalk', '<p>Premium 55 g climbing chalk&mdash;perfect for improving grip and reducing moisture during your sessions. Compact, reliable, and ready to boost your climbing performance.</p>\n', '<p>Take your grip to the next level with our 55 g premium climbing chalk. Specifically formulated to absorb moisture and prevent slips, it keeps your hands dry and secure from the first hold to the last. Ideal for all levels of climbers, this compact chalk is easy to carry and lasts through intense sessions.</p>\n\n<ul>\n	<li>\n	<p><strong>Optimal size &amp; weight</strong>: Each block is 55 g&mdash;lightweight enough for your chalk bag.</p>\n	</li>\n	<li>\n	<p><strong>Superior moisture control</strong>: Effectively wicks away sweat, enhancing friction and reducing the need for reapplication.</p>\n	</li>\n	<li>\n	<p><strong>Universal compatibility</strong>: Use standalone or combine with liquid chalk for maximum dryness.</p>\n	</li>\n	<li>\n	<p><strong>Economical</strong>: Priced between 10 ₾ and 75 ₾ depending on quantity&mdash;choose the size that fits your climbing routine <a href=\"https://shop.climbing.ge/products?utm_source=chatgpt.com\" target=\"_blank\">shop.climbing.ge+1shop.climbing.ge+1</a>.</p>\n	</li>\n</ul>\n\n<p>Whether you&#39;re training indoors or tackling a rocky crag, this chalk delivers consistent reliability when your hands matter most.</p>\n', '', NULL, '2025-12-14 17:21:39'),
(266, 'ka', 'მაგნეზიის ტომარა', '<p>საცოცი ტომარა მაგნეზიისთვის</p>\n', '<p>საცოცი ტომარა მაგნეზიის ჩასაყრელად</p>\n', '', NULL, NULL),
(267, 'us', 'Chalk Bag ', '<p>Climbing Chalk Bag&nbsp;</p>\n', '<p>Climbing Chalk Bag</p>\n', '', NULL, NULL),
(268, 'ka', 'მაგნეზიის ტომარა', '<p>საცოცი ტომარა მაგნეზიისთვის</p>\n', '<p>საცოცი ტომარა მაგნეზიის ჩასაყრელად</p>\n', '', NULL, NULL),
(269, 'us', 'Chalk Bag ', '<p>Climbing Chalk Bag&nbsp;</p>\n', '<p>Climbing Chalk Bag</p>\n', '', NULL, NULL),
(272, 'ka', 'თოკის ჩანთა', '<p>საცოცი თოკის ჩანთა</p>\n', '<p>ჩანთა საცოცი თოკისთვის</p>\n', '', NULL, NULL),
(273, 'us', 'Climbing Rope Bag', '<p>Climbing Rope Bag</p>\n', '<p>Bag For&nbsp;Climbing Rope</p>\n', '', NULL, NULL);
INSERT INTO `locale_products` (`id`, `locale`, `title`, `short_description`, `text`, `material`, `created_at`, `updated_at`) VALUES
(274, 'ka', 'ზვიგენი მაგნეზიის ჩანთა', '<p>ზვიგენის ფორმის მაგნეზიის ჩანთა ფართო ღიობით, ჯაგრისის დამჭერით და ქამრით.</p>\n', '<p>ზვიგენის ფორმის მაგნეზიის ჩანთა &mdash; სტილური და ფუნქციური აქსესუარი მეკლდეურობისთვის, რომელიც გათვლილია როგორც დარბაზში, ისე გარეთ საცოცად. ჩანთა დამზადებულია გამძლე პოლიესტერისგან და გამოირჩევა playful დიზაინით &mdash; ლამაზად ფორმირებული ზვიგენის სახით და მიმზიდველი ცისფერი ტონალობით, რაც კლაიმბერებს ყველა ასაკში იზიდავს.</p>\n\n<ul>\n	<li>\n	<p><strong>ფართო 12 სმ-იანი ღიობი</strong> უზრუნველყოფს ცარცზე სწრაფ და მარტივ წვდომას მოძრაობებს შორის.</p>\n	</li>\n	<li>\n	<p><strong>ელასტიური შემკვრელი თოკი</strong> იცავს ცარცს დაყრისგან, მოძრაობისასაც კი.</p>\n	</li>\n	<li>\n	<p><strong>ჩაშენებული ჯაგრისის დამჭერი</strong> გაძლევს საშუალებას გაწმინდო ბლოკი სწრაფად და მარტივად.</p>\n	</li>\n	<li>\n	<p><strong>რეგულირებადი ქამარი</strong> უზრუნველყოფს კომფორტულ და მყარ მორგებას სრული თავისუფალი მოძრაობით.</p>\n	</li>\n	<li>\n	<p><strong>გამძლე პოლიესტერის კონსტრუქცია</strong>, დაახლოებით 120 გრამი წონა, მორგებული ხანგრძლივ გამოყენებაზე სხვადასხვა გარემოში.</p>\n	</li>\n</ul>\n', '', NULL, '2025-06-20 17:35:01'),
(275, 'us', 'Shark Climbing Chalk Bag', '<p>Striking shark‑shaped chalk bag with wide opening, brush holder, drawstring, and adjustable waist strap.</p>\n', '<p>Dive into adventure with the Shark Climbing Chalk Bag&mdash;a stylish, functional gear piece designed for both gym and outdoor climbs. Crafted from durable polyester, this bag stands out with its playful shark silhouette and bold blue hue that appeals to climbers of all ages&nbsp;</p>\n\n<ul>\n	<li>\n	<p><strong>Wide 12 cm opening</strong> ensures swift chalk access, even between tough moves&nbsp;</p>\n	</li>\n	<li>\n	<p><strong>Elastic drawstring closure</strong> keeps chalk securely inside, preventing spills during movement&nbsp;</p>\n	</li>\n	<li>\n	<p><strong>Integrated brush holder</strong> allows you to clean holds mid-route without fumbling&nbsp;</p>\n	</li>\n	<li>\n	<p><strong>Adjustable waist belt</strong> offers a comfortable fit and full freedom of movement&nbsp;</p>\n	</li>\n	<li>\n	<p><strong>Robust polyester construction</strong>, weighing only around 120 g, built to endure repeated use in varied environments&nbsp;</p>\n	</li>\n</ul>\n\n<p>Whether you&#39;re scaling indoor walls or tackling cliffs, this Shark Chalk Bag blends personality and practicality&mdash;bringing both fun and function to every climb.</p>\n', '', NULL, '2025-06-20 17:36:27'),
(276, 'ka', 'დათვი მაგნეზიის ტომარა', '<p>მხიარული და ფუნქციური დათუნიას ფორმის მაგნეზიის ჩანთა &mdash; იდეალურია როგორც დარბაზში, ისე კლდეზე ცოცვისას.</p>\n', '<p>გაათავისუფლე შენი შინაგანი ძალა Bear Climbing Chalk Bag-ით &mdash; შენი სანდო კომპანიონი, რომელიც აერთიანებს playful დიზაინს და პროფესიონალურ ფუნქციურობას. ჩანთა დაახლოებით 12 სმ სიმაღლისაა და დამზადებულია გამძლე პოლიესტერისგან, რათა გაუძლოს ხშირი გამოყენებისას როგორც დარბაზში, ასევე კლდეზე. ფართო &mdash; 12 სმ დიამეტრის &mdash; ღიობით ცარცზე წვდომა ადვილი და სწრაფია, ხოლო მჭიდრო შესაკრავი ხელს უშლის ცარცის დაქუცმაცებას ან დაყრას. ჩაშენებული ჯაგრისის დამჭერი გაძლევს საშუალებას გაწმინდო ბლოკი ნებისმიერ მომენტში, ხოლო რეგულირებადი ქამარი უზრუნველყოფს კომფორტულ და მყარ მოთავსებას.</p>\n\n<p>იდეალურია ნებისმიერი დონის კლაიმბერებისთვის, ვისაც სურს გამორჩეული და ეფექტური აღჭურვილობა. იქნება ეს დარბაზში ტექნიკური ბლოკის გადალახვა თუ ღია სივრცეში გამბედავი მარშრუტების გაგზავნა &mdash; ეს ცარცის ჩანთა დაგეხმარება სტილში და საიმედოდ!</p>\n', '', NULL, '2025-06-20 17:28:50'),
(277, 'us', 'Bear Climbing Chalk Bag', '<p>A charming and functional Bear-themed chalk bag &mdash; perfect for boosting performance on both indoor and outdoor climbs</p>\n', '<p>Unleash your inner strength with the Bear Climbing Chalk Bag&mdash;a faithful companion that combines playful design with serious climbing functionality. Standing around 12 cm tall, this bag is crafted from robust polyester to withstand frequent use in gyms or at crags. Its spacious 12 cm‑diameter opening ensures easy chalk access, while a secure drawstring keeps spills at bay. An integrated brush-holder lets you tidy your holds mid‑route, and an adjustable waist strap ensures a snug, comfortable fit.</p>\n\n<p>Ideal for climbers of all levels who appreciate gear that stands out, this chalk bag brings both style and practicality to your climbing kit. Whether you&#39;re tackling technical indoor problems or sending bold outdoor lines, it offers reliable performance and a cute companion you&rsquo;ll love.</p>\n', '', NULL, '2025-06-20 17:28:51'),
(278, 'ka', 'LED პორტატული სპორტული ფარანი', '<p>LED პორტატული სპორტული ფარანი</p>\n', '<p>LED პორტატული სპორტული ფარანი</p>\n', '', NULL, NULL),
(279, 'us', 'LED Portable Outdoor Sports Headlamp', '<p>LED Portable Outdoor Sports Headlamp</p>\n', '<p>LED Portable Outdoor Sports Headlamp</p>\n', '', NULL, NULL),
(280, 'ka', 'LED პორტატული სპორტული ფარანი', '<p>LED პორტატული სპორტული ფარანი</p>\n', '<p>LED პორტატული სპორტული ფარანი</p>\n', '', NULL, NULL),
