(283, 'us', 'LED Portable Outdoor Sports Headlamp', '<p>LED Portable Outdoor Sports Headlamp</p>\n', '<p>LED Portable Outdoor Sports Headlamp</p>\n', '', NULL, NULL),
(284, 'ka', 'მინი თერმომეტრი + კომპასი', '<p>მინი თერმომეტრი + კომპასი</p>\n', '<p>მინი თერმომეტრი + კომპასი</p>\n', '', NULL, NULL),
