INSERT INTO `locale_services` (`id`, `locale`, `title`, `short_description`, `text`, `created_at`, `updated_at`) VALUES
(1, 'ka', 'სასიმაღლო სამუშაოები', '<p>სიმაღლეზე სამუშაოები მთელი საქართველოს მაშტაბით</p>\n', '<p>&nbsp;სასომაღლო სმუშაოები მაღალი საფრთხის შემცველი სამუშაოა. ამიტომაც მისი შესრულება განსაკუთრებული გამოცდილების ადამიანს უნდა დაევალოს.</p>\n\n<p>ჩვენი გუნდი და მისი წევრები უკვე 10 წელიწადზე მეტია დაკავებულია მსგავსი ტიპის სამუშაოებით.&nbsp; ჩვენ ვასრულებთ ყველა ტიპის სამუშაოებს სიმაღლეზე (სამონტაჭო და სადემონტაჭო სამუშაოები, შესადუღებელი სამუშაოები, მინის ფასადის წმენდა და მრავალი სხვა).&nbsp;</p>\n\n<p>ჩვენ ვბაზირებთ თბილისთი მაგრამ, ვმუშაობთ მთელი საქართველოს მაშტაბით.</p>\n\n<p>სამონტაჟო სამუშაოები სიმაღლეზე. კონსტრუქციის მონტაჟი/დემონტაჟი, შესადუღებელი სამუშაოები, სანიაღვრე მილების ჩამოყვანა, სარეკლამო ბანერების მონტაჟი, გამწოვი მილების მონტაჟი (არა ლესვა, ღებვა და შუშების წმენდა). ვმუშაობთ მთელ საქართველოში.</p>\n\n<p>ჩვენი <strong>თოკზე წვდომის (Rope Access)</strong> სერვისი იყენებს ინდუსტრიულ ცოცვის ტექნიკებს რთულად მისადგომი ადგილების მისასვლელად, სკაფოლდებისა და ამწეების გარეშე.<br />\nIRATA-სა და SPRAT-ის სერტიფიცირებული ტექნიკოსები იყენებენ ორმაგი თოკის უსაფრთხოების სისტემებს, რაც გამორიცხავს ვარდნის რისკს და უზრუნველყოფს სამაშველო სარეზერვო გეგმას.</p>\n\n<p>ეს მეთოდი იდეალურია ფასადების გაწმენდისთვის, ქარის ტურბინების მოვლისთვის, ხიდების ინსპექციისთვის, მზის პანელებზე მუშაობისთვის და შეზღუდულ სივრცეებში შესასვლელად.<br />\nთოკზე წვდომა უზრუნველყოფს სწრაფ მონტაჟს, დაბალ ეკოლოგიურ ზემოქმედებას და გაცილებით ეკონომიურია ტრადიციულ მეთოდებთან შედარებით.</p>\n\n<hr />\n<h3>რატომ უნდა აირჩიო თოკზე წვდომა?</h3>\n\n<ul>\n	<li>\n	<p><strong>უნივერსალურობა:</strong> ეფექტურია ინდუსტრიულ, კომერციულ და არქიტექტურულ გარემოში &ndash; იქ, სადაც სიმაღლე ან სირთულე გამორიცხავს სტანდარტულ წვდომას.</p>\n	</li>\n	<li>\n	<p><strong>ეფექტიანობა და ეკონომიურობა:</strong> მინიმალური მომზადება, მცირე ჯგუფი და დაბალი ხარჯები &ndash; სწრაფი და ნაკლებად დამღლელი შესრულება.</p>\n	</li>\n	<li>\n	<p><strong>უსაფრთხოება:</strong> ორმაგი თოკის სისტემა, რეზერვული ანკერები და სერტიფიცირებული სპეციალისტები.</p>\n	</li>\n	<li>\n	<p><strong>ეკო-მეგობრული:</strong> მსუბუქი აღჭურვილობა ამცირებს სტრუქტურულ ზიანს და გარემოზე ზემოქმედებას.</p>\n	</li>\n</ul>\n\n<hr />\n<h3>გამოყენების სფეროები:</h3>\n\n<ul>\n	<li>\n	<p>ფასადების გაწმენდა და რემონტი</p>\n	</li>\n	<li>\n	<p>კოშკების, ხიდების, კაშხლებისა და სილოსების მოვლა</p>\n	</li>\n	<li>\n	<p>ქარის ტურბინებისა და მზის პანელების მონტაჟი</p>\n	</li>\n	<li>\n	<p>შეზღუდულ სივრცეებში წვდომა და ტექნიკური მომსახურება</p>\n	</li>\n</ul>\n\n<p>ყველა სამუშაო სრულდება გამოცდილი სპეციალისტების მიერ, საერთაშორისო უსაფრთხოების სტანდარტების დაცვით &ndash; ვუზრუნველყოფთ სწრაფ, ზუსტ და საიმედო სერვისს, როგორც ერთჯერადი პროექტებისთვის, ისე რეგულარული მოვლის გრაფიკისთვის.</p>\n\n<div data-oembed-url=\"https://youtu.be/35cDepjJPsc\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/tp17QcN\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=YBXwXEIHnwQ&amp;t=26s&amp;ab_channel=TemoSamsonadze\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/qich8xa\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=xjIfSMfyRHw&amp;ab_channel=TemoSamsonadze\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/5wcD9vk\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n\n<p>დაგვიკავშირდით ტელეფონის ნომერზე - (+995) 598 45 70 47</p>\n\n<p>ელექტრონული ფოსტა - samsonadze.temo9@gmail.com</p>\n', '2023-05-29 14:13:16', '2025-06-20 18:40:00'),
(2, 'ru', '.', '<p>.</p>\n', '<p>.</p>\n', '2023-05-29 14:13:16', '2024-04-07 17:21:30'),
(3, 'us', 'Rope Acces', '<p>Certified rope-access solutions&mdash;safe, efficient maintenance, inspection, and installation at height.</p>\n', '<p>Job vacancies require a high level of security clearance. Therefore, its completion should be entrusted to a qualified individual who has passed the required tests.</p>\n\n<p>Our team and its members have over 10 years of experience in similar types of work. We perform all types of jobs at high altitudes (rope access and abseiling works, hazardous jobs, confined space works, mini excavator work, and many others).</p>\n\n<p>We are based in Tbilisi but operate throughout Georgia.</p>\n\n<p>Our <strong>Rope Access</strong> service uses industrial climbing techniques to reach hard-to-access structures without scaffolding or lifts. IRATA- and SPRAT-certified technicians ascend, descend, and traverse ropes using dual-rope safety systems&mdash;ensuring zero fall risk and full rescue redundancy.</p>\n\n<p>Perfect for tasks like fa&ccedil;ade cleaning, wind-turbine maintenance, bridge inspections, solar‑panel work, and confined‑space projects, rope access offers fast setup, low environmental impact, and cost-effective operations compared to traditional methods.</p>\n\n<h3>Why Choose Rope Access?</h3>\n\n<ul>\n	<li>\n	<p><strong>Versatility:</strong> Ideal for industrial, commercial, and architectural environments&mdash;anywhere height or complexity hinders conventional access .</p>\n	</li>\n	<li>\n	<p><strong>Efficient &amp; Economical:</strong> Minimal setup time, smaller teams, and lower overhead translate to faster jobs and fewer disruptions .</p>\n	</li>\n	<li>\n	<p><strong>Safety First:</strong> Dual-rope systems, redundant anchoring, and certified technicians ensure top-tier safety protocols.</p>\n	</li>\n	<li>\n	<p><strong>Eco-Friendly:</strong> Lightweight equipment reduces structural damage and environmental impact .</p>\n	</li>\n</ul>\n\n<h3>Applications</h3>\n\n<ul>\n	<li>\n	<p>Building fa&ccedil;ade cleaning and repairs</p>\n	</li>\n	<li>\n	<p>Maintenance of towers, bridges, dams, and silos</p>\n	</li>\n	<li>\n	<p>Wind turbine and solar installation services</p>\n	</li>\n	<li>\n	<p>Confined-space access and industrial facility upkeep&nbsp;</p>\n	</li>\n</ul>\n\n<p>All work is performed by trained professionals following global safety standards to deliver fast, precise, and reliable solutions&mdash;whether for one-off projects or ongoing maintenance programs.</p>\n\n<div data-oembed-url=\"https://youtu.be/35cDepjJPsc\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/tp17QcN\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=YBXwXEIHnwQ&amp;t=26s&amp;ab_channel=TemoSamsonadze\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/qich8xa\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=xjIfSMfyRHw&amp;ab_channel=TemoSamsonadze\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/5wcD9vk\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>Please contact us by phone at (+995) 598 45 70 47</p>\n\n<p>or by email at <a href=\"mailto:samsonadze.temo9@gmail.com\" target=\"_new\">samsonadze.temo9@gmail.com</a>.</p>\n', '2023-05-29 14:13:16', '2025-06-20 18:40:00'),
(4, 'ka', '.', '<p>.</p>\n', '<p>.</p>\n', '2023-05-29 14:16:13', '2023-05-29 14:16:13'),
(5, 'ru', 'ცოცვის და ალპინიხმის გზამკვლევი', '<p>.</p>\n', '<p>.</p>\n', '2023-05-29 14:16:14', '2023-05-29 14:16:14'),
(6, 'us', 'Climbing & Mountaineering Guiding', '<p>.</p>\n', '<p>.</p>\n', '2023-05-29 14:16:14', '2023-05-29 14:16:14'),
(7, 'ka', 'საცოცი ინვენტარის გაქირავება', '<p>საცოცი და სასიმაღლო სამუშაოებისთვის საჭირო აღჭურვილობის გაქირავება. ხარისხიანი აღჭურვილობა დარბაზსა თუ ბუნებისთვის.</p>\n', '<p>ჩვენთან შეგიძლიათ იქირავოთ&nbsp;საცოცი და სასიმაღლო სამუშაოებისთვის საჭირო აღჭურვილობა</p>\n\n<p>თუ საცოცად მიდიხარ და აღჭურვილობა გჭირდება &mdash; ჩვენი კერძო პროგრამა უზრუნველყოფს მასშტაბური ინვესტიციის გარეშე მაღალი ხარისხის და უსაფრთხო აღჭურვილობას.</p>\n\n<p>🔧 რა აღჭურვილობას შეგიძლია იქირაო</p>\n\n<ul>\n	<li>\n	<p><strong>დაცვის ქამარი</strong> &mdash; უნივერსალური, კომფორტული და რეგულირებადი ნებისმიერი აღნმდომარეობისთვის</p>\n	</li>\n	<li>\n	<p><strong>ჩაფხუტი</strong> &mdash; სერტიფიცირებული დაცვა კლდის ქვეშ (რომ იღვენთებ)</p>\n	</li>\n	<li>\n	<p><strong>დაცვის მოწყობილობა &amp; კარაბინერები</strong> &mdash; უსაფრთხო ღვედის კონტროლისთვის, ავტომატური საკეტით</p>\n	</li>\n	<li>\n	<p><strong>ცარცის ჩანთები &amp; ცარცი</strong> &mdash; მზა და თხევადი ცარცის ვერსიები</p>\n	</li>\n	<li>\n	<p><strong>ექსპრესები&nbsp;&amp; თოკები</strong> &mdash; სპორტული და ტრადიციული ცოცვისთვის (ამოღებული მოთხოვნისას)</p>\n	</li>\n</ul>\n\n<p>რატომ არის გაქირავება გონივრული გზა?</p>\n\n<ul>\n	<li>\n	<p><strong>ეკონომიური</strong>: აღარ გჭირდება დიდი თანხის დახარჯვა &ndash; იხდიხარ წუთზე, დღეს ან ვიქენდზე</p>\n	</li>\n	<li>\n	<p><strong>პრაქტიკისთვის შესაფერისი</strong>: დააყენე გამოცდული მოდელები და ზომები ნაკლებ რისკთან</p>\n	</li>\n	<li>\n	<p><strong>მინიმალური მოვლა</strong>: ყველა გაწყობილობა იცვლება პროფესიონალურად, პირწმინდად და გამოცდილი</p>\n	</li>\n	<li>\n	<p><strong>საუკეთესოა დაუგეგმავი გასვლებისთვის</strong>: იდეალურია შემთხვევითი ცოცვის მოყვარულებისთვის ან ვიზიტორებისთვის</p>\n	</li>\n	<li>\n	<p><strong>საგზაო მოსახერხებელი</strong>: შედარებით მსუბუქი და პორტატული აღჭურვილობა</p>\n	</li>\n</ul>\n\n<p>სპორტული აღჭურვილობის ჩამონათვალი და ფასები იხილეთ ქვემოთ</p>\n\n<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:100%\">\n	<tbody>\n		<tr>\n			<td><strong>სახელი</strong></td>\n			<td><strong>არწერა</strong></td>\n			<td><strong>ფასი 1 დღეში</strong></td>\n		</tr>\n		<tr>\n			<td>კარაბინი</td>\n			<td>ალუმინის კარაბინი ჩამკეტით</td>\n			<td>2$ (1 დრე)</td>\n		</tr>\n		<tr>\n			<td>საცოცი ექსპრესი (აწიაშკა) 1ც</td>\n			<td>საცოცი ექსპრესი 1 ცალის ოდენობით</td>\n			<td>3$ (1დღე)</td>\n		</tr>\n		<tr>\n			<td>საცოცი ექსპრესების კომპლექტი&nbsp;1სც</td>\n			<td>საცოცი ექსპრესი 12&nbsp;ცალის ოდენობით</td>\n			<td>20$ (1დღე)</td>\n		</tr>\n		<tr>\n			<td>საცოცი თოკი 60მ</td>\n			<td>60მ სიგრძის თოკი</td>\n			<td>15$ (1დღე)</td>\n		</tr>\n		<tr>\n			<td>საცოცი თოკი 80მ</td>\n			<td>80მ სიგრძის თოკი</td>\n			<td>20$ (1დღე)</td>\n		</tr>\n		<tr>\n			<td>საცოცი ჩაფხუტი</td>\n			<td>1ც საცოცი ჩაფხუტი</td>\n			<td>8$ (1დღე)</td>\n		</tr>\n		<tr>\n			<td>წერაყინი</td>\n			<td>არასაცოცი წერაყინი</td>\n			<td>12$ (1დღე)</td>\n		</tr>\n		<tr>\n			<td>წრიაპი</td>\n			<td>უნივერსალური წრიაპი</td>\n			<td>12$ (1დღე)</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>&nbsp;</p>\n', '2023-05-29 14:17:17', '2025-06-20 18:51:24'),
(8, 'ru', '.', '<p>.</p>\n', '<p>.</p>\n', '2023-05-29 14:17:17', '2024-04-07 17:25:15'),
(9, 'us', 'Rent Climbing Gear', '<p>Affordable climbing gear rentals&mdash;top-quality equipment for your indoor gym or outdoor adventures.</p>\n', '<p>You can rent the necessary equipment for industrial and high-altitude work with us.</p>\n\n<p>Equip your adventure with ease using our <strong>Rent Climbing Gear</strong> service. Whether you&#39;re heading to a climbing gym, exploring crags, or organizing a one-off climbing trip, our rental program provides premium, safety-certified equipment without the investment.</p>\n\n<p>🔧 What You Can Rent</p>\n\n<ul>\n	<li>\n	<p><strong>Harnesses</strong> &mdash; comfortable, adjustable models for all body types</p>\n	</li>\n	<li>\n	<p><strong>Helmets</strong> &mdash; certified protection against rockfall and impacts</p>\n	</li>\n	<li>\n	<p><strong>Belay Devices &amp; Carabiners</strong> &mdash; smooth braking systems, auto-locking carabiners</p>\n	</li>\n	<li>\n	<p><strong>Chalk Bags &amp; Chalk</strong> &mdash; grab-bag and liquid chalk options available</p>\n	</li>\n	<li>\n	<p><strong>Quickdraws &amp; Ropes</strong> &mdash; suitable for sport and trad routes (available upon request)</p>\n	</li>\n</ul>\n\n<p>Why Rental Makes Sense</p>\n\n<ul>\n	<li>\n	<p><strong>Cost‑effective</strong>: Avoid hefty upfront purchase&mdash;pay only for the time you use</p>\n	</li>\n	<li>\n	<p><strong>Try Before You Buy</strong>: Test different models and sizes before committing</p>\n	</li>\n	<li>\n	<p><strong>Minimal Maintenance Work</strong>: All gear is professionally cleaned and inspected after use</p>\n	</li>\n	<li>\n	<p><strong>Perfect for Occasional Climbers</strong>: Ideal for casual users on a budget or occasional visitors</p>\n	</li>\n	<li>\n	<p><strong>Travel-Friendly</strong>: Lightweight gear that&rsquo;s easy to carry or store temporarily</p>\n	</li>\n</ul>\n\n<p>Please find below the specifications and prices for sports equipment:<br />\n&nbsp;</p>\n\n<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:100%\">\n	<tbody>\n		<tr>\n			<td>Name</td>\n			<td>Description</td>\n			<td>Price per Day</td>\n		</tr>\n		<tr>\n			<td>Karabiner</td>\n			<td>Aluminum carabiner with a lock</td>\n			<td>$2 (1 day)</td>\n		</tr>\n		<tr>\n			<td>Quickdraw&nbsp;1pc</td>\n			<td>Quickdraw 1pc</td>\n			<td>3$ (1 day)</td>\n		</tr>\n		<tr>\n			<td>Quickdraw&nbsp;12pc</td>\n			<td>Quickdraw 12 pc</td>\n			<td>20$ (1 day)</td>\n		</tr>\n		<tr>\n			<td>Harness</td>\n			<td>Climbing harness (1pc)</td>\n			<td>5$ (1 day)</td>\n		</tr>\n		<tr>\n			<td>Climbing rope 60მ</td>\n			<td>Climbing rope 60m</td>\n			<td>15$ (1 day)</td>\n		</tr>\n		<tr>\n			<td>Climbing rope&nbsp;80მ</td>\n			<td>Climbing rope&nbsp;80m</td>\n			<td>20$ (1 day)</td>\n		</tr>\n		<tr>\n			<td>Helmet</td>\n			<td>Helmet 1pc</td>\n			<td>8$ (1 day)</td>\n		</tr>\n		<tr>\n			<td>Ice axe</td>\n			<td>Mountaineering ice axe</td>\n			<td>12$ (1 day)</td>\n		</tr>\n		<tr>\n			<td>Ice Tool</td>\n			<td>Ice Tool (1pc)</td>\n			<td>15$ (1 day)</td>\n		</tr>\n		<tr>\n			<td>Ice Tool</td>\n			<td>Ice Tool (2pc)</td>\n			<td>25$ (1&nbsp;day)</td>\n		</tr>\n		<tr>\n			<td>Crampons</td>\n			<td>Universal crampons</td>\n			<td>12$ (1 day)</td>\n		</tr>\n		<tr>\n			<td>Ice scrow</td>\n			<td>Ice scrow (1pc)</td>\n			<td>15$ (1 day)</td>\n		</tr>\n		<tr>\n			<td>Stopers</td>\n			<td>Stoper (15PC)</td>\n			<td>15$ (1 day)</td>\n		</tr>\n	</tbody>\n</table>\n', '2023-05-29 14:17:17', '2026-02-04 13:28:27'),
(10, 'ka', 'საცოცი კედლების მშენებლობა (საბავშვო საცოცი კედელი)', '<p>ცოცვის კედლების პროექტირებს, დამზადება და მონტაჟი &ndash; პროფესიონალური დიზაინი, გამძლე მასალები და სივრცეზე მორგებული გადაწყვეტა.</p>\n', '<p>&nbsp;&nbsp;</p>\n\n<p>ვაკეთებთ საცოც კედლებს როგორც ბავშვებისთვის, ასევე მოყვარულ და პროფესიონალ სპორტმენებისთვის. ჩვენი კომპანია აგიწყობთ ნებისმიერი სიმაღლის სიგანის და რელიეფის კედელს, ყველა საერთაშორისო სტანდატრის დაცვით, იმისთვის რომ თქვენი ვარჯიში მეტად სასიამოვნო და პროდუქტიული იყოს.</p>\n\n<p>საცოცი კედლის გაკეთება შესაძლებელია ნებისმიერ ადგილას: სახლში, სპორტულ დარბაზში, ფიტნეს ცენტრში, სკოლაში და ნებისმიერ იმ ადგილას, სადაც თქვენ მოინდომებთ.</p>\n\n<p>ვმუშაობთ მთელ საქართველოში. ასევე, ჩვენვე ვაწარმოებთ საჭიდებს, საცოც ტრენაჟორებს და ყველაფერს, რასაც თქვენ ცოცვაში იყენებთ.</p>\n\n<p><a href=\"https://shop.climbing.ge/climbing_wall_colculator\">თქვენ შეგიძლიათ დაითვალოთ თქვენთვის სასურველი კედლის ფასი ამ გვერდზე</a>. გაითვალისწინეთ ფასი დაახლოებითია და ექვემდებარება კორექტირებას.</p>\n\n<p>გადაქციე შენი სივრცე სანახაობრივ და ფუნქციურ ცოცვის გარემოდ ჩვენი <strong>ცოცვის კედლების დამზადებისა და მონტაჟის სერვისით</strong>.<br />\nიქნება ეს სპორტდარბაზი, სათემო ცენტრი, სკოლა თუ სახლი &ndash; ჩვენ ვქმნით შენზე მორგებულ, პროფესიონალურად აგებულ და უსაფრთხო ცოცვის კედელს.</p>\n\n<p><strong>რატომ ცოცვის კედელი?</strong></p>\n\n<ul>\n	<li>\n	<p><strong>ფიტნესი &amp; გართობა:</strong> სრულფასოვანი ვარჯიში, რომელიც აერთიანებს ძალას, მოქნილობასა და კარდიო დატვირთვას &ndash; ვარჯიში თამაშივით.</p>\n	</li>\n	<li>\n	<p><strong>მენტალური კონცენტრაცია:</strong> ცოცვა აუმჯობესებს პრობლემების გადაჭრის უნარს, ფოკუსსა და გამძლეობას.</p>\n	</li>\n	<li>\n	<p><strong>თემური და საგანმანათლებლო ღირებულება:</strong> იდეალურია ბავშვთა პროგრამებისთვის, გუნდური აქტივობებისთვის და სოციალური სივრცისთვის.</p>\n	</li>\n</ul>\n\n<p><strong>რას ვთავაზობთ:</strong></p>\n\n<ul>\n	<li>\n	<p><strong>ბოულდერ კედელი:</strong> დაბალი სიმაღლის კედელი (5 მეტრამდე), უსაფრთხო მარბელზე &ndash; იდეალურია დამწყებთათვის და თავისუფალი ცოცვისთვის.</p>\n	</li>\n	<li>\n	<p><strong>ტოპ-როუპ/ლიდ კედლები:</strong> მაღალი კედლები სარტყლის სისტემით &ndash; განკუთვნილია სპორტდარბაზებისთვის, სკოლებისა და ექსტრემალური ვარჯიშისთვის.</p>\n	</li>\n	<li>\n	<p><strong>მორგებადი და მოდულური სისტემები:</strong> ცალკე მდგომი ან კედელზე მიმაგრებული, კუთხითა და სირთულით ადაპტირებადი.</p>\n	</li>\n</ul>\n\n<hr />\n<h3>🏗️ როგორ ხდება პროცესი?</h3>\n\n<ol>\n	<li>\n	<p><strong>კონსულტაცია &amp; დიზაინი</strong><br />\n	ვაფასებთ შენს სივრცეს, საჭიროებებს და მიზნებს. ჩვენი გუნდი ქმნის ინდივიდუალურ დიზაინს და მარშრუტებს.</p>\n	</li>\n	<li>\n	<p><strong>მასალების შერჩევა</strong><br />\n	ვიყენებთ მაღალი ხარისხის მასალებს &ndash; დამუშავებულ ხეს (glulam), ბალტიის ხის ფენოვან დაფას და ინდუსტრიულ სამაგრებს.</p>\n	</li>\n	<li>\n	<p><strong>მონტაჟი და აწყობა</strong><br />\n	ჩვენი გუნდი უზრუნველყოფს სტრუქტურის უსაფრთხო მშენებლობას: კარკასის აწყობა, პანელების დამაგრება, საჭდების დაყენება, დამცავი მარბელის განთავსება.</p>\n	</li>\n	<li>\n	<p><strong>მარშრუტების დაყენება და ტრენინგი</strong><br />\n	ვამზადებთ საწყის მარშრუტებს სხვადასხვა დონეზე და ვწვრთნით თქვენს პერსონალს ან ოჯახის წევრებს გზების გადასაწყობად.</p>\n	</li>\n	<li>\n	<p><strong>ოპერაციული მხარდაჭერა</strong><br />\n	დაგეხმარებით უსაფრთხოების წესების შემუშავებაში, პერსონალის მართვასა და საჭირო დაზღვევასთან დაკავშირებულ საკითხებში.</p>\n	</li>\n</ol>\n\n<hr />\n<h3>📣 სარგებელი</h3>\n\n<table>\n	<thead>\n		<tr>\n			<th>უპირატესობა</th>\n			<th>აღწერა</th>\n		</tr>\n	</thead>\n	<tbody>\n		<tr>\n			<td><strong>ინოვაციური ვარჯიში</strong></td>\n			<td>ვარჯიშის მთელი წელი, როგორც ფიზიკური, ასევე მენტალური ჯანმრთელობისთვის.</td>\n		</tr>\n		<tr>\n			<td><strong>საზოგადოების მოზიდვა</strong></td>\n			<td>იდეალურია ყველა ასაკისთვის &ndash; ბავშვები, მოზარდები, მშობლები და პროფესიონალები.</td>\n		</tr>\n		<tr>\n			<td><strong>პროგრამების განვითარება</strong></td>\n			<td>საშუალებას იძლევა ჩატარდეს ბანაკები, შეჯიბრებები და გუნდის შეკრული აქტივობები.</td>\n		</tr>\n		<tr>\n			<td><strong>ეკოეფექტიანობა</strong></td>\n			<td>ეკოლოგიური მასალები და ენერგოეფექტური დიზაინი ამცირებს ხარჯებს.</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>&nbsp;</p>\n\n<hr />\n<h3>✅ რატომ უნდა აირჩიო ჩვენთან?</h3>\n\n<ul>\n	<li>\n	<p><strong>მორგებული გამოცდილება:</strong> ვქმნით როგორც პატარა საოჯახო სტენდებს, ისე სრულმასშტაბიან დარბაზებს.</p>\n	</li>\n	<li>\n	<p><strong>სერტიფიცირებული გუნდი:</strong> თანამშრომლობას ვაწარმოებთ პროფესიონალ ტრასავიკებთან და უსაფრთხოების სპეციალისტებთან.</p>\n	</li>\n	<li>\n	<p><strong>მომსახურების მხარდაჭერა:</strong> ვაწვდით ტექნიკურ რჩევებს, გზების განახლების გეგმებსა და ტრენინგს.</p>\n	</li>\n</ul>\n\n<hr />\n<p>დაგეგმე შენთან თავგადასავალი, ვარჯიში და საზოგადოებრივი სივრცე &ndash; დღესვე დაგვიკავშირდი უფასო კონსულტაციისთვის და ინდივიდუალური შეთავაზებისთვის!</p>\n\n<p>&nbsp;</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=dWnswDmxiXI&amp;ab_channel=TemoSamsonadze\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/RJdJF4P\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n', '2023-05-29 14:18:44', '2026-02-04 13:08:37'),
(11, 'ru', '.', '<p>.</p>\n', '<p>.</p>\n', '2023-05-29 14:18:44', '2024-04-07 17:20:35'),
(12, 'us', 'Building climbing walls', '<p>Custom climbing wall installation&mdash;expert design, durable materials, and tailored for your space.</p>\n', '<p>We make climbing walls for children, amateur ორ professional athletes. Our company arranges for you a wall of any height, width and terrain, with all international standards, to make your training more&nbsp;comfortable and productive.</p>\n\n<p>Climbing wall can be done anywhere: at home, gym, fitness center, school and anywhere you want.</p>\n\n<p>We work throughout Georgia. Also, we make our own holde, climbing trainers and everything which you use for climbing.</p>\n\n<p><a href=\"https://shop.climbing.ge/climbing_wall_colculator\">You can calculate the price of the wall on this page</a>. Note that the price is approximate and subject to adjustment.</p>\n\n<p>Transform your space into a thrilling climbing environment with our Building Climbing Walls service. Whether you&#39;re outfitting a commercial gym, community center, school, or home, we deliver a professionally designed and installed climbing wall tailored to your goals.</p>\n\n<p>Why choose a climbing wall?</p>\n\n<p>Fitness &amp; Fun: Offers a full‑body workout that enhances strength, flexibility, and cardiovascular health&mdash;making exercise feel like play, not a chore&nbsp;<br />\n&nbsp;</p>\n\n<p>Mental Engagement: Encourages problem-solving, concentration, and resilience&mdash;perfect for stress relief and mental wellness&nbsp;<br />\n&nbsp;</p>\n\n<p>Community &amp; Education: Ideal for youth programs, team-building, and social gatherings&mdash;climbing fosters connection and inclusivity&nbsp;<br />\n&nbsp;</p>\n\n<p>Types of walls available:</p>\n\n<p>Bouldering: Low-height walls (&lt; 5 m) requiring padded flooring&mdash;great for casual and beginner-friendly use&nbsp;<br />\n&nbsp;</p>\n\n<p>Top-Rope / Lead: Taller walls with harness systems&mdash;suitable for advanced training, adventure schools, and commercial gyms&nbsp;<br />\n&nbsp;</p>\n\n<p>Custom &amp; Modular: Freestanding or attached panels, adjustable angles, and overhangs to match your space and ambition .</p>\n\n<p>🏗️ How It Works<br />\nConsultation &amp; Design<br />\nWe begin by assessing your available space, usage goals, and preferred climbing styles. Our architects and designers collaborate with you to create a personalized layout and route flow&nbsp;<br />\n&nbsp;</p>\n\n<p>Material Selection<br />\nWe use premium materials&mdash;glulam (engineered wood), Baltic birch plywood, and industrial-grade hardware&mdash;to ensure longevity, safety, and visual appeal&nbsp;<br />\n&nbsp;</p>\n\n<p>Professional Build &amp; Installation<br />\nOur experienced team constructs and secures the wall&mdash;including framing, panels, holds, and safety surfacing. We prioritize quality installations that comply with safety standards&nbsp;<br />\n&nbsp;</p>\n\n<p>Custom Routesetting &amp; Training<br />\nWe plan initial routes across all difficulty levels and can train your staff or family members in maintaining and resetting routes effectively&nbsp;<br />\n&nbsp;</p>\n\n<p>Operational Support<br />\nWe help implement safety protocols, staffing strategies, insurance advisories, and facility operations&mdash;vital for commercial or community installations&nbsp;<br />\n&nbsp;</p>\n\n<p>📣 Benefits You&rsquo;ll See<br />\nBenefit&nbsp;&nbsp; &nbsp;Description<br />\nInnovative Wellness&nbsp;&nbsp; &nbsp;Year-round fitness and mental wellness boost.<br />\nCommunity Magnet&nbsp;&nbsp; &nbsp;Attracts users across demographics&mdash;families, schools, fitness enthusiasts&nbsp;<br />\n<br />\nProgram Potential&nbsp;&nbsp; &nbsp;Enables youth camps, competitions, team-building, and more.<br />\nSustainable Efficiency&nbsp;&nbsp; &nbsp;Eco-friendly materials and energy-conscious design reduce long-term costs .</p>\n\n<p>✅ Why Trust Us?<br />\nCustom expertise: From compact home setups to full-scale gyms, we tailor every detail&nbsp;<br />\n&nbsp;</p>\n\n<p>Certified professionals: We partner with experienced route-setters and certified inspectors to ensure safety compliance&nbsp;<br />\nclimbingbusinessjournal.com<br />\n&nbsp;</p>\n\n<p>Aftercare support: We offer maintenance guidance, route rotation plans, and refresher staff training</p>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n\n<div data-oembed-url=\"https://www.youtube.com/watch?v=dWnswDmxiXI&amp;ab_channel=TemoSamsonadze\">\n<div>\n<div style=\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.25%;\"><iframe allow=\"accelerometer *; clipboard-write *; encrypted-media *; gyroscope *; picture-in-picture *; web-share *;\" allowfullscreen=\"\" scrolling=\"no\" src=\"//if-cdn.com/RJdJF4P\" style=\"top: 0; left: 0; width: 100%; height: 100%; position: absolute; border: 0;\" tabindex=\"-1\"></iframe></div>\n</div>\n</div>\n\n<p>&nbsp;</p>\n', '2023-05-29 14:18:44', '2025-06-20 18:24:53');
INSERT INTO `locale_sites` (`id`, `slug`, `us_data`, `ka_data`, `created_at`, `updated_at`) VALUES
(4, 'guid_title', 'Rock Climbing in Georgia', 'მეკლდეურობა საქართველოში', NULL, NULL),
(5, 'guid_description', '<p>Rock climbing and alpinism in Georgia are among the most exciting and rapidly developing activities. The country stands out for its diversity of rock formations, stunning mountain landscapes, valleys, and still unexplored climbing areas.</p>\n\n<p>Our goal is to provide detailed descriptions, systematization, and regular updates of climbing locations across Georgia. We offer route descriptions, access information, logistical support, equipment, transportation, and, if needed, professional guiding services.</p>\n\n<p>Our mission is to make rock climbing in Georgia more accessible, safe, and appealing. We always welcome the involvement of the climbing community.</p>\n\n<p>There are already climbing routes of various difficulty levels in Georgia, but there is still great potential for further development, making the country especially attractive for adventure-seeking climbers.</p>\n\n<p>For additional information, feel free to contact us.</p>', '<p>მეკლდეურობა და ალპინიზმი საქართველოში ერთ-ერთი ყველაზე საინტერესო და სწრაფად განვითარებადი მიმართულებაა.&nbsp; ქვეყანა გამოირჩევა კლდეების მრავალფეროვნებით, შთამბეჭდავი მთის ლანდშაფტებით, ხეობებითა და ჯერ კიდევ გამოუკვლეველი საცოცი ადგილებით.</p>\n\n<p>ჩვენი მიზანია საქართველოს მასშტაბით საცოცი ლოკაციების დეტალური აღწერა, სისტემატიზაცია და რეგულარული განახლება. გთავაზობთ მარშრუტების აღწერას, მისასვლელი გზების დეტალებს, ლოჯისტიკურ დახმარებას, აღჭურვილობას, ტრანსპორტსა და საჭიროების შემთხვევაში პროფესიონალი გიდის მომსახურებას. ჩვენი მისიაა მეკლდეურობა საქართველოში იყოს უფრო ხელმისაწვდომი, უსაფრთხო და მიმზიდველი.</p>\n\n<p>ყოველთვის მივესალმებით საცოცი საზოგადოების ჩართულობას. საქართველოში უკვე არსებობს სხვადასხვა სირთულის საცოცი მარშრუტები, მაგრამ გვაქვს მისი განვითარების დიდი პოტენციალი, რაც ქვეყანას განსაკუთრებით მიმზიდველს ხდის თავგადასავლების მაძიებელი მეკლდეურებისთვის.</p>\n\n<p>დამატებითი ინფორმაციისთვის შეგიძლიათ დაგვიკავშირდეთ.</p>', NULL, '2026-04-20 19:43:34'),
(6, 'guid_short_description', 'Rock climbing and mountaineering across Georgia', 'საქართველოს საცოცი და ალპინისტური მარშრუტების აღწერა', NULL, NULL),
(7, 'films_title', 'Rock Climbing Films', 'ცოცვის ფილმები', NULL, NULL),
(8, 'films_description', '<p>.</p>', '<p>.</p>', NULL, '2026-04-20 19:43:47'),
(9, 'films_short_description', '<p>.</p>', '<p>.</p>', NULL, '2026-04-20 19:43:53'),
(10, 'forum_title', 'Georgian Climbing Forum', 'ქართული ცოცვის ფორუმი', NULL, NULL),
(11, 'forum_description', 'A friendly community forum where climbers share experience, advice, trip reports, and news.', '<p>.</p>', NULL, '2026-04-19 22:51:40'),
(12, 'forum_short_description', 'Community forum for climbers', '<p>.</p>', NULL, '2026-04-19 22:51:46'),
(13, 'shop_title', 'Climbing.ge Products and Services', 'Climbing.ge-ს პროდუქცია და მომსახურება', NULL, NULL),
(14, 'shop_description', '<p>Our online store offers a wide range of products for rock climbing and alpinism. The main focus is on quality, durability, and practical use.</p>\n\n<p>In addition, we provide professional services &mdash; including instructor support, as well as the design and construction of climbing walls.</p>', '<p>ჩვენი ონლაინ მაღაზია გთავაზობთ ცოცვისთვისა და ალპინიზმისთვის საჭირო სხვადასხვა პროდუქციას. მთავარი აქცენტი კეთდება ხარისხზე, გამძლეობასა და პრაქტიკულ გამოყენებაზე.&nbsp;</p>\n\n<p>გარდა ამისა, გთავაზობთ პროფესიონალურ სერვისებს &mdash; ინსტრუქტორის მომსახურებას, საცოცი კედლების პროექტირებას და მშენებლობას.</p>', NULL, '2026-04-20 19:44:34'),
(15, 'shop_short_description', 'Climbing gear and services', 'საცოცი აღჭურვილობა და სერვისები', NULL, NULL),
(16, 'other_activity_description', 'Other outdoor activities and adventures in Georgia', 'სხვა აქტიური თავგადასავლები საქართველოში', NULL, NULL),
(17, 'mount_description', 'Mountaineering routes and alpine adventures in the Caucasus', 'ალპინისტური მარშრუტები კავკასიონის მთებში', NULL, NULL),
(18, 'event_description', 'Rock climbing events and outdoor activities', 'საცოცი ღონისძიებები და აქტივობები', NULL, NULL),
(19, 'tech_tips_description', 'Climbing techniques, tips, and safety advice', 'ცოცვის ტექნიკა და უსაფრთხოების რჩევები', NULL, NULL),
(20, 'news_description', 'Latest news from the climbing community in Georgia', 'ცოცვის სიახლეები საქართველოში', NULL, NULL),
(21, 'index_gallery_description', 'Photo gallery from climbing and mountaineering trips', 'საცოცი და ალპინისტური ფოტოგალერეა', NULL, NULL),
(22, 'outdoor_description', 'Outdoor rock climbing areas across Georgia', '<p>ბუნებრივ კლდეზე საცოცი რეგიონები და მარშრუტები საქართველოში</p>', NULL, '2026-04-19 23:16:31'),
(23, 'indoor_description', 'Indoor climbing gyms and training spaces', '<p>საცოცი დარბაზები საქართველოში</p>', NULL, '2026-04-19 23:16:57'),
(24, 'ice_description', 'Ice climbing routes and winter adventures', '<p>ყინულზე ცოცვა</p>', NULL, '2026-04-19 23:17:15'),
(25, 'topo_description', 'Interactive map and climbing topos of Georgia', '<p>საქართველოს საცოცი და სამთო რეგიონების რუკა</p>', NULL, '2026-04-19 23:17:44'),
(26, 'what_we_do_description', 'We explore, document, and promote climbing in Georgia', '<p>ჩვენ ვიკვლევთ და ვანვითარებთ ცოცვას საქართველოში</p>', NULL, '2026-04-19 22:27:20'),
(27, 'products_description', 'Climbing.ge branded products', 'Climbing.ge-ს ბრენდირებული პროდუქცია', NULL, NULL),
(28, 'services_description', 'Guiding services, route development, and climbing support', '<p>ინსტრუქტორის მომსახურება და საცოცი მხარდაჭერა</p>', NULL, '2026-04-19 23:18:32'),
(29, 'terms_of_use', 'By using Climbing.ge, you agree to use the website at your own risk. Climbing and mountaineering are dangerous activities.\r\n\r\nInformation may change, so always verify details on site. Climbing.ge is not responsible for accidents or injuries.', '<p>Climbing.ge-ზე განთავსებული ინფორმაცია არის საინფორმაციო სახის, არ გამორიცხავს უზუსტობას ბუნებრივი პროცესებისა და სხვადასხვა (კლიმატური და ადამიანური) ფაქტორებიდან გამომდინარე ცვლილებების გამო. აუცილებელია ადგილზე სიტუაციის საღად შეფასება და რისკების განსაზღვრა.&nbsp;</p>', NULL, '2026-04-19 23:30:49'),
(30, 'blog_title', 'Climbing & Mountaineering Blog', 'ცოცვისა და ალპინიზმის ბლოგი', NULL, NULL),
(31, 'blog_short_description', 'Stories, guides, tips, and real experiences from the climbing world', '<p>ისტორიები, თავგადასავლები და სხვადასხვა საინტერესო მოვლენები მთიდან</p>', NULL, '2026-04-19 23:32:07'),
(32, 'blog_description', '<p>The blog is a space dedicated to rock climbing, alpinism, and an active lifestyle. Here, we share stories from climbing trips, route experiences, training tips, safety recommendations, gear reviews, interviews, and perspectives from the climbing community.</p>\n\n<p>The blog is created by active climbers and instructors and is intended for both beginners and experienced athletes.</p>\n\n<p>Our goal is to share knowledge, inspire, and bring the climbing community together.</p>', '<p>ბლოგი წარმოადგენს სივრცეს, რომელიც ეძღვნება მეკლდეურობას, ალპინიზმსა და აქტიურ ცხოვრებას. აქ ვაზიარებთ საცოცი მოგზაურობების ისტორიებს, მარშრუტების გამოცდილებას, სავარჯიშო რჩევებს, უსაფრთხოების რეკომენდაციებს, აღჭურვილობის მიმოხილვებს, ინტერვიუებსა და საცოცი საზოგადოების ხედვებს.</p>\n\n<p>ბლოგი იქმნება აქტიური მეკლდეურებისა და ინსტრუქტორების მიერ და განკუთვნილია, როგორც დამწყებთათვის, ისე გამოცდილი სპორტსმენებისთვის.</p>\n\n<p>ჩვენი მიზანია ცოდნის გაზიარება, ინსპირაცია და საცოცი საზოგადოების გაერთიანება.</p>', NULL, '2026-04-20 19:45:21'),
(33, 'message', '<p>.</p>', '<p>.</p>', '2026-04-20 16:12:49', '2026-04-20 16:12:49'),
