(36, 'partners_description', '<p>.</p>', '<p>.</p>', '2026-04-20 16:15:49', '2026-04-20 16:15:49'),
(37, 'project_description', '<p>.</p>', '<p>.</p>', '2026-04-20 16:17:11', '2026-04-20 16:17:11'),
(38, 'search_description', '<p>.</p>', '<p>.</p>', '2026-04-20 16:18:46', '2026-04-20 16:18:46'),
(39, 'guide_search_description', '<p>.</p>', '<p>.</p>', '2026-04-20 16:19:23', '2026-04-20 16:19:23'),
(40, 'shop_search_description', '<p>.</p>', '<p>.</p>', '2026-04-20 16:19:33', '2026-04-20 16:19:33'),
(41, 'tour_description', '<p>.</p>', '<p>.</p>', '2026-04-20 16:41:47', '2026-04-20 16:41:47'),
(43, 'summit_title', '<p>.</p>', '<p>.</p>', '2026-04-20 18:08:12', '2026-04-20 18:08:12'),
(44, 'summit_description', '<p>.</p>', '<p>.</p>', '2026-04-20 18:08:29', '2026-04-20 18:08:29'),
(45, 'summit_description_description', '<p>.</p>', '<p>.</p>', '2026-04-20 18:08:46', '2026-04-20 18:08:46'),
(46, 'summit_map_description', '<p>.</p>', '<p>.</p>', '2026-04-20 18:09:00', '2026-04-20 18:09:00'),
(47, 'donation_description', '<p>donation_description&nbsp; us</p>\n\n<p>&nbsp;</p>', '<p>donation_description კა</p>\n\n<p>&nbsp;</p>', '2026-04-20 18:37:12', '2026-04-27 14:09:57'),
(48, 'donation_short_description', '<p>.</p>', '<p>.</p>', '2026-04-20 18:37:31', '2026-04-20 18:37:31'),
(49, 'donation_terms_of_use', '<p>.</p>', '<p>.</p>', '2026-04-20 18:37:50', '2026-04-20 18:37:50'),
(50, 'summit_index_intro', '<p>Point your camera at the QR code placed at the summit to instantly register your climb. Track all your ascents and share them with the climbing community</p>', '<p>მიუთითეთ კამერა QR კოდზე, რომელიც განთავსებულია მწვერვალზე, ასვლის მყისიერი რეგისტრაციისთვის. თვალყური ადევნეთ ყველა ასვლას და გაუზიარეთ ისინი მთამსვლელთა საზოგადოებას.</p>', '2026-04-26 16:15:35', '2026-04-26 16:23:37'),
(51, 'summit_about_welcome', '<p>Welcome to Summit Climbing Georgia &ndash; the platform for mountain adventurers who want to document, validate, and share their ascents across Georgia\\&#39;s spectacular peaks.</p>', '<p>კეთილი იყოს თქვენი მობრძანება Summit Climbing Georgia-ზე &ndash; პლატფორმაზე მთის მოყვარულებისთვის, რომლებსაც სურთ საქართველოს შთამბეჭდავ მწვერვალებზე ასვლების დოკუმენტირება, დადასტურება და გაზიარება.</p>', '2026-04-26 16:16:20', '2026-04-26 16:16:20'),
(52, 'summit_about_mission', '<p>Our mission is to connect climbers with Georgia\\&#39;s epic summits through QR code registration and community sharing. Every ascent is logged, GPS-verified where possible, and added to the public record &ndash; building a living history of Georgian mountaineering.</p>', '<p>ჩვენი მიზანია ალპინისტების დაკავშირება საქართველოს განსაცვიფრებელ მწვერვალებთან QR კოდის რეგისტრაციისა და საზოგადოებრივი გაზიარების გზით. ყოველი ასვლა ფიქსირდება, GPS-ით მოწმდება სადაც შესაძლებელია და ემატება საჯარო ჩანაწერს.</p>', '2026-04-26 16:17:28', '2026-04-26 16:17:28'),
(53, 'summit_how_reach_desc', '<p>Hike or climb to the top of your chosen peak in Georgia.</p>', '<p>ივლეთ ან ასვლით მიაღწიეთ თქვენი არჩეული მწვერვალის მწვერვალს საქართველოში.</p>', '2026-04-26 16:17:59', '2026-04-26 16:24:14'),
(54, 'summit_how_scan_desc', '<p>Find the QR code marker at the summit and scan it with your phone.</p>', '<p>იპოვეთ QR კოდის მარკირება მწვერვალზე და დასკანირეთ ტელეფონით.</p>', '2026-04-26 16:18:52', '2026-04-26 16:18:52'),
(55, 'summit_how_validate_desc', '<p>GPS automatically confirms you reached the summit location.</p>', '<p>GPS ავტომატურად ადასტურებს, რომ მიაღწიეთ მწვერვალის მდებარეობას.</p>', '2026-04-26 16:19:52', '2026-04-26 16:19:52'),
(56, 'summit_how_share_desc', '<p>Your ascent is logged and visible to the entire climbing community.</p>', '<p>თქვენი ასვლა ფიქსირდება და ხილვადია მთელი მთამსვლელთა საზოგადოებისთვის.</p>', '2026-04-26 16:20:41', '2026-04-26 16:20:41'),
(57, 'summit_about_explore_desc', '<p>Browse our growing list of challenging peaks across Georgia, from the Greater Caucasus to lesser-known hidden gems.</p>', '<p>გაეცანით ჩვენს მზარდ სიას საქართველოს სახიფათო მწვერვალების შესახებ, დიდი კავკასიონიდან ნაკლებად ცნობილ ფარულ მარგალიტებამდე.</p>', '2026-04-26 16:21:24', '2026-04-26 16:21:24'),
(58, 'summit_about_qr_desc', '<p>Scan QR codes placed at summit markers to instantly log your climb, no internet connection needed at the top</p>', '<p>სკანირეთ მწვერვალის მარკირებებზე განთავსებული QR კოდები ასვლის მყისიერი ჩასაწერად &ndash; ინტერნეტ კავშირი მწვერვალზე არ არის საჭირო.</p>', '2026-04-26 16:22:06', '2026-04-26 16:22:06'),
(59, 'summit_about_community_desc', '<p>Share your experiences, view other climbers\\&#39; ascents, and build your personal summit logbook with the climbing community.</p>', '<p>გაუზიარეთ გამოცდილება, ნახეთ სხვა მთამსვლელების ასვლები და შექმენით პირადი მწვერვალების ჟურნალი მთამსვლელთა საზოგადოებასთან ერთად.</p>', '2026-04-26 16:22:41', '2026-04-26 16:22:41');
