(14, 'ru', 'ალპინისტური გასვლა ჭაუხის მასივში', '<p>ალპინისტური ტური ჭაუხის მასივში</p>\n', '<p>ალპინისტური ტური ჭაუხის მასივში</p>\n', NULL, NULL, '2023-12-21 01:18:02', '2023-12-21 01:18:02'),
