INSERT INTO `regions` (`id`, `us_name`, `ka_name`, `us_text`, `ka_text`, `map`, `created_at`, `updated_at`) VALUES
(1, 'Chiatura region', 'ჭიათურის რეგიონი', '<p>Chiatura region is the largest industrial region in Georgia. It has over 20 sectors and more than 200 cable car routes within the region.</p>', '<p>ჭიათურის რეგიონი საქართველოს ყველაზე დიდი საცოცი რეგიონია. რეგიონში 20ამდე&nbsp; სექტორია და 200ზე მეტი საცოცი მარშრუტი.</p>', '<iframe src=\"https://www.google.com/maps/d/embed?mid=1DrAQiTPMiMazYvfmMER3O2Eza2uu6T8&ehbc=2E312F\" width=\"100%\" height=\"480\"></iframe>', '2023-04-16 21:27:23', '2023-05-28 22:10:12'),
(2, 'Adjara region', 'აჭარის რეგიონი', '<p>On the Black Sea coast, you can climb. Near of Batumi, you have the opportunity to discover more than 25 climbing routes.</p>', '<p>შავი ზღვის სანაპიროზე შეგიძლიათ დაკავდეთ ცოცვით. ქალაქი ბათუმის სიახლოვეს თქვენ შძლებთ იპოვოთ 25ზე მეტი საცოცი მარშრუტი.</p>', '<iframe src=\"https://www.google.com/maps/d/embed?mid=1QrpC3jhcnzjlp-kCujErs-E5iMdfCD8&ehbc=2E312F\" width=\"100%\" height=\"480\"></iframe>', '2023-04-16 21:47:07', '2023-05-28 22:22:54'),
(3, 'Near Tbilisi', 'თბილისთან ახლოს', '<p>In Tbilisi and its suburbs (within less than 1 hour by car), you can explore more than one climbing sector.</p>', '<p>თბილისში და მის შემოგარენში (მანქანით 1 საათზე ნაკლებ სავალზე) თქვენ შეგუძლიათ ეწვიოთ არაერთ საცოც სექტორს.</p>', '<iframe src=\"https://www.google.com/maps/d/embed?mid=1Qd6O22nNY3cXne-9EMLIOcA5yCTzPLY&ehbc=2E312F\" width=\"100%\" height=\"480\"></iframe>', '2023-04-16 22:09:28', '2023-05-28 22:43:06'),
(5, 'Stepantsminda (Kazbegi) region', 'სტეპანწმინდა (ყაზბეგის) რეგიონი', '<p>In Stefantsminda (Kazbeg district), you can visit lot of mountaineering routes, also rock climbing sectors and climbing gyms. In the winter, you can climb on the frozen ice waterfall.</p>', '<p>სტეფანწმინდაში (ყაზბეგის რაიონში), შეგიძლიათ ეწვიოთ როგორც ალპინისტურ მარშრუტებს ასევე კლდეზე საცოცი სექტორები და საცოც დარბაზებს. ზამთრის პერიოდძი კი იცოცოთ გაყინულ ყინულის ჩანჩქერზე.</p>', '<iframe src=\"https://www.google.com/maps/d/embed?mid=1ndEUqyK15qpnKQkQioZOeOIMQ-jknOA&ehbc=2E312F\" width=\"100%\" height=\"480\"></iframe>', '2023-04-16 22:43:04', '2023-05-28 22:54:04'),
(6, 'Borjomi Region', 'ბორჯომის რეგიონი', '<p>.</p>', '<p>.</p>', NULL, '2025-11-24 12:47:49', '2025-11-24 12:47:49');
